import { useState, useCallback } from "react";
import axios from "axios";
import { toast } from "sonner";
import { AlertTriangle, CheckCircle, RefreshCw, Save } from "lucide-react";
import { API } from "../../../utils/constants";

const Card = ({ children, className = "" }) => (
  <div className={`bg-white rounded-xl shadow-sm border border-gray-100 ${className}`}>{children}</div>
);

export function TabNonMappati({ dizionario, onRicetteRefresh }) {
  const [nonMappati, setNonMappati] = useState(null);
  const [rinominaState, setRinominaState] = useState({});
  const [loading, setLoading] = useState(false);

  const fetchNonMappati = useCallback(async () => {
    setLoading(true);
    try {
      const res = await axios.get(`${API}/report-haccp/ingredienti-non-mappati`);
      setNonMappati(res.data);
    } catch (e) {
      console.error("Errore non mappati:", e);
    } finally {
      setLoading(false);
    }
  }, []);

  const handleRinomina = async (nomeVecchio, nomeNuovo) => {
    if (!nomeNuovo || nomeNuovo.trim() === nomeVecchio) return;
    try {
      const res = await axios.post(
        `${API}/food-cost/rinomina-ingrediente?nome_vecchio=${encodeURIComponent(nomeVecchio)}&nome_nuovo=${encodeURIComponent(nomeNuovo.trim())}`
      );
      toast.success(`Rinominato in ${res.data.count} ricette: "${nomeVecchio}" → "${nomeNuovo.trim()}"`);
      setRinominaState((prev) => { const n = { ...prev }; delete n[nomeVecchio]; return n; });
      fetchNonMappati();
      onRicetteRefresh();
    } catch (e) {
      toast.error("Errore rinomina: " + (e.response?.data?.detail || e.message));
    }
  };

  return (
    <div className="space-y-4">
      <Card className="p-4">
        <div className="flex items-center justify-between mb-4">
          <div>
            <h3 className="font-semibold flex items-center gap-2">
              <AlertTriangle size={18} className="text-amber-600" />
              Ingredienti Non Mappati nel Dizionario
            </h3>
            <p className="text-sm text-gray-500 mt-1">
              Ingredienti usati nelle ricette ma non trovati nel dizionario. Non contribuiscono al food cost.
            </p>
          </div>
          <button
            onClick={fetchNonMappati}
            disabled={loading}
            className="px-4 py-2 bg-amber-100 text-amber-700 rounded-lg flex items-center gap-2 hover:bg-amber-200 font-medium text-sm disabled:opacity-50"
            data-testid="analizza-non-mappati-btn"
          >
            <RefreshCw size={15} className={loading ? "animate-spin" : ""} />
            Analizza
          </button>
        </div>

        {!nonMappati ? (
          <div className="text-center py-12 text-gray-400">
            <AlertTriangle size={48} className="mx-auto mb-3 opacity-30" />
            <p>Clicca "Analizza" per verificare gli ingredienti non mappati</p>
          </div>
        ) : (
          <>
            <div className="grid grid-cols-3 gap-3 mb-4">
              <div className="bg-green-50 rounded-xl p-3 text-center">
                <p className="text-2xl font-bold text-green-600">{nonMappati.trovati}</p>
                <p className="text-xs text-gray-500">Ingredienti Trovati</p>
              </div>
              <div className="bg-amber-50 rounded-xl p-3 text-center">
                <p className="text-2xl font-bold text-amber-600">{nonMappati.non_trovati}</p>
                <p className="text-xs text-gray-500">Non Mappati</p>
              </div>
              <div className="bg-blue-50 rounded-xl p-3 text-center">
                <p className="text-2xl font-bold text-blue-600">{nonMappati.percentuale_copertura}%</p>
                <p className="text-xs text-gray-500">Copertura Dizionario</p>
              </div>
            </div>
            <div className="w-full bg-gray-200 rounded-full h-2 mb-4">
              <div
                className="bg-green-500 h-2 rounded-full transition-all"
                style={{ width: `${nonMappati.percentuale_copertura}%` }}
              />
            </div>

            {nonMappati.non_trovati === 0 ? (
              <div className="text-center py-8 text-green-600">
                <CheckCircle size={48} className="mx-auto mb-3" />
                <p className="font-semibold">Tutti gli ingredienti sono mappati!</p>
              </div>
            ) : (
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead className="bg-gray-50">
                    <tr>
                      <th className="text-left p-3 font-medium text-gray-600">Ingrediente (nelle ricette)</th>
                      <th className="text-center p-3 font-medium text-gray-600">Usato in</th>
                      <th className="text-left p-3 font-medium text-gray-600">Ricette Coinvolte</th>
                      <th className="text-left p-3 font-medium text-gray-600">Rinomina con</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y">
                    {nonMappati.ingredienti_mancanti.map((item, i) => (
                      <tr key={i} className="hover:bg-amber-50">
                        <td className="p-3">
                          <span className="font-medium text-amber-800 bg-amber-100 px-2 py-0.5 rounded text-sm">
                            {item.ingrediente}
                          </span>
                        </td>
                        <td className="p-3 text-center">
                          <span className="text-gray-700 font-semibold">{item.count}</span>
                          <span className="text-gray-400 text-xs ml-1">ricette</span>
                        </td>
                        <td className="p-3 text-xs text-gray-500">
                          {item.ricette.slice(0, 3).join(", ")}
                          {item.ricette.length > 3 && (
                            <span className="text-gray-400"> +{item.ricette.length - 3} altri</span>
                          )}
                        </td>
                        <td className="p-3">
                          <div className="flex gap-1.5 items-center">
                            <input
                              type="text"
                              placeholder="Nuovo nome ingrediente..."
                              value={rinominaState[item.ingrediente] || ""}
                              onChange={(e) =>
                                setRinominaState((prev) => ({ ...prev, [item.ingrediente]: e.target.value }))
                              }
                              onKeyDown={(e) => {
                                if (e.key === "Enter") handleRinomina(item.ingrediente, rinominaState[item.ingrediente]);
                              }}
                              list={`sug-${i}`}
                              className="flex-1 px-2 py-1.5 text-sm border border-gray-200 rounded-lg focus:ring-2 focus:ring-amber-400 focus:outline-none min-w-[160px]"
                            />
                            <datalist id={`sug-${i}`}>
                              {dizionario
                                .filter((p) =>
                                  p.nome_normalizzato?.toLowerCase().includes(
                                    (rinominaState[item.ingrediente] || "").toLowerCase().slice(0, 3)
                                  )
                                )
                                .slice(0, 8)
                                .map((p, j) => (
                                  <option key={j} value={p.nome_normalizzato} />
                                ))}
                            </datalist>
                            <button
                              onClick={() => handleRinomina(item.ingrediente, rinominaState[item.ingrediente])}
                              disabled={!rinominaState[item.ingrediente]?.trim()}
                              data-testid={`rinomina-btn-${i}`}
                              className="px-3 py-1.5 bg-amber-500 text-white rounded-lg text-xs font-medium hover:bg-amber-600 disabled:opacity-40 flex items-center gap-1"
                            >
                              <Save size={13} />Salva
                            </button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </>
        )}
      </Card>

      <Card className="p-4 bg-blue-50 border-blue-200">
        <p className="text-sm font-medium text-blue-800 mb-2">Come risolvere i mancanti</p>
        <ul className="text-xs text-blue-700 space-y-1 list-disc list-inside">
          <li><strong>Rinomina diretta:</strong> Scrivi il nome corretto e premi Salva — aggiorna tutte le ricette</li>
          <li>Il campo supporta autocomplete dai prodotti del dizionario</li>
          <li>Oppure importa le fatture XML dei fornitori che vendono questi prodotti</li>
        </ul>
      </Card>
    </div>
  );
}
