/**
 * RigaRicettaLista.jsx — Riga singola nella lista ricette di SchedaProdottoView
 */
import { useState } from "react";
import { ChevronRight, Copy, Trash2 } from "lucide-react";

const RigaRicettaLista = ({ r, varianti, isSelected, selectedVarianteId, onSelect, onClona, onDelete }) => {
  const [varAperte, setVarAperte] = useState(true);
  return (
    <div>
      <div onClick={() => onSelect(r)}
        className={`group flex items-center gap-2 px-3 py-2.5 rounded-xl cursor-pointer transition-all ${isSelected ? "bg-orange-100 border border-orange-300" : "bg-white border border-gray-100 hover:bg-orange-50 hover:border-orange-200"}`}>
        <div className="flex-1 min-w-0">
          <p className={`text-sm font-medium capitalize truncate ${isSelected ? "text-orange-800" : "text-gray-800"}`}>
            {r.nome}
            {r.approvata === false && (
              <span className="ml-1.5 text-[9px] font-bold bg-orange-100 text-orange-600 border border-orange-200 rounded-full px-1.5 py-0.5 align-middle">🆕 NUOVA</span>
            )}
          </p>
          <p className="text-xs text-gray-400">
            {r.ingredienti?.length || 0} ing{r.porzioni > 1 ? ` · ${r.porzioni} pz` : ""}
            {r.costo_totale > 0 && <span className="ml-1 text-green-600">€{Number(r.costo_totale).toFixed(2)}</span>}
          </p>
        </div>
        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 flex-shrink-0" onClick={e => e.stopPropagation()}>
          {varianti.length > 0 && (
            <button onClick={e => { e.stopPropagation(); setVarAperte(!varAperte); }}
              className="text-[10px] px-1.5 py-0.5 rounded bg-amber-100 text-amber-700 font-bold">
              {varAperte ? "▲" : "▼"} {varianti.length}
            </button>
          )}
          <button onClick={() => onClona && onClona(r)} className="p-1 text-green-400 hover:text-green-600" title="Clona"><Copy size={13} /></button>
          <button onClick={() => onDelete && onDelete(r.id)} className="p-1 text-red-300 hover:text-red-500" title="Elimina"><Trash2 size={13} /></button>
        </div>
        {isSelected && <ChevronRight size={14} className="text-orange-500 flex-shrink-0" />}
      </div>
      {varAperte && varianti.map(v => (
        <div key={v.id} onClick={() => onSelect(v)}
          className={`ml-3 flex items-center gap-2 px-3 py-2 rounded-xl cursor-pointer transition-all border-l-2 border-amber-300 ${selectedVarianteId === v.id ? "bg-amber-50 border-amber-400" : "bg-amber-50/30 hover:bg-amber-50"}`}>
          <span className="text-[9px] bg-amber-400 text-white px-1 py-0.5 rounded font-bold flex-shrink-0">V</span>
          <p className="text-xs text-gray-700 capitalize truncate flex-1">{v.nome}</p>
          {v.costo_totale > 0 && <span className="text-xs text-green-600">€{Number(v.costo_totale).toFixed(2)}</span>}
        </div>
      ))}
    </div>
  );
};

export default RigaRicettaLista;
