import { useState, useEffect } from "react";
import axios from "axios";
import { toast } from "sonner";
import { Search, Package, Edit, Plus, RefreshCw } from "lucide-react";
import { Trash2 } from "lucide-react";
import { API } from "../../../utils/constants";

const Card = ({ children, className = "" }) => (
  <div className={`bg-white rounded-xl shadow-sm border border-gray-100 ${className}`}>{children}</div>
);

function PrezziManualiSection({ onSaved, dizionario }) {
  const [manuali, setManuali] = useState([]);
  const [form, setForm] = useState({ nome: "", prezzo_kg: "", note: "", fornitore: "" });
  const [loading, setLoading] = useState(false);

  const fetchManuali = async () => {
    try {
      const res = await axios.get(`${API}/food-cost/dizionario/manuali`);
      setManuali(res.data || []);
    } catch {
      console.error("Errore prezzi manuali");
    }
  };

  useEffect(() => { fetchManuali(); }, []);

  const salva = async () => {
    if (!form.nome || !form.prezzo_kg) { toast.error("Nome e prezzo/kg obbligatori"); return; }
    setLoading(true);
    try {
      const res = await axios.post(`${API}/food-cost/dizionario/manuale`, {
        nome: form.nome,
        prezzo_kg: parseFloat(form.prezzo_kg),
        note: form.note,
        fornitore: form.fornitore || "Manuale",
      });
      toast.success(`${res.data.aggiornato ? "Aggiornato" : "Aggiunto"}: ${form.nome} a €${form.prezzo_kg}/kg`);
      setForm({ nome: "", prezzo_kg: "", note: "", fornitore: "" });
      fetchManuali();
      onSaved();
    } catch (e) {
      toast.error(e.response?.data?.detail || "Errore salvataggio");
    } finally {
      setLoading(false);
    }
  };

  const elimina = async (nome_norm) => {
    if (!window.confirm(`Eliminare il prezzo manuale per "${nome_norm}"?`)) return;
    try {
      await axios.delete(`${API}/food-cost/dizionario/manuale/${encodeURIComponent(nome_norm)}`);
      toast.success("Prezzo manuale eliminato");
      fetchManuali();
      onSaved();
    } catch {
      toast.error("Errore eliminazione");
    }
  };

  return (
    <Card className="p-5">
      <div className="flex items-center gap-2 mb-4">
        <Edit size={18} className="text-amber-600" />
        <h3 className="font-semibold text-gray-800">Prezzi Manuali</h3>
        <span className="text-xs text-gray-400">Ingredienti non in fattura (acquistati in contanti)</span>
        {manuali.length > 0 && (
          <span className="ml-auto text-xs bg-amber-100 text-amber-700 px-2 py-0.5 rounded-full">{manuali.length} inseriti</span>
        )}
      </div>
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3 mb-4 p-3 bg-amber-50 rounded-xl border border-amber-100">
        <div>
          <label className="text-xs font-medium text-gray-600">Nome ingrediente *</label>
          <input type="text" value={form.nome}
            onChange={(e) => setForm({ ...form, nome: e.target.value })}
            placeholder="es. capperi"
            className="w-full mt-0.5 px-2.5 py-1.5 border rounded-lg text-sm focus:ring-2 focus:ring-amber-400"
            onKeyDown={(e) => e.key === "Enter" && salva()}
          />
        </div>
        <div>
          <label className="text-xs font-medium text-gray-600">Prezzo €/kg *</label>
          <input type="number" step="0.01" min="0.01" value={form.prezzo_kg}
            onChange={(e) => setForm({ ...form, prezzo_kg: e.target.value })}
            placeholder="es. 12.50"
            className="w-full mt-0.5 px-2.5 py-1.5 border rounded-lg text-sm focus:ring-2 focus:ring-amber-400"
            onKeyDown={(e) => e.key === "Enter" && salva()}
          />
        </div>
        <div>
          <label className="text-xs font-medium text-gray-600">Fornitore</label>
          <input type="text" value={form.fornitore}
            onChange={(e) => setForm({ ...form, fornitore: e.target.value })}
            placeholder="es. Mercato"
            className="w-full mt-0.5 px-2.5 py-1.5 border rounded-lg text-sm"
          />
        </div>
        <div className="flex items-end">
          <button onClick={salva} disabled={loading}
            className="w-full px-3 py-1.5 bg-amber-600 text-white rounded-lg text-sm font-medium flex items-center justify-center gap-1.5 hover:bg-amber-700 disabled:opacity-50"
            data-testid="salva-prezzo-manuale-btn">
            <Plus size={14} /> Aggiungi
          </button>
        </div>
      </div>
      {manuali.length > 0 ? (
        <div className="space-y-1.5">
          {manuali.map((p) => (
            <div key={p.id || p.nome_normalizzato}
              className="flex items-center justify-between px-3 py-2 bg-white border border-amber-100 rounded-lg">
              <div className="flex items-center gap-3">
                <span className="font-medium text-gray-800 capitalize">{p.nome_normalizzato}</span>
                {p.fornitore && p.fornitore !== "Manuale" && (
                  <span className="text-xs text-gray-400">— {p.fornitore}</span>
                )}
              </div>
              <div className="flex items-center gap-3">
                <span className="font-bold text-amber-700">€{(p.prezzo_kg || 0).toFixed(2)}/kg</span>
                <span className="text-xs text-gray-400">{p.data_fattura}</span>
                <button onClick={() => elimina(p.nome_normalizzato)}
                  className="p-1 text-red-400 hover:bg-red-50 hover:text-red-600 rounded">
                  <Trash2 size={13} />
                </button>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="text-center py-6 text-gray-400">
          <p className="text-sm">Nessun prezzo manuale inserito</p>
        </div>
      )}
    </Card>
  );
}

// ── ScortaMinimaCell — cella editabile inline ────────────────────────────────
function ScortaMinimaCell({ prodotto, onSaved }) {
  const [editing, setEditing] = useState(false);
  const [val, setVal] = useState(String(prodotto.scorta_minima ?? ""));
  const [saving, setSaving] = useState(false);

  const salva = async () => {
    const num = parseFloat(val);
    if (isNaN(num) || num < 0) { toast.error("Valore non valido"); return; }
    setSaving(true);
    try {
      await axios.patch(`${API}/food-cost/dizionario/${prodotto.id}/scorta-minima?scorta_minima=${num}`);
      toast.success(`Scorta minima aggiornata: ${num} kg`);
      setEditing(false);
      onSaved();
    } catch {
      toast.error("Errore salvataggio scorta minima");
    } finally {
      setSaving(false);
    }
  };

  if (!editing) {
    const hasSoglia = (prodotto.scorta_minima ?? 0) > 0;
    return (
      <button
        data-testid={`scorta-min-${prodotto.id}`}
        onClick={() => { setVal(String(prodotto.scorta_minima ?? "")); setEditing(true); }}
        className={`text-xs font-semibold px-2 py-0.5 rounded border border-dashed transition-colors ${hasSoglia ? "text-orange-600 border-orange-300 bg-orange-50 hover:bg-orange-100" : "text-gray-400 border-gray-200 hover:bg-gray-50"}`}
      >
        {hasSoglia ? `${Number(prodotto.scorta_minima).toFixed(1)} kg` : "—"}
      </button>
    );
  }

  return (
    <div className="flex items-center gap-1">
      <input
        type="number" min="0" step="0.5" autoFocus
        value={val} onChange={e => setVal(e.target.value)}
        onKeyDown={e => { if (e.key === "Enter") salva(); if (e.key === "Escape") setEditing(false); }}
        className="w-16 px-1.5 py-0.5 text-xs border-2 border-orange-400 rounded outline-none text-center"
      />
      <button onClick={salva} disabled={saving}
        className="text-xs px-1.5 py-0.5 bg-orange-500 text-white rounded font-bold disabled:opacity-50">
        {saving ? "…" : "OK"}
      </button>
      <button onClick={() => setEditing(false)} className="text-xs px-1 py-0.5 text-gray-400 hover:text-gray-600">✕</button>
    </div>
  );
}

export function TabDizionario({ dizionario, fetchDizionario }) {
  const [searchDizionario, setSearchDizionario] = useState("");

  const dizionarioFiltrato = searchDizionario
    ? dizionario.filter((p) =>
        p.nome_normalizzato?.toLowerCase().includes(searchDizionario.toLowerCase()) ||
        p.fornitore?.toLowerCase().includes(searchDizionario.toLowerCase())
      ).slice(0, 100)
    : dizionario.slice(0, 100);

  return (
    <div className="space-y-4">
      <Card className="p-5">
        <div className="flex items-center justify-between mb-4">
          <div>
            <h3 className="font-semibold flex items-center gap-2">
              <Package size={18} className="text-purple-600" />Dizionario Prodotti
            </h3>
            <p className="text-sm text-gray-500">{dizionario.length} prodotti dai fornitori attivi</p>
          </div>
          <button
            onClick={async () => {
              try {
                const res = await axios.post(`${API}/food-cost/sincronizza-fatture`);
                const d = res.data;
                toast.success(`Sincronizzazione: ${d.prodotti_trovati} processati, ${d.prodotti_aggiunti} nuovi, ${d.prodotti_aggiornati} aggiornati`);
                fetchDizionario();
              } catch {
                toast.error("Errore sincronizzazione");
              }
            }}
            className="px-3 py-2 bg-purple-600 text-white rounded-lg text-sm flex items-center gap-2 hover:bg-purple-700"
          >
            <RefreshCw size={14} /> Sincronizza Prezzi da Fatture
          </button>
        </div>
        <div className="relative mb-4">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
          <input type="text" placeholder="Cerca prodotto o fornitore..." value={searchDizionario}
            onChange={(e) => setSearchDizionario(e.target.value)}
            className="w-full pl-9 pr-3 py-2 text-sm border rounded-lg focus:ring-2 focus:ring-purple-400" />
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead className="bg-gray-100">
              <tr>
                <th className="text-left p-3">Prodotto</th>
                <th className="text-left p-3">Fornitore</th>
                <th className="text-center p-3">Confezione</th>
                <th className="text-right p-3">€/kg</th>
                <th className="text-right p-3">Disponibile</th>
                <th className="text-center p-3" title="Scorta minima: soglia sotto la quale viene segnalato SOTTO SCORTA">
                  Scorta min. <span className="text-gray-400 font-normal">(kg)</span>
                </th>
              </tr>
            </thead>
            <tbody className="divide-y">
              {dizionarioFiltrato.map((p) => {
                const sottoScorta = (p.scorta_minima ?? 0) > 0
                  ? (p.quantita_disponibile_kg || 0) < p.scorta_minima
                  : (p.quantita_disponibile_kg || 0) < 1;
                return (
                  <tr key={p.id} className={`hover:bg-gray-50 ${p.inserito_manualmente ? "bg-amber-50/50" : ""} ${sottoScorta ? "bg-red-50/30" : ""}`}>
                    <td className="p-3 font-medium capitalize">
                      {p.nome_normalizzato}
                      {p.inserito_manualmente && (
                        <span className="ml-2 text-xs bg-amber-100 text-amber-700 px-1.5 py-0.5 rounded">manuale</span>
                      )}
                      {sottoScorta && (
                        <span className="ml-2 text-xs bg-red-100 text-red-600 px-1.5 py-0.5 rounded font-bold">↓ scorta</span>
                      )}
                    </td>
                    <td className="p-3 text-xs text-gray-500 max-w-[200px] truncate">{p.fornitore}</td>
                    <td className="p-3 text-center text-xs">{p.peso_confezione} {p.unita_confezione}</td>
                    <td className="p-3 text-right font-bold text-green-600">€{(p.prezzo_kg || 0).toFixed(2)}</td>
                    <td className="p-3 text-right">
                      <span className={`font-bold ${sottoScorta ? "text-red-500" : "text-green-600"}`}>
                        {(p.quantita_disponibile_kg || 0).toFixed(1)} kg
                      </span>
                    </td>
                    <td className="p-3 text-center">
                      {p.id ? <ScortaMinimaCell prodotto={p} onSaved={fetchDizionario} /> : <span className="text-gray-300 text-xs">—</span>}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
        {dizionarioFiltrato.length >= 100 && (
          <p className="text-center text-gray-400 text-xs mt-3">Mostrati 100 risultati. Usa la ricerca per filtrare.</p>
        )}
      </Card>
      <PrezziManualiSection onSaved={fetchDizionario} dizionario={dizionario} />
    </div>
  );
}
