import { useState } from "react";
import { FileText } from "lucide-react";

const MESI = ["Gen","Feb","Mar","Apr","Mag","Giu","Lug","Ago","Set","Ott","Nov","Dic"];

const HACCPPdfButton = () => {
  const now = new Date();
  const [mese, setMese] = useState(now.getMonth() + 1);
  const [anno, setAnno] = useState(now.getFullYear());
  const [fase, setFase] = useState("idle");
  const [reportHtml, setReportHtml] = useState("");

  const apriReport = async () => {
    const url = `${process.env.REACT_APP_BACKEND_URL}/api/report-haccp/mensile?mese=${mese}&anno=${anno}`;
    setFase("caricamento");
    try {
      const res = await fetch(url, { headers: { Accept: "text/html" } });
      const html = await res.text();
      setReportHtml(html);
      setFase("viewer");
    } catch (e) {
      setReportHtml(`<div style="padding:40px;color:red;font-size:16px;">Errore: ${e.message}</div>`);
      setFase("viewer");
    }
  };

  const scaricaHtml = () => {
    if (!reportHtml) return;
    const blob = new Blob([reportHtml], { type: "text/html;charset=utf-8" });
    const a = document.createElement("a");
    a.href = URL.createObjectURL(blob);
    a.download = `report_haccp_${anno}_${String(mese).padStart(2,"0")}.html`;
    document.body.appendChild(a);
    a.click();
    setTimeout(() => { URL.revokeObjectURL(a.href); document.body.removeChild(a); }, 1000);
  };

  const chiudi = () => { setFase("idle"); setReportHtml(""); };

  if (fase === "scelta") {
    return (
      <div style={{ position: "fixed", inset: 0, zIndex: 99999, background: "rgba(0,0,0,0.6)", display: "flex", alignItems: "center", justifyContent: "center" }}>
        <div style={{ background: "#fff", borderRadius: 16, padding: 28, width: 320, boxShadow: "0 20px 60px rgba(0,0,0,0.3)" }}>
          <h3 style={{ margin: "0 0 16px", fontSize: 16, fontWeight: 700, color: "#1e293b" }}>Report HACCP Mensile</h3>
          <div style={{ display: "flex", gap: 10, marginBottom: 20 }}>
            <select value={mese} onChange={e => setMese(Number(e.target.value))}
              style={{ flex: 1, padding: "8px 12px", borderRadius: 8, border: "2px solid #e2e8f0", fontSize: 14 }}>
              {MESI.map((m, i) => <option key={i+1} value={i+1}>{m}</option>)}
            </select>
            <select value={anno} onChange={e => setAnno(Number(e.target.value))}
              style={{ width: 90, padding: "8px 12px", borderRadius: 8, border: "2px solid #e2e8f0", fontSize: 14 }}>
              {[2024, 2025, 2026, 2027].map(a => <option key={a} value={a}>{a}</option>)}
            </select>
          </div>
          <div style={{ display: "flex", gap: 10 }}>
            <button onClick={chiudi}
              style={{ flex: 1, padding: "10px 0", borderRadius: 9, border: "2px solid #e2e8f0", background: "#f8fafc", fontWeight: 600, fontSize: 14, cursor: "pointer", color: "#64748b" }}>
              Annulla
            </button>
            <button onClick={apriReport} data-testid="btn-apri-report-confirm"
              style={{ flex: 2, padding: "10px 0", borderRadius: 9, border: "none", background: "#dc2626", color: "#fff", fontWeight: 700, fontSize: 14, cursor: "pointer" }}>
              Apri Report
            </button>
          </div>
        </div>
      </div>
    );
  }

  if (fase === "caricamento") {
    return (
      <div style={{ position: "fixed", inset: 0, zIndex: 99999, background: "#fff", display: "flex", alignItems: "center", justifyContent: "center", flexDirection: "column", gap: 16 }}>
        <div style={{ fontSize: 32 }}>⏳</div>
        <p style={{ fontSize: 16, color: "#64748b", fontWeight: 600 }}>Generazione report in corso...</p>
      </div>
    );
  }

  if (fase === "viewer") {
    return (
      <div style={{ position: "fixed", inset: 0, zIndex: 99999, display: "flex", flexDirection: "column", background: "#fff" }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "10px 16px", background: "#dc2626", color: "#fff", flexShrink: 0 }}>
          <span style={{ fontWeight: 700, fontSize: 14 }}>Report HACCP — {MESI[mese-1]} {anno}</span>
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={scaricaHtml}
              style={{ padding: "6px 14px", borderRadius: 7, border: "2px solid rgba(255,255,255,0.5)", background: "rgba(255,255,255,0.15)", color: "#fff", fontSize: 13, fontWeight: 600, cursor: "pointer" }}>
              Scarica HTML
            </button>
            <button onClick={() => {
              const w = window.open('', '_blank');
              w.document.write(reportHtml);
              w.document.close();
              setTimeout(() => w.print(), 800);
            }}
              style={{ padding: "6px 14px", borderRadius: 7, border: "2px solid rgba(255,255,255,0.5)", background: "rgba(255,255,255,0.2)", color: "#fff", fontSize: 13, fontWeight: 700, cursor: "pointer" }}>
              Stampa
            </button>
            <button onClick={chiudi}
              style={{ padding: "6px 14px", borderRadius: 7, border: "2px solid rgba(255,255,255,0.5)", background: "rgba(255,255,255,0.15)", color: "#fff", fontSize: 13, fontWeight: 700, cursor: "pointer" }}>
              Chiudi
            </button>
          </div>
        </div>
        <iframe srcDoc={reportHtml} style={{ flex: 1, width: "100%", border: "none" }} title="Report HACCP" sandbox="allow-same-origin allow-scripts allow-modals" />
      </div>
    );
  }

  return (
    <button
      onClick={() => setFase("scelta")}
      data-testid="btn-scarica-pdf-haccp"
      className="flex items-center gap-1.5 px-3 py-1.5 bg-red-600 text-white rounded-lg text-xs font-semibold hover:bg-red-700 transition-colors shadow-sm whitespace-nowrap ml-auto flex-shrink-0"
    >
      <FileText size={13} />
      Report PDF
    </button>
  );
};

export default HACCPPdfButton;
