import { useState } from "react";
import axios from "axios";
import { toast } from "sonner";
import { Search, ChefHat, AlertTriangle, Edit, RefreshCw, CheckCircle } from "lucide-react";
import { API } from "../../../utils/constants";

const Card = ({ children, className = "" }) => (
  <div className={`bg-white rounded-xl shadow-sm border border-gray-100 ${className}`}>{children}</div>
);

export function TabFoodCost({ ricetteFiltrate, ricette, stats, loading, searchRicetta, setSearchRicetta, handleEditRicetta, fetchRicette, setActiveTab }) {
  const [autoMapping, setAutoMapping] = useState(false);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-5">
      <Card className="p-5">
        <div className="flex items-center gap-2 mb-4">
          <ChefHat size={20} className="text-green-600" />
          <h3 className="font-semibold">Ricette - Analisi Costi</h3>
        </div>
        <div className="relative mb-3">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
          <input type="text" placeholder="Cerca..." value={searchRicetta}
            onChange={(e) => setSearchRicetta(e.target.value)}
            className="w-full pl-9 pr-3 py-2 text-sm border rounded-lg focus:ring-2 focus:ring-green-400" />
        </div>
        <div className="space-y-1.5 max-h-[500px] overflow-y-auto">
          {ricetteFiltrate.map((r) => (
            <div key={r.id}
              onClick={() => setActiveTab("ricettario")}
              className="p-3 bg-gray-50 rounded-lg border border-gray-200 hover:border-green-300 hover:bg-green-50 cursor-pointer flex justify-between items-center">
              <div>
                <p className="font-medium text-sm">{r.nome}</p>
                <p className="text-xs text-gray-500">{r.ingredienti_totali} ingr • {r.completezza} con prezzo</p>
              </div>
              <div className="text-right">
                <p className="font-bold text-green-600">€{(r.costo_totale || 0).toFixed(2)}</p>
                <p className="text-xs text-gray-400">€{(r.costo_porzione || 0).toFixed(2)}/pz</p>
              </div>
            </div>
          ))}
        </div>
      </Card>

      <Card className="p-5">
        <div className="flex items-center gap-2 mb-4 text-amber-700">
          <AlertTriangle size={20} />
          <h3 className="font-semibold">Riepilogo Statistiche</h3>
        </div>
        <div className="space-y-3">
          <div className="p-4 bg-green-50 rounded-xl">
            <p className="text-3xl font-bold text-green-600">€{stats.costoMedio.toFixed(2)}</p>
            <p className="text-sm text-green-700">Costo medio per ricetta</p>
          </div>
          <div className="p-4 bg-blue-50 rounded-xl">
            <p className="text-3xl font-bold text-blue-600">{stats.complete}/{stats.totale}</p>
            <p className="text-sm text-blue-700">Ricette con costo completo</p>
          </div>
          <div className="p-4 bg-amber-50 rounded-xl border border-amber-200">
            <div className="flex items-center justify-between mb-2">
              <p className="font-medium text-amber-800 flex items-center gap-2">
                <AlertTriangle size={16} />Ricette incomplete
              </p>
              <button
                data-testid="auto-mappa-btn"
                onClick={async () => {
                  setAutoMapping(true);
                  try {
                    const res = await axios.post(`${API}/food-cost/auto-mappa-ingredienti`);
                    const d = res.data;
                    toast.success(`Auto-mapping: ${d.ingredienti_mappati} ingredienti mappati, ${d.ricette_aggiornate} ricette aggiornate`);
                    fetchRicette();
                  } catch (e) {
                    toast.error("Errore auto-mapping: " + (e.response?.data?.detail || e.message));
                  } finally {
                    setAutoMapping(false);
                  }
                }}
                disabled={loading || autoMapping}
                className="px-2 py-1 bg-amber-600 text-white rounded text-xs flex items-center gap-1 hover:bg-amber-700 disabled:opacity-50"
              >
                <RefreshCw size={11} className={(loading || autoMapping) ? "animate-spin" : ""} />
                Auto-mappa
              </button>
            </div>
            <div className="space-y-1 max-h-48 overflow-y-auto">
              {ricette.filter((r) => {
                const [con, tot] = (r.completezza || "0/0").split("/").map(Number);
                return tot > 0 && con < tot;
              }).map((r) => (
                <div
                  key={r.id}
                  onClick={() => { handleEditRicetta(r); setActiveTab("ricettario"); }}
                  className="flex justify-between text-sm p-1.5 bg-white rounded border border-amber-100 cursor-pointer hover:bg-amber-50 hover:border-amber-300 transition-colors group"
                >
                  <span className="truncate group-hover:text-amber-800">{r.nome}</span>
                  <div className="flex items-center gap-1.5 ml-2 flex-shrink-0">
                    <span className="text-amber-600 font-medium">{r.completezza}</span>
                    <Edit size={11} className="text-amber-400 opacity-0 group-hover:opacity-100" />
                  </div>
                </div>
              ))}
              {ricette.filter((r) => {
                const [con, tot] = (r.completezza || "0/0").split("/").map(Number);
                return tot > 0 && con < tot;
              }).length === 0 && (
                <p className="text-center text-green-600 text-sm py-2 flex items-center justify-center gap-1">
                  <CheckCircle size={14} /> Tutte le ricette sono complete!
                </p>
              )}
            </div>
          </div>
        </div>
      </Card>
    </div>
  );
}
