import React, { useState, useEffect, useMemo } from "react";
import axios from "axios";
import { toast } from "sonner";
import { API } from "../../utils/constants";

// ── Icone ────────────────────────────────────────────────────────────────────
const IconAlert = () => (
  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
    <path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/>
    <line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/>
  </svg>
);
const IconCheck = () => (
  <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3">
    <polyline points="20 6 9 17 4 12"/>
  </svg>
);
const IconSend = () => (
  <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
    <line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/>
  </svg>
);
const IconHistory = () => (
  <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
    <polyline points="12 8 12 12 14 14"/>
    <path d="M3.05 11a9 9 0 1 0 .5-4.5M3 3v5h5"/>
  </svg>
);

// ── CardProdottoOrdine ────────────────────────────────────────────────────────
function CardProdottoOrdine({ prodotto, selezionato, quantita, onToggle, onQuantita }) {
  const sottoScorta = prodotto.sotto_scorta;
  const borderColor = selezionato ? (sottoScorta ? "#ef4444" : "#3b82f6") : (sottoScorta ? "#fca5a5" : "#e2e8f0");
  const bgColor = selezionato ? (sottoScorta ? "#fef2f2" : "#eff6ff") : "#fff";

  return (
    <div
      data-testid={`card-prodotto-${prodotto.id}`}
      style={{ border: `2px solid ${borderColor}`, borderRadius: 12, background: bgColor, padding: "10px 12px", display: "flex", alignItems: "center", gap: 10, cursor: "pointer", transition: "border-color 0.15s, background 0.15s" }}
      onClick={() => onToggle(prodotto.id)}
    >
      <div style={{ width: 22, height: 22, borderRadius: 6, flexShrink: 0, border: `2px solid ${selezionato ? (sottoScorta ? "#ef4444" : "#3b82f6") : "#cbd5e1"}`, background: selezionato ? (sottoScorta ? "#ef4444" : "#3b82f6") : "#fff", display: "flex", alignItems: "center", justifyContent: "center", color: "#fff" }}>
        {selezionato && <IconCheck />}
      </div>
      <div style={{ width: 40, height: 40, borderRadius: 8, flexShrink: 0, overflow: "hidden", background: "#f1f5f9", display: "flex", alignItems: "center", justifyContent: "center" }}>
        {prodotto.foto_url ? (
          <img src={prodotto.foto_url} alt={prodotto.nome} style={{ width: "100%", height: "100%", objectFit: "cover" }} onError={e => { e.target.style.display = "none"; }} />
        ) : <span style={{ fontSize: 18 }}>📦</span>}
      </div>
      <div style={{ flex: 1, minWidth: 0 }}>
        <p style={{ margin: 0, fontWeight: 700, fontSize: 13, color: "#1e293b", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis", textTransform: "capitalize" }}>{prodotto.nome}</p>
        <div style={{ display: "flex", gap: 6, marginTop: 2, flexWrap: "wrap" }}>
          <span style={{ fontSize: 10, color: "#64748b" }}>{prodotto.fornitore}</span>
          {prodotto.prezzo_kg > 0 && <span style={{ fontSize: 10, color: "#059669", fontWeight: 600 }}>€{prodotto.prezzo_kg.toFixed(2)}/kg</span>}
          {sottoScorta && (
            <span style={{ fontSize: 9, fontWeight: 700, color: "#dc2626", background: "#fee2e2", borderRadius: 4, padding: "1px 5px", display: "flex", alignItems: "center", gap: 2 }}>
              <IconAlert /> SOTTO SCORTA
            </span>
          )}
        </div>
        <p style={{ margin: "1px 0 0", fontSize: 10, color: "#94a3b8" }}>Disp: {prodotto.quantita_disponibile_kg.toFixed(1)} kg</p>
      </div>
      <div style={{ flexShrink: 0, display: "flex", flexDirection: "column", alignItems: "center", gap: 2 }} onClick={e => e.stopPropagation()}>
        <div style={{ display: "flex", alignItems: "center", gap: 3 }}>
          <button onClick={e => { e.stopPropagation(); onQuantita(prodotto.id, Math.max(0.5, quantita - 0.5)); }} style={{ width: 22, height: 22, borderRadius: 5, border: "1.5px solid #e2e8f0", background: "#f8fafc", fontSize: 13, cursor: "pointer", fontWeight: 700 }}>−</button>
          <input type="number" min="0.5" step="0.5" value={quantita} onChange={e => { e.stopPropagation(); onQuantita(prodotto.id, Math.max(0.5, parseFloat(e.target.value) || 0.5)); }} onClick={e => e.stopPropagation()} style={{ width: 40, textAlign: "center", fontSize: 12, fontWeight: 700, border: "1.5px solid #e2e8f0", borderRadius: 5, padding: "1px 0", outline: "none" }} />
          <button onClick={e => { e.stopPropagation(); onQuantita(prodotto.id, quantita + 0.5); }} style={{ width: 22, height: 22, borderRadius: 5, border: "1.5px solid #e2e8f0", background: "#f8fafc", fontSize: 13, cursor: "pointer", fontWeight: 700 }}>+</button>
        </div>
        <span style={{ fontSize: 9, color: "#94a3b8" }}>{prodotto.unita_confezione || "kg"}</span>
      </div>
    </div>
  );
}

// ── CardRicettaOrdine ─────────────────────────────────────────────────────────
function CardRicettaOrdine({ ricetta, selezionata, lotti, onToggle, onLotti }) {
  return (
    <div
      data-testid={`card-ricetta-${ricetta.id}`}
      style={{ border: `2px solid ${selezionata ? "#7c3aed" : "#e2e8f0"}`, borderRadius: 12, background: selezionata ? "#f5f3ff" : "#fff", padding: "10px 12px", display: "flex", alignItems: "center", gap: 10, cursor: "pointer" }}
      onClick={() => onToggle(ricetta.id)}
    >
      <div style={{ width: 22, height: 22, borderRadius: 6, flexShrink: 0, border: `2px solid ${selezionata ? "#7c3aed" : "#cbd5e1"}`, background: selezionata ? "#7c3aed" : "#fff", display: "flex", alignItems: "center", justifyContent: "center", color: "#fff" }}>
        {selezionata && <IconCheck />}
      </div>
      <div style={{ width: 40, height: 40, borderRadius: 8, flexShrink: 0, overflow: "hidden", background: "#f1f5f9", display: "flex", alignItems: "center", justifyContent: "center" }}>
        {ricetta.foto_url ? <img src={ricetta.foto_url} alt={ricetta.nome} style={{ width: "100%", height: "100%", objectFit: "cover" }} onError={e => { e.target.style.display = "none"; }} /> : <span style={{ fontSize: 18 }}>🍽️</span>}
      </div>
      <div style={{ flex: 1, minWidth: 0 }}>
        <p style={{ margin: 0, fontWeight: 700, fontSize: 13, color: "#1e293b", textTransform: "capitalize", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{ricetta.nome}</p>
        <p style={{ margin: "1px 0 0", fontSize: 10, color: "#64748b" }}>{ricetta.reparto || "—"} · {ricetta.porzioni || 1} pz/ricetta</p>
      </div>
      <div style={{ flexShrink: 0, display: "flex", flexDirection: "column", alignItems: "center", gap: 2 }} onClick={e => e.stopPropagation()}>
        <div style={{ display: "flex", alignItems: "center", gap: 3 }}>
          <button onClick={e => { e.stopPropagation(); onLotti(ricetta.id, Math.max(1, lotti - 1)); }} style={{ width: 22, height: 22, borderRadius: 5, border: "1.5px solid #e2e8f0", background: "#f8fafc", fontSize: 13, cursor: "pointer", fontWeight: 700 }}>−</button>
          <input type="number" min="1" step="1" value={lotti} onChange={e => { e.stopPropagation(); onLotti(ricetta.id, Math.max(1, parseInt(e.target.value) || 1)); }} onClick={e => e.stopPropagation()} style={{ width: 36, textAlign: "center", fontSize: 12, fontWeight: 700, border: "1.5px solid #e2e8f0", borderRadius: 5, padding: "1px 0", outline: "none" }} />
          <button onClick={e => { e.stopPropagation(); onLotti(ricetta.id, lotti + 1); }} style={{ width: 22, height: 22, borderRadius: 5, border: "1.5px solid #e2e8f0", background: "#f8fafc", fontSize: 13, cursor: "pointer", fontWeight: 700 }}>+</button>
        </div>
        <span style={{ fontSize: 9, color: "#94a3b8" }}>lotti</span>
      </div>
    </div>
  );
}

// ── StoricoOrdini ─────────────────────────────────────────────────────────────
function StoricoOrdini() {
  const [ordini, setOrdini] = useState([]);
  const [loading, setLoading] = useState(true);
  const [aperto, setAperto] = useState(null);

  useEffect(() => {
    axios.get(`${API}/ordini-fornitori?source=tracciabilita&limit=30`)
      .then(r => setOrdini(r.data || []))
      .catch(() => toast.error("Errore caricamento storico"))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <div style={{ textAlign: "center", padding: 40, color: "#94a3b8" }}>Caricamento...</div>;

  if (!ordini.length) return (
    <div style={{ textAlign: "center", padding: 40, color: "#94a3b8" }}>
      <p style={{ fontSize: 32, marginBottom: 8 }}>📋</p>
      <p>Nessun ordine inviato finora.</p>
    </div>
  );

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
      {ordini.map(o => {
        const isAperto = aperto === o.id;
        const stato = o.stato || "inviato";
        const statoColor = stato === "completato" ? "#059669" : stato === "inviato" ? "#3b82f6" : "#f59e0b";
        return (
          <div key={o.id} style={{ border: "1.5px solid #e2e8f0", borderRadius: 12, overflow: "hidden" }}>
            <div style={{ padding: "12px 14px", cursor: "pointer", display: "flex", justifyContent: "space-between", alignItems: "center" }}
              onClick={() => setAperto(isAperto ? null : o.id)}>
              <div>
                <p style={{ margin: 0, fontSize: 13, fontWeight: 700, color: "#1e293b" }}>
                  Ordine del {o.data_ordine} · {(o.prodotti || []).length} prodotti
                  {(o.ricette_da_produrre || []).length > 0 && ` + ${o.ricette_da_produrre.length} ricette`}
                </p>
                <p style={{ margin: "2px 0 0", fontSize: 11, color: "#64748b" }}>
                  {o.reparto && <span>{o.reparto} · </span>}
                  <span style={{ color: statoColor, fontWeight: 700 }}>{stato.toUpperCase()}</span>
                  {o.note_operatore && <span style={{ color: "#94a3b8" }}> · "{o.note_operatore}"</span>}
                </p>
              </div>
              <span style={{ fontSize: 12, color: "#94a3b8" }}>{isAperto ? "▲" : "▼"}</span>
            </div>
            {isAperto && (
              <div style={{ padding: "0 14px 14px", borderTop: "1px solid #f1f5f9" }}>
                {(o.prodotti || []).length > 0 && (
                  <>
                    <p style={{ fontSize: 11, fontWeight: 700, color: "#64748b", margin: "10px 0 6px", textTransform: "uppercase" }}>Prodotti ordinati</p>
                    {o.prodotti.map((p, i) => (
                      <div key={i} style={{ display: "flex", justifyContent: "space-between", padding: "4px 8px", background: "#f8fafc", borderRadius: 6, marginBottom: 3, fontSize: 12 }}>
                        <span style={{ color: "#374151", textTransform: "capitalize" }}>{p.nome}</span>
                        <span style={{ color: "#1e293b", fontWeight: 700 }}>{p.quantita} {p.unita}</span>
                      </div>
                    ))}
                  </>
                )}
                {(o.ricette_da_produrre || []).length > 0 && (
                  <>
                    <p style={{ fontSize: 11, fontWeight: 700, color: "#7c3aed", margin: "10px 0 6px", textTransform: "uppercase" }}>Ricette da produrre</p>
                    {o.ricette_da_produrre.map((r, i) => (
                      <div key={i} style={{ display: "flex", justifyContent: "space-between", padding: "4px 8px", background: "#f5f3ff", borderRadius: 6, marginBottom: 3, fontSize: 12 }}>
                        <span style={{ color: "#374151", textTransform: "capitalize" }}>{r.nome}</span>
                        <span style={{ color: "#7c3aed", fontWeight: 700 }}>{r.quantita} lotti</span>
                      </div>
                    ))}
                  </>
                )}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

// ── OrdiniFornitoriView (componente principale) ───────────────────────────────
const REPARTI = [
  { id: "tutti", label: "Tutti" },
  { id: "rosticceria", label: "Rosticceria" },
  { id: "pasticceria", label: "Pasticceria" },
  { id: "bar", label: "Bar" },
];

export default function OrdiniFornitoriView() {
  const [vista, setVista]                 = useState("nuovo");   // "nuovo" | "storico"
  const [prodotti, setProdotti]           = useState([]);
  const [ricette, setRicette]             = useState([]);
  const [loading, setLoading]             = useState(true);
  const [search, setSearch]               = useState("");
  const [reparto, setReparto]             = useState("tutti");
  const [fornitoreAttivo, setFornitoreAttivo] = useState("tutti");
  const [sezioneProdotti, setSezioneProdotti] = useState(true);
  const [sezioneRicette, setSezioneRicette]   = useState(false);
  const [selProdotti, setSelProdotti]     = useState({});
  const [qtProdotti, setQtProdotti]       = useState({});
  const [selRicette, setSelRicette]       = useState({});
  const [lottiRicette, setLottiRicette]   = useState({});
  const [noteOperatore, setNoteOperatore] = useState("");
  const [inviando, setInviando]           = useState(false);
  const [ordineSalvato, setOrdineSalvato] = useState(null);

  useEffect(() => {
    const load = async () => {
      setLoading(true);
      try {
        const [resProd, resRic] = await Promise.all([
          axios.get(`${API}/ordini-fornitori/prodotti-suggeriti?limit=700`),
          axios.get(`${API}/ricette`),
        ]);
        const prods = resProd.data || [];
        setProdotti(prods);
        setRicette(resRic.data || []);
        // Pre-seleziona sotto scorta
        const ps = {}, qs = {};
        prods.forEach(p => {
          if (p.sotto_scorta) {
            ps[p.id] = true;
            qs[p.id] = p.peso_confezione > 0 ? p.peso_confezione : 1;
          }
        });
        setSelProdotti(ps);
        setQtProdotti(qs);
      } catch {
        toast.error("Errore caricamento");
      }
      setLoading(false);
    };
    load();
  }, []);

  const fornitori = useMemo(() => {
    const u = [...new Set(prodotti.map(p => p.fornitore).filter(Boolean))].sort();
    return ["tutti", ...u];
  }, [prodotti]);

  const prodottiFiltrati = useMemo(() => prodotti.filter(p => {
    const ms = !search || p.nome.toLowerCase().includes(search.toLowerCase());
    const mf = fornitoreAttivo === "tutti" || p.fornitore === fornitoreAttivo;
    return ms && mf;
  }), [prodotti, search, fornitoreAttivo]);

  const ricetteFiltrate = useMemo(() => ricette.filter(r => {
    const ms = !search || r.nome?.toLowerCase().includes(search.toLowerCase());
    const mr = reparto === "tutti" || r.reparto === reparto;
    return ms && mr;
  }), [ricette, search, reparto]);

  const sottoScorta    = prodottiFiltrati.filter(p => p.sotto_scorta);
  const nonSottoScorta = prodottiFiltrati.filter(p => !p.sotto_scorta);
  const nProdSel = Object.values(selProdotti).filter(Boolean).length;
  const nRicSel  = Object.values(selRicette).filter(Boolean).length;
  const nTotSel  = nProdSel + nRicSel;

  // Costo stimato totale: Σ(quantita × prezzo_kg) per prodotti selezionati
  const costoStimato = useMemo(() => {
    return Object.entries(selProdotti)
      .filter(([, v]) => v)
      .reduce((acc, [id]) => {
        const p = prodotti.find(x => x.id === id);
        const qt = qtProdotti[id] || (p?.peso_confezione > 0 ? p.peso_confezione : 1);
        return acc + (p?.prezzo_kg || 0) * qt;
      }, 0);
  }, [selProdotti, qtProdotti, prodotti]);

  const handleToggleProd = (id) => {
    setSelProdotti(prev => {
      const n = { ...prev, [id]: !prev[id] };
      if (n[id] && !qtProdotti[id]) {
        const p = prodotti.find(x => x.id === id);
        setQtProdotti(q => ({ ...q, [id]: p?.peso_confezione > 0 ? p.peso_confezione : 1 }));
      }
      return n;
    });
  };

  const handleToggleRic = (id) => {
    setSelRicette(prev => {
      const n = { ...prev, [id]: !prev[id] };
      if (n[id] && !lottiRicette[id]) setLottiRicette(l => ({ ...l, [id]: 1 }));
      return n;
    });
  };

  const handleInvia = async () => {
    if (nTotSel === 0) { toast.warning("Seleziona almeno un prodotto o ricetta"); return; }
    setInviando(true);
    try {
      const prodottiOrdine = Object.entries(selProdotti).filter(([, v]) => v).map(([id]) => {
        const p = prodotti.find(x => x.id === id);
        return { prodotto_id: id, nome: p?.nome || id, fornitore: p?.fornitore || "", quantita: qtProdotti[id] || 1, unita: p?.unita_confezione || "kg", prezzo_ultimo: p?.prezzo_kg || 0, note: "" };
      });
      const ricetteOrdine = Object.entries(selRicette).filter(([, v]) => v).map(([id]) => {
        const r = ricette.find(x => x.id === id);
        return { ricetta_id: id, nome: r?.nome || id, reparto: r?.reparto || "", quantita: lottiRicette[id] || 1, note: "" };
      });
      const res = await axios.post(`${API}/ordini-fornitori`, {
        reparto, operatore: "", prodotti: prodottiOrdine,
        ricette_da_produrre: ricetteOrdine, note_operatore: noteOperatore,
      });
      setOrdineSalvato(res.data);
      toast.success(`Ordine ${res.data.ordine_id.slice(0, 8)}... inviato`);
    } catch (e) {
      toast.error("Errore: " + (e.response?.data?.detail || e.message));
    } finally {
      setInviando(false);
    }
  };

  // ── Schermata conferma ────────────────────────────────────────────────────
  if (ordineSalvato) {
    const prods = ordineSalvato.ordine?.prodotti || [];
    const rics  = ordineSalvato.ordine?.ricette_da_produrre || [];
    return (
      <div style={{ maxWidth: 700, margin: "0 auto", padding: "24px 16px" }}>
        <div style={{ background: "#f0fdf4", border: "2px solid #86efac", borderRadius: 16, padding: "24px 20px", textAlign: "center", marginBottom: 24 }}>
          <div style={{ fontSize: 40, marginBottom: 8 }}>✅</div>
          <h2 style={{ fontSize: 18, fontWeight: 800, color: "#166534", margin: "0 0 4px" }}>Ordine inviato</h2>
          <p style={{ color: "#4ade80", margin: 0, fontSize: 12, fontFamily: "monospace" }}>ID: {ordineSalvato.ordine_id}</p>
          <p style={{ color: "#15803d", margin: "8px 0 0", fontSize: 13 }}>L'amministratore lo troverà su <strong>listino-prezzi-merci</strong>.</p>
        </div>
        {prods.length > 0 && (
          <>
            <p style={{ fontWeight: 700, color: "#374151", marginBottom: 8 }}>Prodotti ordinati ({prods.length})</p>
            {prods.map((p, i) => (
              <div key={i} style={{ display: "flex", justifyContent: "space-between", padding: "6px 12px", background: "#f8fafc", borderRadius: 8, marginBottom: 4, fontSize: 13 }}>
                <span style={{ textTransform: "capitalize" }}>{p.nome}</span>
                <strong>{p.quantita} {p.unita}</strong>
              </div>
            ))}
          </>
        )}
        {rics.length > 0 && (
          <>
            <p style={{ fontWeight: 700, color: "#7c3aed", margin: "12px 0 8px" }}>Ricette da produrre ({rics.length})</p>
            {rics.map((r, i) => (
              <div key={i} style={{ display: "flex", justifyContent: "space-between", padding: "6px 12px", background: "#f5f3ff", borderRadius: 8, marginBottom: 4, fontSize: 13 }}>
                <span style={{ textTransform: "capitalize" }}>{r.nome}</span>
                <strong style={{ color: "#7c3aed" }}>{r.quantita} lotti</strong>
              </div>
            ))}
          </>
        )}
        <div style={{ display: "flex", gap: 10, marginTop: 16 }}>
          <button data-testid="vedi-storico-btn" onClick={() => { setOrdineSalvato(null); setVista("storico"); }} style={{ flex: 1, padding: "12px", borderRadius: 12, border: "2px solid #e2e8f0", background: "#f8fafc", fontWeight: 600, fontSize: 14, cursor: "pointer" }}>
            <IconHistory /> Storico
          </button>
          <button data-testid="nuovo-ordine-btn" onClick={() => { setOrdineSalvato(null); setSelProdotti({}); setQtProdotti({}); setSelRicette({}); setLottiRicette({}); setNoteOperatore(""); }} style={{ flex: 2, padding: "12px", borderRadius: 12, border: "none", background: "linear-gradient(135deg, #1e40af, #3b82f6)", color: "#fff", fontWeight: 700, fontSize: 14, cursor: "pointer" }}>
            Nuovo ordine
          </button>
        </div>
      </div>
    );
  }

  // ── Vista principale ──────────────────────────────────────────────────────
  return (
    <div style={{ maxWidth: 900, margin: "0 auto" }}>

      {/* Header */}
      <div style={{ background: "linear-gradient(135deg, #1e40af, #3b82f6)", borderRadius: 16, padding: "18px 20px 14px", marginBottom: 14, color: "#fff" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: 12 }}>
          <div>
            <h2 style={{ margin: 0, fontSize: 19, fontWeight: 800 }}>Ordini Fornitori</h2>
            <p style={{ margin: "3px 0 0", fontSize: 12, color: "rgba(255,255,255,0.8)" }}>
              {loading ? "Caricamento..." : `${prodotti.length} prodotti · ${prodotti.filter(p => p.sotto_scorta).length} sotto scorta`}
            </p>
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            <button data-testid="btn-storico" onClick={() => setVista(vista === "storico" ? "nuovo" : "storico")}
              style={{ padding: "8px 14px", borderRadius: 10, border: "2px solid rgba(255,255,255,0.4)", background: vista === "storico" ? "rgba(255,255,255,0.3)" : "rgba(255,255,255,0.1)", color: "#fff", fontWeight: 700, fontSize: 12, cursor: "pointer", display: "flex", alignItems: "center", gap: 5 }}>
              <IconHistory /> Storico
            </button>
            {vista === "nuovo" && (
              <button data-testid="invia-ordine-btn" onClick={handleInvia} disabled={inviando || nTotSel === 0}
                style={{ padding: "8px 14px", borderRadius: 10, border: "2px solid rgba(255,255,255,0.4)", background: nTotSel > 0 ? "rgba(255,255,255,0.2)" : "rgba(255,255,255,0.1)", color: "#fff", fontWeight: 700, fontSize: 12, cursor: nTotSel > 0 ? "pointer" : "not-allowed", opacity: nTotSel > 0 ? 1 : 0.5, display: "flex", alignItems: "center", gap: 5 }}>
                <IconSend /> {inviando ? "Invio..." : `Invia${nTotSel > 0 ? ` (${nTotSel})` : ""}`}
              </button>
            )}
          </div>
        </div>
        {vista === "nuovo" && (
          <div style={{ display: "flex", gap: 6, marginTop: 12, flexWrap: "wrap" }}>
            {REPARTI.map(r => (
              <button key={r.id} onClick={() => setReparto(r.id)}
                style={{ padding: "3px 10px", borderRadius: 20, border: "2px solid", borderColor: reparto === r.id ? "#fff" : "rgba(255,255,255,0.3)", background: reparto === r.id ? "#fff" : "transparent", color: reparto === r.id ? "#1e40af" : "#fff", fontSize: 11, fontWeight: 700, cursor: "pointer" }}>
                {r.label}
              </button>
            ))}
          </div>
        )}
      </div>

      {/* Storico */}
      {vista === "storico" && <StoricoOrdini />}

      {/* Nuovo ordine */}
      {vista === "nuovo" && (
        loading ? (
          <div style={{ textAlign: "center", padding: 60, color: "#94a3b8" }}>Caricamento prodotti...</div>
        ) : (
          <>
            {/* Barra ricerca + filtro fornitore */}
            <div style={{ display: "flex", gap: 10, marginBottom: 12, flexWrap: "wrap" }}>
              <input data-testid="search-prodotti" type="text" placeholder="Cerca prodotto o ricetta..." value={search} onChange={e => setSearch(e.target.value)}
                style={{ flex: 1, minWidth: 180, padding: "9px 14px", borderRadius: 10, border: "2px solid #e2e8f0", fontSize: 13, outline: "none" }} />
              <select data-testid="filtro-fornitore" value={fornitoreAttivo} onChange={e => setFornitoreAttivo(e.target.value)}
                style={{ padding: "9px 12px", borderRadius: 10, border: "2px solid #e2e8f0", fontSize: 12, outline: "none", background: "#fff" }}>
                {fornitori.map(f => <option key={f} value={f}>{f === "tutti" ? "Tutti i fornitori" : f}</option>)}
              </select>
            </div>

            {/* Toggle sezioni */}
            <div style={{ display: "flex", gap: 8, marginBottom: 12 }}>
              <button onClick={() => setSezioneProdotti(v => !v)}
                style={{ padding: "7px 14px", borderRadius: 10, border: `2px solid ${sezioneProdotti ? "#3b82f6" : "#e2e8f0"}`, background: sezioneProdotti ? "#eff6ff" : "#f8fafc", color: sezioneProdotti ? "#1d4ed8" : "#64748b", fontSize: 12, fontWeight: 700, cursor: "pointer" }}>
                📦 Prodotti {nProdSel > 0 ? `(${nProdSel} sel.)` : ""}
              </button>
              <button onClick={() => setSezioneRicette(v => !v)}
                style={{ padding: "7px 14px", borderRadius: 10, border: `2px solid ${sezioneRicette ? "#7c3aed" : "#e2e8f0"}`, background: sezioneRicette ? "#f5f3ff" : "#f8fafc", color: sezioneRicette ? "#7c3aed" : "#64748b", fontSize: 12, fontWeight: 700, cursor: "pointer" }}>
                🍽️ Ricette da produrre {nRicSel > 0 ? `(${nRicSel} sel.)` : ""}
              </button>
            </div>

            {/* ── SEZIONE PRODOTTI ───────────────────────────────────────────── */}
            {sezioneProdotti && (
              <>
                {sottoScorta.length > 0 && (
                  <div style={{ marginBottom: 16 }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8, padding: "7px 12px", background: "#fee2e2", borderRadius: 10, border: "1.5px solid #fca5a5" }}>
                      <span style={{ color: "#dc2626" }}><IconAlert /></span>
                      <span style={{ fontSize: 12, fontWeight: 800, color: "#991b1b" }}>Sotto scorta — {sottoScorta.length} prodotti</span>
                      <button data-testid="seleziona-tutti-scorta" onClick={() => {
                        const ps = { ...selProdotti }; const qs = { ...qtProdotti };
                        sottoScorta.forEach(p => { ps[p.id] = true; if (!qs[p.id]) qs[p.id] = p.peso_confezione > 0 ? p.peso_confezione : 1; });
                        setSelProdotti(ps); setQtProdotti(qs);
                      }} style={{ marginLeft: "auto", padding: "2px 8px", borderRadius: 6, border: "1.5px solid #fca5a5", background: "#fff", color: "#dc2626", fontSize: 10, fontWeight: 700, cursor: "pointer" }}>
                        Seleziona tutti
                      </button>
                    </div>
                    <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                      {sottoScorta.map(p => (
                        <CardProdottoOrdine key={p.id} prodotto={p} selezionato={!!selProdotti[p.id]} quantita={qtProdotti[p.id] || (p.peso_confezione > 0 ? p.peso_confezione : 1)} onToggle={handleToggleProd} onQuantita={(id, v) => setQtProdotti(q => ({ ...q, [id]: v }))} />
                      ))}
                    </div>
                  </div>
                )}
                {nonSottoScorta.length > 0 && (
                  <div style={{ marginBottom: 16 }}>
                    <p style={{ fontSize: 11, fontWeight: 700, color: "#64748b", textTransform: "uppercase", letterSpacing: "0.5px", marginBottom: 8 }}>
                      {fornitoreAttivo === "tutti" ? `Tutti i prodotti — ${nonSottoScorta.length}` : `${fornitoreAttivo} — ${nonSottoScorta.length}`}
                    </p>
                    <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                      {nonSottoScorta.map(p => (
                        <CardProdottoOrdine key={p.id} prodotto={p} selezionato={!!selProdotti[p.id]} quantita={qtProdotti[p.id] || (p.peso_confezione > 0 ? p.peso_confezione : 1)} onToggle={handleToggleProd} onQuantita={(id, v) => setQtProdotti(q => ({ ...q, [id]: v }))} />
                      ))}
                    </div>
                  </div>
                )}
              </>
            )}

            {/* ── SEZIONE RICETTE ────────────────────────────────────────────── */}
            {sezioneRicette && (
              <div style={{ marginBottom: 16 }}>
                <p style={{ fontSize: 11, fontWeight: 700, color: "#7c3aed", textTransform: "uppercase", letterSpacing: "0.5px", marginBottom: 8 }}>
                  Ricette da produrre — {ricetteFiltrate.length}
                </p>
                <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                  {ricetteFiltrate.map(r => (
                    <CardRicettaOrdine key={r.id} ricetta={r} selezionata={!!selRicette[r.id]} lotti={lottiRicette[r.id] || 1} onToggle={handleToggleRic} onLotti={(id, v) => setLottiRicette(l => ({ ...l, [id]: v }))} />
                  ))}
                </div>
              </div>
            )}

            {/* Note operatore */}
            {nTotSel > 0 && (
              <div style={{ marginTop: 8, marginBottom: 8 }}>
                <label style={{ fontSize: 12, fontWeight: 600, color: "#374151", display: "block", marginBottom: 5 }}>
                  Note per l'amministratore (opzionale):
                </label>
                <textarea data-testid="note-operatore" value={noteOperatore} onChange={e => setNoteOperatore(e.target.value)} placeholder="Es. Urgente, consegna entro venerdì..." rows={2}
                  style={{ width: "100%", padding: "9px 12px", borderRadius: 10, border: "2px solid #e2e8f0", fontSize: 13, outline: "none", resize: "vertical", boxSizing: "border-box" }} />
              </div>
            )}

            {/* Pulsante sticky in basso */}
            {nTotSel > 0 && (
              <div style={{ position: "sticky", bottom: 0, paddingTop: 10, paddingBottom: 14, background: "linear-gradient(to top, #f8fafc 70%, transparent)" }}>
                {costoStimato > 0 && (
                  <div style={{ display: "flex", justifyContent: "flex-end", alignItems: "center", gap: 6, marginBottom: 8, padding: "6px 12px", background: "#f0fdf4", border: "1.5px solid #86efac", borderRadius: 10 }}>
                    <span style={{ fontSize: 12, color: "#16a34a", fontWeight: 600 }}>Costo stimato ordine:</span>
                    <span data-testid="costo-stimato-totale" style={{ fontSize: 16, fontWeight: 800, color: "#15803d" }}>€ {costoStimato.toFixed(2)}</span>
                    <span style={{ fontSize: 10, color: "#4ade80" }}>(prezzo acquisto × quantità)</span>
                  </div>
                )}
                <button data-testid="invia-ordine-bottom-btn" onClick={handleInvia} disabled={inviando}
                  style={{ width: "100%", padding: "15px", borderRadius: 14, border: "none", background: "linear-gradient(135deg, #1e40af, #3b82f6)", color: "#fff", fontWeight: 800, fontSize: 15, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", gap: 8, boxShadow: "0 4px 20px rgba(59,130,246,0.4)" }}>
                  <IconSend />
                  {inviando ? "Invio in corso..." : `Invia ordine — ${nProdSel} prodott${nProdSel === 1 ? "o" : "i"}${nRicSel > 0 ? ` + ${nRicSel} ricett${nRicSel === 1 ? "a" : "e"}` : ""}`}
                </button>
              </div>
            )}
          </>
        )
      )}
    </div>
  );
}
