/**
 * ImportaFattureView + ImportDropdown
 * Estratto da App.js
 */
import { useState, useEffect, useRef } from "react";
import axios from "axios";
import { toast } from "sonner";
import {
  FileUp, Upload, RefreshCw, CheckCircle, FileText,
  FolderUp, ChevronDown, Mail, Trash2
} from "lucide-react";
import Button from "../ui/Button";
import { API } from "../../utils/constants";

// ── Componenti UI locali ───────────────────────────────────────────────────────
const Card = ({ children, className = "" }) => (
  <div className={`bg-white rounded-xl shadow-sm border border-gray-100 ${className}`}>{children}</div>
);

// ── ImportaFatture ─────────────────────────────────────────────────────────────
export const ImportaFatture = ({ onImportComplete }) => {
  const [files, setFiles]       = useState([]);
  const [uploading, setUploading] = useState(false);
  const [risultato, setRisultato] = useState(null);
  const [fatture, setFatture]   = useState([]);

  const fetchFatture = async () => {
    try {
      const res = await axios.get(`${API}/fatture`);
      setFatture(res.data || []);
    } catch (e) {
      console.error("Errore fatture:", e);
      setFatture([]);
    }
  };

  useEffect(() => { fetchFatture(); }, []);

  const handleFileChange = (e) => {
    if (e.target.files) setFiles(Array.from(e.target.files));
  };

  const handleUpload = async () => {
    if (files.length === 0) { toast.error("Seleziona almeno un file XML"); return; }
    setUploading(true);
    setRisultato(null);
    const formData = new FormData();
    files.forEach(f => formData.append("files", f));
    try {
      const res = await axios.post(`${API}/fatture/importa-xml`, formData, {
        headers: { "Content-Type": "multipart/form-data" }
      });
      setRisultato(res.data);
      toast.success(`Importate ${res.data.fatture_processate || 0} fatture!`);
      setFiles([]);
      const fi = document.getElementById("xml-upload");
      if (fi) fi.value = "";
      await fetchFatture();
      if (onImportComplete) onImportComplete();
    } catch (e) {
      toast.error("Errore nell'importazione: " + (e.response?.data?.detail || e.message));
    } finally {
      setUploading(false);
    }
  };

  const handleAggiorna = async () => {
    setUploading(true);
    setRisultato(null);
    try {
      const res = await axios.post(`${API}/aggiorna-materie-da-fatture`);
      toast.success(res.data.message);
      setRisultato({ aggiornamenti: res.data.aggiornamenti, dettagli: res.data.dettagli });
      if (onImportComplete) onImportComplete();
    } catch { toast.error("Errore nell'aggiornamento"); }
    finally { setUploading(false); }
  };

  const handlePuliziaDati = async () => {
    if (!window.confirm("Eliminerà righe spazzatura da Materie Prime, Dizionario e Lotti. Continuare?")) return;
    setUploading(true);
    try {
      const res = await axios.post(`${API}/pulizia-dati-spazzatura`);
      toast.success(`Pulizia completata: ${res.data.totale} righe eliminate`);
      fetchFatture();
      if (onImportComplete) onImportComplete();
    } catch (e) {
      toast.error("Errore pulizia: " + (e.response?.data?.detail || e.message));
    } finally { setUploading(false); }
  };

  const handleDeleteFattura = async (id) => {
    if (!window.confirm("Eliminare questa fattura?")) return;
    try {
      await axios.delete(`${API}/fatture/${id}`);
      toast.success("Eliminata!");
      fetchFatture();
    } catch { toast.error("Errore"); }
  };

  return (
    <div className="space-y-6">
      <Card className="p-6">
        <h3 className="text-lg font-semibold mb-4 flex items-center gap-2">
          <FileUp className="text-blue-600" size={24} /> Importa Fatture XML
        </h3>
        <p className="text-sm text-gray-500 mb-4">
          Carica i file XML delle fatture elettroniche. Il sistema aggiornerà automaticamente i dati di tracciabilità.
        </p>
        <div className="border-2 border-dashed border-gray-300 rounded-lg p-6 text-center hover:border-blue-400 transition-colors">
          <input type="file" accept=".xml" multiple onChange={handleFileChange} className="hidden" id="xml-upload" />
          <label htmlFor="xml-upload" className="cursor-pointer">
            <Upload className="mx-auto mb-3 text-gray-400" size={40} />
            <p className="text-gray-600 font-medium">Clicca per selezionare file XML</p>
            <p className="text-sm text-gray-400">oppure trascina qui i file</p>
          </label>
        </div>
        {files.length > 0 && (
          <div className="mt-4">
            <p className="text-sm font-medium text-gray-700 mb-2">{files.length} file selezionati:</p>
            <div className="flex flex-wrap gap-2">
              {files.map((f, i) => (
                <span key={i} className="px-3 py-1 bg-blue-100 text-blue-700 rounded-full text-sm">{f.name}</span>
              ))}
            </div>
          </div>
        )}
        <div className="flex gap-3 mt-4 flex-wrap">
          <Button onClick={handleUpload} disabled={uploading || files.length === 0}>
            {uploading ? <RefreshCw className="animate-spin" size={18} /> : <Upload size={18} />}
            {uploading ? "Importazione..." : "Importa Fatture"}
          </Button>
          <Button onClick={handleAggiorna} variant="secondary" disabled={uploading}>
            <RefreshCw size={18} /> Aggiorna Materie (ultimi 10 giorni)
          </Button>
          <Button onClick={handlePuliziaDati} variant="outline" disabled={uploading}
            className="border-red-200 text-red-600 hover:bg-red-50">
            <Trash2 size={18} /> Pulizia Dati Spazzatura
          </Button>
        </div>
      </Card>

      {risultato !== null && (
        <Card className="p-6 bg-green-50 border-green-200">
          <h4 className="font-semibold text-green-800 mb-3 flex items-center gap-2">
            <CheckCircle size={20} /> Risultato Importazione
          </h4>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-4">
            {[
              { val: risultato.fatture_processate || 0,                              label: "Fatture processate",  col: "text-green-600"  },
              { val: risultato.prodotti_trovati || 0,                                label: "Prodotti trovati",    col: "text-blue-600"   },
              { val: risultato.materie_aggiornate || risultato.aggiornamenti || 0,   label: "Materie aggiornate",  col: "text-purple-600" },
              { val: risultato.errori?.length || 0,                                  label: "Errori",              col: "text-orange-600" },
            ].map(({ val, label, col }) => (
              <div key={label} className="text-center p-3 bg-white rounded-lg">
                <p className={`text-2xl font-bold ${col}`}>{val}</p>
                <p className="text-xs text-gray-500">{label}</p>
              </div>
            ))}
          </div>
          {risultato.dettagli?.length > 0 && (
            <div className="mb-3">
              <p className="text-sm font-medium text-green-700 mb-2">Dettagli aggiornamenti:</p>
              <div className="max-h-40 overflow-y-auto space-y-1">
                {risultato.dettagli.map((d, i) => (
                  <div key={i} className="text-xs bg-white p-2 rounded">
                    <span className="font-medium">{d.ingrediente}</span>
                    <span className="text-gray-500"> → {d.nuovo_fornitore} ({d.nuova_fattura})</span>
                  </div>
                ))}
              </div>
            </div>
          )}
          {risultato.errori?.length > 0 && (
            <div className="mt-3">
              <p className="text-sm font-medium text-red-700 mb-2">Errori:</p>
              {risultato.errori.map((err, i) => <p key={i} className="text-xs text-red-600">{err}</p>)}
            </div>
          )}
        </Card>
      )}

      <Card>
        <div className="p-4 border-b">
          <h4 className="font-semibold flex items-center gap-2">
            <FileText size={20} /> Fatture Importate ({Array.isArray(fatture) ? fatture.length : 0})
          </h4>
        </div>
        <div className="divide-y max-h-96 overflow-y-auto">
          {!Array.isArray(fatture) || fatture.length === 0 ? (
            <div className="p-8 text-center text-gray-500">
              <FolderUp size={48} className="mx-auto mb-3 opacity-30" />
              <p>Nessuna fattura importata</p>
            </div>
          ) : (
            fatture.map((f, idx) => (
              <div key={f.id || idx} className="p-4 hover:bg-gray-50 flex items-center justify-between">
                <div>
                  <p className="font-medium">{f.fornitore || "N/A"}</p>
                  <p className="text-sm text-gray-500">
                    Fatt. {f.numero_fattura || "N/A"} — {f.data_fattura || "N/A"} — {Array.isArray(f.prodotti) ? f.prodotti.length : 0} prodotti
                  </p>
                </div>
                <div className="flex items-center gap-2">
                  <button
                    onClick={() => { const id = f.id || f.numero_fattura; if (id) window.open(`${API}/fatture/${id}/visualizza`, "_blank"); }}
                    className="px-2.5 py-1.5 text-blue-600 bg-blue-50 hover:bg-blue-100 rounded-lg text-xs flex items-center gap-1.5 border border-blue-200"
                    data-testid={`visualizza-fattura-${f.id}`}
                  >
                    <FileText size={13} /> {f.xml_raw ? "Assosoftware" : "Visualizza"}
                  </button>
                  <button onClick={() => handleDeleteFattura(f.id)} className="p-2 text-red-500 hover:bg-red-50 rounded-lg">
                    <Trash2 size={18} />
                  </button>
                </div>
              </div>
            ))
          )}
        </div>
      </Card>
    </div>
  );
};

// ── ImportDropdown ─────────────────────────────────────────────────────────────
export const ImportDropdown = ({ activeTab, onTabChange }) => {
  const [open, setOpen]       = useState(false);
  const [dropPos, setDropPos] = useState({ top: 0, left: 0 });
  const btnRef  = useRef(null);
  const menuRef = useRef(null);
  const isActive = activeTab === "pec_import" || activeTab === "fatture";

  useEffect(() => {
    const handler = (e) => {
      if (btnRef.current?.contains(e.target) || menuRef.current?.contains(e.target)) return;
      setOpen(false);
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const handleToggle = () => {
    if (!open && btnRef.current) {
      const rect = btnRef.current.getBoundingClientRect();
      setDropPos({ top: rect.bottom + 4, left: rect.left });
    }
    setOpen(v => !v);
  };

  return (
    <>
      <button ref={btnRef} onClick={handleToggle}
        className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg font-medium transition-all whitespace-nowrap text-xs ${
          isActive ? "bg-blue-600 text-white shadow-md" : "bg-white text-gray-600 hover:bg-gray-100 border"
        }`}
        data-testid="import-dropdown-btn"
      >
        <FileUp size={14} />
        Importa
        <ChevronDown size={12} className={`transition-transform duration-150 ${open ? "rotate-180" : ""}`} />
      </button>

      {open && (
        <div ref={menuRef}
          style={{ position: "fixed", top: dropPos.top, left: dropPos.left, zIndex: 9999 }}
          className="w-44 bg-white border border-gray-200 rounded-xl shadow-xl overflow-hidden"
        >
          {[
            { id: "pec_import", icon: <Mail size={14} className="text-blue-500" />,   label: "Import PEC",    testid: "nav-pec-import",    hoverCls: "hover:bg-blue-50",   activeCls: "bg-blue-50 text-blue-700"   },
            { id: "fatture",    icon: <FileUp size={14} className="text-indigo-500" />, label: "Fatture XML",  testid: "nav-fatture-xml",   hoverCls: "hover:bg-indigo-50", activeCls: "bg-indigo-50 text-indigo-700" },
          ].map((item, i) => (
            <div key={item.id}>
              {i > 0 && <div className="border-t border-gray-100" />}
              <button
                onClick={() => { onTabChange(item.id); setOpen(false); }}
                className={`w-full flex items-center gap-2.5 px-3 py-2.5 text-xs font-medium transition-colors ${item.hoverCls} ${activeTab === item.id ? item.activeCls : "text-gray-700"}`}
                data-testid={item.testid}
              >
                {item.icon} {item.label}
              </button>
            </div>
          ))}
        </div>
      )}
    </>
  );
};

export default ImportaFatture;
