/**
 * SchedaProdottoView — Vista unificata a due colonne per la gestione ricette.
 * Colonna sinistra: lista ricette con ricerca e filtri.
 * Colonna destra: pannello con 4 tab per la ricetta selezionata:
 *   1. Ingredienti  — form aggiunta/modifica ingredienti con food cost
 *   2. Prezzi & Margini — costo/pezzo, prezzo vendita, badge margine + calcolatore
 *   3. Lotti & Recall — storico lotti + recall ingrediente
 *   4. Allergeni & Nutri — 14 allergeni + dichiarazione nutrizionale
 *
 * URL: #ricette (subpath gestito internamente via state)
 */
import { useState, useEffect, useMemo, useRef } from "react";
import axios from "axios";
import { toast } from "sonner";
import {
  ChefHat, Search, DollarSign, X, Edit, Save, Plus, RefreshCw,
  ChevronRight, ChevronDown, AlertTriangle, Calculator, Layers,
  Package, Download, Upload, FileSpreadsheet, Printer, Check, Copy, Trash2,
  ShieldCheck,
} from "lucide-react";
import { API } from "../../utils/constants";
import TabIngredienti from "./scheda/TabIngredienti";
import TabPrezziMargini from "./scheda/TabPrezziMargini";
import TabCalcolatore from "./scheda/TabCalcolatore";
import TabLotti from "./scheda/TabLotti";
import TabAllergeni from "./scheda/TabAllergeni";
import TabNutrizionali from "./scheda/TabNutrizionali";
import RigaRicettaLista from "./scheda/RigaRicettaLista";

// ─── Pannello Export/Import Ricette (CSV template) ──────────────────────────
export const ExportImportPanel = ({ onRicetteUpdate }) => {
  const [aperto, setAperto] = useState(false);
  const [file, setFile] = useState(null);
  const [anteprima, setAnt] = useState(null);
  const [loading, setLoading] = useState(false);
  const [importing, setImp] = useState(false);
  const fileRef = useRef(null);

  const scaricaTemplate = () => window.open(`${API}/ricette/export/template-csv`, "_blank");
  const scaricaCSV = () => window.open(`${API}/ricette/export/csv`, "_blank");

  const onFileChange = async (e) => {
    const f = e.target.files?.[0];
    if (!f) return;
    setFile(f);
    setAnt(null);
    setLoading(true);
    try {
      const buf = await f.arrayBuffer();
      const res = await axios.post(
        `${API}/ricette/import/csv?anteprima=true`,
        buf,
        { headers: { "Content-Type": "application/octet-stream" } }
      );
      setAnt(res.data);
    } catch (e) {
      toast.error("Errore lettura file: " + (e?.response?.data?.detail || e.message));
    }
    setLoading(false);
  };

  const importa = async () => {
    if (!file) return;
    setImp(true);
    try {
      const buf = await file.arrayBuffer();
      const res = await axios.post(
        `${API}/ricette/import/csv?anteprima=false`,
        buf,
        { headers: { "Content-Type": "application/octet-stream" } }
      );
      const d = res.data;
      toast.success(`Importate: ${d.create} nuove · ${d.aggiornate} aggiornate`);
      if (d.errori?.length > 0) toast.warning(`${d.totale_errori} errori: ${d.errori.slice(0,2).join(", ")}`);
      setFile(null); setAnt(null);
      if (fileRef.current) fileRef.current.value = "";
      onRicetteUpdate && onRicetteUpdate();
    } catch (e) {
      toast.error("Errore importazione: " + (e?.response?.data?.detail || e.message));
    }
    setImp(false);
  };

  return (
    <div className="border border-gray-200 rounded-xl mb-3 overflow-hidden">
      <button
        onClick={() => setAperto(v => !v)}
        className="w-full flex items-center gap-2 px-3 py-2.5 bg-green-50 hover:bg-green-100 border border-green-200 rounded-lg transition-colors text-sm"
        data-testid="toggle-export-import"
      >
        <FileSpreadsheet size={15} className="text-green-600" />
        <span className="font-semibold text-green-800 flex-1 text-left">Import / Export Ricette (CSV)</span>
        {aperto
          ? <ChevronDown size={14} className="text-green-500" />
          : <span className="flex items-center gap-1 text-[10px] text-green-600 font-medium"><Upload size={10}/> Apri<ChevronRight size={14} className="text-green-500" /></span>
        }
      </button>

      {aperto && (
        <div className="p-3 border-t bg-white space-y-3">
          <div className="flex gap-2 flex-wrap">
            <button onClick={scaricaTemplate} data-testid="btn-scarica-template"
              className="flex items-center gap-1.5 px-3 py-2 bg-green-600 text-white rounded-lg text-xs font-semibold hover:bg-green-700 transition-colors">
              <Download size={12} /> Scarica Template Compilabile
            </button>
            <button onClick={scaricaCSV}
              className="flex items-center gap-1.5 px-3 py-2 border border-gray-200 text-gray-600 rounded-lg text-xs hover:bg-gray-50 transition-colors">
              <Download size={12} /> Export CSV Semplice
            </button>
          </div>

          <p className="text-[10px] text-gray-500 leading-relaxed">
            Il template contiene le ricette esistenti pronte da modificare. Imposta AZIONE su{" "}
            <code className="bg-gray-100 px-1 rounded">NUOVA</code> per aggiungere,{" "}
            <code className="bg-gray-100 px-1 rounded">AGGIORNA</code> per modificare,{" "}
            <code className="bg-gray-100 px-1 rounded">ELIMINA</code> per rimuovere.
          </p>

          {/* Upload */}
          <div className="border-t border-gray-100 pt-3 space-y-2">
            <label className="block">
              <span className="text-xs font-semibold text-gray-600">Carica file CSV compilato</span>
              <input ref={fileRef} type="file" accept=".csv,.xlsx,.xls" onChange={onFileChange}
                className="mt-1 block w-full text-xs text-gray-500 file:mr-3 file:py-1.5 file:px-3 file:rounded-lg file:border-0 file:text-xs file:font-medium file:bg-green-50 file:text-green-700 hover:file:bg-green-100" />
            </label>

            {loading && <div className="flex items-center gap-2 text-xs text-gray-400"><RefreshCw size={12} className="animate-spin" /> Analisi file...</div>}

            {anteprima && (
              <div className="bg-gray-50 rounded-lg p-3 text-xs space-y-1 border border-gray-200">
                <p className="font-semibold text-gray-700">Anteprima importazione:</p>
                <p>Nuove ricette: <strong className="text-green-600">{anteprima.nuove}</strong></p>
                <p>Aggiornamenti: <strong className="text-blue-600">{anteprima.aggiornate}</strong></p>
                <p>Eliminazioni: <strong className="text-red-600">{anteprima.da_eliminare}</strong></p>
                {anteprima.errori?.length > 0 && <p className="text-red-500">Errori: {anteprima.errori.slice(0,2).join(", ")}</p>}
              </div>
            )}

            {file && !loading && (
              <div className="flex gap-2">
                <button onClick={() => { setFile(null); setAnt(null); if (fileRef.current) fileRef.current.value = ""; }}
                  className="flex-1 py-1.5 border border-gray-200 text-gray-600 rounded-lg text-xs hover:bg-gray-50">
                  <X size={12} className="inline mr-1" /> Annulla
                </button>
                <button onClick={importa} disabled={importing}
                  className="flex-1 py-1.5 bg-green-600 text-white rounded-lg text-xs font-semibold hover:bg-green-700 disabled:opacity-50 flex items-center justify-center gap-1">
                  {importing ? <RefreshCw size={12} className="animate-spin" /> : <Upload size={12} />}
                  Importa
                </button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

// ─── Costanti ─────────────────────────────────────────────────────────────────
const TABS_SCHEDA = [
  { id: "ingredienti", label: "Ingredienti",     icon: Package },
  { id: "prezzi",      label: "Prezzi & Calc",   icon: DollarSign },
  { id: "lotti",       label: "Lotti & Recall",  icon: Layers },
  { id: "allergeni",   label: "Allergeni & Nutri", icon: AlertTriangle },
  { id: "nutrizionali", label: "Nutrizionali",   icon: ShieldCheck },
];

const ALFABETO = ['A','B','C','D','E','F','G','H','I','L','M','N','O','P','Q','R','S','T','U','V','Z'];

// ─── Componente principale ────────────────────────────────────────────────────
export const SchedaProdottoView = ({
  ricette = [],
  onDeleteRicetta,
  onAddRicetta,
  onUpdateRicetta,
  onClonaRicetta,
  searchRicette,
  setSearchRicette,
  onNavigateToLotti,
  onRicetteUpdate
}) => {
  const [ricettaSelezionata, setRicettaSelezionata] = useState(null);
  const [tabAttiva, setTabAttiva] = useState("ingredienti");
  const [letteraFiltro, setLetteraFiltro] = useState(null);
  const [filtroReparto, setFiltroReparto] = useState("tutti");
  const [showNuovaModal, setShowNuovaModal] = useState(false);
  const [nuovaForm, setNuovaForm] = useState({ nome: "", porzioni: 1 });
  const [salvandoNuova, setSalvandoNuova] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [editForm, setEditForm] = useState({ nome: "", porzioni: 1, note: "", reparto: "" });
  const [salvandoEdit, setSalvandoEdit] = useState(false);

  const handleCreaRicetta = async () => {
    if (!nuovaForm.nome.trim()) { toast.error("Inserisci il nome della ricetta"); return; }
    setSalvandoNuova(true);
    try {
      await onAddRicetta({ nome: nuovaForm.nome.trim(), porzioni: nuovaForm.porzioni, ingredienti: [], ingredienti_dettaglio: [] });
      setShowNuovaModal(false);
      setNuovaForm({ nome: "", porzioni: 1 });
      onRicetteUpdate && onRicetteUpdate();
    } catch { toast.error("Errore creazione ricetta"); }
    finally { setSalvandoNuova(false); }
  };

  const handleSalvaEdit = async () => {
    if (!editForm.nome.trim()) { toast.error("Il nome è obbligatorio"); return; }
    setSalvandoEdit(true);
    try {
      await (onUpdateRicetta && onUpdateRicetta(ricettaSelezionata.id, {
        ...ricettaSelezionata,
        nome: editForm.nome.trim(),
        porzioni: editForm.porzioni,
        note: editForm.note,
        reparto: editForm.reparto
      }));
      setRicettaSelezionata(prev => ({ ...prev, nome: editForm.nome.trim(), porzioni: editForm.porzioni, note: editForm.note, reparto: editForm.reparto }));
      setShowEditModal(false);
      toast.success("Ricetta aggiornata!");
      onRicetteUpdate && onRicetteUpdate();
    } catch (e) {
      const det = e?.response?.data?.detail;
      const msg = Array.isArray(det) ? det.map(d => d.msg).join(", ") : (typeof det === "string" ? det : e?.message || "sconosciuto");
      toast.error("Errore salvataggio: " + msg);
    }
    finally { setSalvandoEdit(false); }
  };

  const handleEliminaRicetta = (r) => {
    toast(`Eliminare "${r.nome}" definitivamente?`, {
      description: "L'operazione non può essere annullata.",
      action: {
        label: "Elimina",
        onClick: async () => {
          try {
            await onDeleteRicetta && onDeleteRicetta(r.id);
            setRicettaSelezionata(null);
            onRicetteUpdate && onRicetteUpdate();
            toast.success("Ricetta eliminata");
          } catch { toast.error("Errore eliminazione"); }
        }
      },
      cancel: { label: "Annulla", onClick: () => {} },
      duration: 8000,
    });
  };

  const handleStampaScheda = (r) => {
    const ingredienti = r.ingredienti_dettaglio?.length > 0
      ? r.ingredienti_dettaglio
      : (r.ingredienti || []).map(i => ({ nome: i, quantita: "", unita_misura: "" }));
    const righe = ingredienti.map(i =>
      `<tr><td style="text-transform:capitalize">${i.nome || i}</td><td>${i.quantita || "—"}</td><td>${i.unita_misura || ""}</td></tr>`
    ).join("");
    const html = `<!DOCTYPE html><html><head><meta charset="utf-8">
<title>Scheda Ricetta — ${r.nome}</title>
<style>
  @media print { @page { margin: 15mm; } }
  body { font-family: Arial, sans-serif; margin: 0; padding: 24px; color: #1a1a2e; }
  .header { border-bottom: 3px solid #f97316; padding-bottom: 12px; margin-bottom: 20px; }
  h1 { margin: 0; font-size: 24px; text-transform: capitalize; }
  .meta { font-size: 11px; color: #666; margin-top: 4px; }
  table { width: 100%; border-collapse: collapse; margin: 10px 0; }
  th { background: #f97316; color: white; padding: 7px 12px; text-align: left; font-size: 12px; }
  td { padding: 6px 12px; border-bottom: 1px solid #eee; font-size: 12px; }
  tr:nth-child(even) td { background: #fafafa; }
  .note { background: #fff7ed; border-left: 4px solid #f97316; padding: 10px 14px; font-size: 12px; margin-top: 14px; border-radius: 4px; }
  .footer { margin-top: 20px; font-size: 10px; color: #aaa; text-align: center; border-top: 1px solid #eee; padding-top: 8px; }
</style></head><body>
<div class="header">
  <h1>${r.nome}</h1>
  <div class="meta">${r.reparto ? `Reparto: <strong>${r.reparto}</strong> · ` : ""}Porzioni base: <strong>${r.porzioni || 1}</strong> · Ingredienti: <strong>${ingredienti.length}</strong></div>
</div>
<table><thead><tr><th>Ingrediente</th><th>Quantità</th><th>Unità</th></tr></thead><tbody>${righe}</tbody></table>
${r.note ? `<div class="note"><strong>Note:</strong> ${r.note}</div>` : ""}
<div class="footer">Ceraldi Group · HACCP System · ${new Date().toLocaleDateString("it-IT")}</div>
<script>window.onload = () => { window.print(); }<\/script>
</body></html>`;
    const win = window.open("", "_blank", "width=800,height=900");
    win.document.write(html);
    win.document.close();
  };

  // Leggi subpath dall'URL hash
  useEffect(() => {
    const hash = window.location.hash.replace("#", "");
    const parts = hash.split("/");
    if (parts[1] && TABS_SCHEDA.find(t => t.id === parts[1])) {
      setTabAttiva(parts[1]);
    }
  }, []);

  const handleTabChange = (tabId) => {
    setTabAttiva(tabId);
    const baseHash = window.location.hash.replace("#", "").split("/")[0] || "ricette";
    window.history.replaceState(null, "", `#${baseHash}/${tabId}`);
  };

  const ricetteFiltrate = useMemo(() => {
    let r = ricette;
    if (letteraFiltro) r = r.filter(x => x.nome.toUpperCase().startsWith(letteraFiltro));
    if (searchRicette) r = r.filter(x => x.nome.toLowerCase().includes(searchRicette.toLowerCase()));
    if (filtroReparto !== "tutti") r = r.filter(x => x.reparto === filtroReparto);
    return [...r].sort((a, b) => a.nome.localeCompare(b.nome, "it", { sensitivity: "base" }));
  }, [ricette, letteraFiltro, searchRicette, filtroReparto]);

  const { basi, varMap } = useMemo(() => {
    const basi = ricetteFiltrate.filter(r => !r.ricetta_base_id);
    const varMap = {};
    ricetteFiltrate.filter(r => r.ricetta_base_id).forEach(v => {
      (varMap[v.ricetta_base_id] = varMap[v.ricetta_base_id] || []).push(v);
    });
    return { basi, varMap };
  }, [ricetteFiltrate]);

  return (
    <div className="flex h-[calc(100vh-200px)] gap-4 overflow-hidden">
      {/* Modal Modifica Ricetta */}
      {showEditModal && ricettaSelezionata && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md">
            <div className="px-6 py-4 bg-blue-600 text-white rounded-t-2xl flex items-center justify-between">
              <h3 className="font-bold text-lg">Modifica Ricetta</h3>
              <button onClick={() => setShowEditModal(false)} className="hover:bg-white/20 p-1 rounded-lg"><X size={18} /></button>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="text-xs font-semibold text-gray-600 block mb-1.5">Nome Ricetta *</label>
                <input autoFocus type="text" value={editForm.nome}
                  onChange={e => setEditForm(f => ({ ...f, nome: e.target.value }))}
                  className="w-full px-3 py-2.5 border border-gray-200 rounded-xl text-sm focus:ring-2 focus:ring-blue-400 focus:outline-none" />
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-xs font-semibold text-gray-600 block mb-1.5">Pezzi/ricetta</label>
                  <input type="number" min="1" value={editForm.porzioni}
                    onChange={e => setEditForm(f => ({ ...f, porzioni: parseInt(e.target.value) || 1 }))}
                    className="w-full px-3 py-2.5 border border-gray-200 rounded-xl text-sm" />
                </div>
                <div>
                  <label className="text-xs font-semibold text-gray-600 block mb-1.5">Reparto</label>
                  <select value={editForm.reparto} onChange={e => setEditForm(f => ({ ...f, reparto: e.target.value }))}
                    className="w-full px-3 py-2.5 border border-gray-200 rounded-xl text-sm bg-white">
                    <option value="">— nessuno —</option>
                    <option value="pasticceria">Pasticceria</option>
                    <option value="rosticceria">Rosticceria</option>
                    <option value="bar">Bar</option>
                  </select>
                </div>
              </div>
              <div>
                <label className="text-xs font-semibold text-gray-600 block mb-1.5">Note</label>
                <textarea value={editForm.note} onChange={e => setEditForm(f => ({ ...f, note: e.target.value }))}
                  rows={2} className="w-full px-3 py-2 border border-gray-200 rounded-xl text-sm resize-none"
                  placeholder="Descrizione, note di produzione..." />
              </div>
              <div className="flex gap-3 pt-2">
                <button onClick={() => setShowEditModal(false)} className="flex-1 py-2.5 border border-gray-200 rounded-xl text-sm text-gray-600 hover:bg-gray-50">Annulla</button>
                <button onClick={handleSalvaEdit} disabled={salvandoEdit}
                  className="flex-1 py-2.5 bg-blue-600 text-white rounded-xl text-sm font-semibold hover:bg-blue-700 disabled:opacity-50 flex items-center justify-center gap-2">
                  {salvandoEdit ? <RefreshCw size={16} className="animate-spin" /> : <Save size={16} />}
                  Salva Modifiche
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Modal Nuova Ricetta */}
      {showNuovaModal && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md">
            <div className="px-6 py-4 bg-orange-600 text-white rounded-t-2xl flex items-center justify-between">
              <h3 className="font-bold text-lg">Nuova Ricetta</h3>
              <button onClick={() => setShowNuovaModal(false)} className="hover:bg-white/20 p-1 rounded-lg"><X size={18} /></button>
            </div>
            <div className="p-6 space-y-4">
              <div>
                <label className="text-xs font-semibold text-gray-600 block mb-1.5">Nome Ricetta *</label>
                <input autoFocus type="text" value={nuovaForm.nome}
                  onChange={e => setNuovaForm(f => ({ ...f, nome: e.target.value }))}
                  onKeyDown={e => e.key === "Enter" && handleCreaRicetta()}
                  placeholder="es. Sfogliatella Riccia"
                  className="w-full px-3 py-2.5 border border-gray-200 rounded-xl text-sm focus:ring-2 focus:ring-orange-400 focus:outline-none" />
              </div>
              <div>
                <label className="text-xs font-semibold text-gray-600 block mb-1.5">Pezzi prodotti per ricetta base</label>
                <input type="number" min="1" value={nuovaForm.porzioni}
                  onChange={e => setNuovaForm(f => ({ ...f, porzioni: parseInt(e.target.value) || 1 }))}
                  className="w-full px-3 py-2.5 border border-gray-200 rounded-xl text-sm" />
                <p className="text-xs text-gray-400 mt-1">Puoi aggiungere gli ingredienti dopo la creazione</p>
              </div>
              <div className="flex gap-3 pt-2">
                <button onClick={() => setShowNuovaModal(false)} className="flex-1 py-2.5 border border-gray-200 rounded-xl text-sm text-gray-600 hover:bg-gray-50">Annulla</button>
                <button onClick={handleCreaRicetta} disabled={salvandoNuova}
                  className="flex-1 py-2.5 bg-orange-600 text-white rounded-xl text-sm font-semibold hover:bg-orange-700 disabled:opacity-50 flex items-center justify-center gap-2">
                  {salvandoNuova ? <RefreshCw size={16} className="animate-spin" /> : <Check size={16} />}
                  Crea Ricetta
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ── Colonna sinistra: Lista ricette ──────────────────────────────── */}
      <div className={`flex flex-col ${ricettaSelezionata ? "hidden lg:flex lg:w-72" : "w-full lg:w-80"} flex-shrink-0`}>
        <div className="relative mb-2">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
          <input type="text" placeholder="Cerca ricetta..." value={searchRicette}
            onChange={e => { setSearchRicette(e.target.value); setLetteraFiltro(null); }}
            className="w-full pl-9 pr-4 py-2.5 border border-gray-200 rounded-xl text-sm focus:ring-2 focus:ring-orange-400 focus:outline-none bg-white" />
        </div>

        <div className="flex gap-1 mb-2">
          {[["tutti","Tutti"],["pasticceria","Pasticc."],["rosticceria","Rostic."]].map(([v,l]) => (
            <button key={v} onClick={() => setFiltroReparto(v)}
              className={`flex-1 py-1.5 rounded-lg text-xs font-semibold transition-colors ${filtroReparto === v ? "bg-orange-600 text-white" : "bg-white border border-gray-200 text-gray-500 hover:bg-orange-50"}`}>
              {l}
            </button>
          ))}
          <button onClick={() => setShowNuovaModal(true)}
            className="px-3 py-1.5 bg-green-600 text-white rounded-lg text-xs font-semibold hover:bg-green-700 flex items-center gap-1">
            <Plus size={14} /> Nuova
          </button>
        </div>

        <div className="flex flex-wrap gap-0.5 mb-2 p-1.5 bg-white rounded-xl border border-gray-100">
          <button onClick={() => setLetteraFiltro(null)}
            className={`px-1.5 py-0.5 text-xs rounded transition-colors ${!letteraFiltro ? "bg-orange-500 text-white" : "text-gray-500 hover:bg-gray-100"}`}>
            Tutti
          </button>
          {ALFABETO.map(l => {
            const c = ricette.filter(r => r.nome.toUpperCase().startsWith(l)).length;
            return (
              <button key={l} disabled={c === 0} onClick={() => setLetteraFiltro(l === letteraFiltro ? null : l)}
                className={`w-6 h-6 text-[10px] rounded transition-colors ${l === letteraFiltro ? "bg-orange-500 text-white" : c > 0 ? "bg-gray-50 text-gray-600 hover:bg-orange-100" : "text-gray-200 cursor-not-allowed"}`}>
                {l}
              </button>
            );
          })}
        </div>

        <p className="text-xs text-gray-400 mb-2 px-1">{ricetteFiltrate.length} ricette</p>
        <ExportImportPanel onRicetteUpdate={onRicetteUpdate} />

        <div className="flex-1 overflow-y-auto space-y-0.5 pr-1">
          {basi.map(r => (
            <RigaRicettaLista
              key={r.id}
              r={r}
              varianti={varMap[r.id] || []}
              isSelected={ricettaSelezionata?.id === r.id}
              selectedVarianteId={ricettaSelezionata?.id}
              onSelect={setRicettaSelezionata}
              onClona={onClonaRicetta}
              onDelete={onDeleteRicetta}
            />
          ))}
          {ricetteFiltrate.filter(r => r.ricetta_base_id && !ricette.find(b => b.id === r.ricetta_base_id)).map(r => (
            <div key={r.id} onClick={() => setRicettaSelezionata(r)}
              className={`flex items-center gap-2 px-3 py-2.5 rounded-xl cursor-pointer transition-all border border-gray-100 ${ricettaSelezionata?.id === r.id ? "bg-orange-100 border-orange-300" : "hover:bg-orange-50"}`}>
              <span className="text-[9px] bg-amber-400 text-white px-1 py-0.5 rounded font-bold">VAR</span>
              <p className="text-sm text-gray-700 capitalize truncate flex-1">{r.nome}</p>
            </div>
          ))}
          {ricetteFiltrate.length === 0 && (
            <div className="text-center py-12 text-gray-400">
              <ChefHat size={32} className="mx-auto mb-2 opacity-30" />
              <p className="text-sm">Nessuna ricetta trovata</p>
            </div>
          )}
        </div>
      </div>

      {/* ── Pannello destro: Scheda Prodotto ─────────────────────────────── */}
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        {!ricettaSelezionata ? (
          <div className="flex-1 flex items-center justify-center">
            <div className="text-center text-gray-400">
              <ChefHat size={64} className="mx-auto mb-4 opacity-20" />
              <p className="text-lg font-medium text-gray-500">Seleziona una ricetta</p>
              <p className="text-sm mt-1">per visualizzare la scheda prodotto completa</p>
              <p className="text-xs mt-3 text-gray-300">{ricette.length} ricette disponibili</p>
            </div>
          </div>
        ) : (
          <>
            {/* Header scheda */}
            <div className="flex items-center gap-3 mb-4 flex-shrink-0">
              <button onClick={() => setRicettaSelezionata(null)}
                className="lg:hidden p-2 bg-white border border-gray-200 rounded-xl text-gray-500 hover:text-gray-700 flex-shrink-0">
                <ChevronRight size={16} className="rotate-180" />
              </button>
              {ricettaSelezionata.foto_url ? (
                <img src={ricettaSelezionata.foto_url} alt={ricettaSelezionata.nome}
                  className="w-12 h-12 rounded-xl object-cover border border-gray-100 flex-shrink-0" />
              ) : (
                <div className="w-12 h-12 rounded-xl bg-orange-100 flex items-center justify-center flex-shrink-0">
                  <ChefHat size={22} className="text-orange-500" />
                </div>
              )}
              <div className="flex-1 min-w-0">
                <h2 className="text-lg font-bold text-gray-800 capitalize truncate">{ricettaSelezionata.nome}</h2>
                <div className="flex items-center gap-2 text-xs text-gray-400 flex-wrap">
                  {ricettaSelezionata.reparto && <span className={`px-1.5 py-0.5 rounded font-medium ${ricettaSelezionata.reparto === "pasticceria" ? "bg-amber-100 text-amber-700" : "bg-blue-100 text-blue-700"}`}>{ricettaSelezionata.reparto}</span>}
                  {ricettaSelezionata.approvata === false && (
                    <span className="px-2 py-0.5 rounded-full bg-orange-100 text-orange-700 font-bold text-[10px] animate-pulse">🆕 NUOVA</span>
                  )}
                  <span>{(ricettaSelezionata.ingredienti_dettaglio?.length || ricettaSelezionata.ingredienti?.length || 0)} ingredienti</span>
                  {ricettaSelezionata.porzioni > 1 && <span>· {ricettaSelezionata.porzioni} pz/ricetta</span>}
                  {ricettaSelezionata.ricetta_base_nome && <span className="text-amber-600">← variante di {ricettaSelezionata.ricetta_base_nome}</span>}
                </div>
              </div>
              <div className="flex items-center gap-1 flex-shrink-0">
                {ricettaSelezionata.approvata === false && (
                  <button
                    data-testid="btn-approva-ricetta"
                    onClick={async () => {
                      try {
                        await axios.patch(`${API}/ricette/${ricettaSelezionata.id}/approva`);
                        setRicettaSelezionata(prev => ({ ...prev, approvata: true }));
                        onRicetteUpdate && onRicetteUpdate();
                        toast.success("Ricetta approvata ✓");
                      } catch { toast.error("Errore approvazione"); }
                    }}
                    className="px-2 py-1 bg-green-600 text-white rounded-lg text-xs font-bold hover:bg-green-700 flex items-center gap-1"
                    title="Approva ricetta (admin)">
                    <ShieldCheck size={13} /> Approva
                  </button>
                )}
                <button onClick={() => { setEditForm({ nome: ricettaSelezionata.nome || "", porzioni: ricettaSelezionata.porzioni || 1, note: ricettaSelezionata.note || "", reparto: ricettaSelezionata.reparto || "" }); setShowEditModal(true); }}
                  className="p-2 text-blue-400 hover:bg-blue-50 rounded-xl" title="Modifica ricetta"><Edit size={16} /></button>
                <button onClick={() => onClonaRicetta && onClonaRicetta(ricettaSelezionata)}
                  className="p-2 text-green-400 hover:bg-green-50 rounded-xl" title="Clona"><Copy size={16} /></button>
                <button onClick={() => handleStampaScheda(ricettaSelezionata)}
                  data-testid="btn-stampa-scheda"
                  className="p-2 text-orange-400 hover:bg-orange-50 rounded-xl" title="Stampa scheda ricetta">
                  <Printer size={16} />
                </button>
                <button onClick={() => handleEliminaRicetta(ricettaSelezionata)}
                  className="p-2 text-red-300 hover:bg-red-50 hover:text-red-500 rounded-xl" title="Elimina ricetta"><Trash2 size={16} /></button>
              </div>
            </div>

            {/* Tab switcher */}
            <div className="flex gap-0 border-b border-gray-200 mb-4 flex-shrink-0 overflow-x-auto" style={{scrollbarWidth:"none"}}>
              {TABS_SCHEDA.map(t => (
                <button key={t.id} onClick={() => handleTabChange(t.id)}
                  className={`flex items-center gap-1.5 px-4 py-2.5 text-sm font-semibold whitespace-nowrap border-b-2 -mb-px transition-all ${
                    tabAttiva === t.id ? "border-orange-500 text-orange-600" : "border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-200"
                  }`}>
                  <t.icon size={14} />
                  {t.label}
                </button>
              ))}
            </div>

            {/* Contenuto tab */}
            <div className="flex-1 overflow-y-auto pr-1">
              {tabAttiva === "ingredienti" && (
                <TabIngredienti ricetta={ricettaSelezionata} onUpdated={() => {}} />
              )}
              {tabAttiva === "prezzi" && (
                <>
                  <TabPrezziMargini ricetta={ricettaSelezionata} allRicette={ricette} onUpdated={() => {}} />
                  <div className="mt-4 border-t border-gray-100 pt-4">
                    <p className="text-xs font-bold text-gray-400 uppercase tracking-wide mb-3 flex items-center gap-1.5">
                      <Calculator size={13} /> Calcolatore Produzione
                    </p>
                    <TabCalcolatore ricetta={ricettaSelezionata} />
                  </div>
                </>
              )}
              {tabAttiva === "lotti" && (
                <TabLotti ricetta={ricettaSelezionata} onNavigateToLotti={onNavigateToLotti} />
              )}
              {tabAttiva === "allergeni" && (
                <TabAllergeni ricetta={ricettaSelezionata} onUpdated={() => {}} />
              )}
              {tabAttiva === "nutrizionali" && (
                <TabNutrizionali ricettaId={ricettaSelezionata.id} />
              )}
            </div>
          </>
        )}
      </div>
    </div>
  );
};

