/**
 * SparklinePrezzo.jsx — Grafico sparkline SVG storico ultimi 6 prezzi per ingrediente
 */
import { useState, useEffect } from "react";
import axios from "axios";
import { TrendingUp, TrendingDown, Minus, RefreshCw } from "lucide-react";
import { API } from "../../../utils/constants";

const SparklinePrezzo = ({ nomeIngrediente, prezzoCorrente }) => {
  const [storico, setStorico] = useState([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (!nomeIngrediente) return;
    setLoading(true);
    axios.get(`${API}/food-cost/storico-prezzi`, { params: { nome: nomeIngrediente, limit: 6 } })
      .then(r => setStorico(r.data.storico || []))
      .catch(() => setStorico([]))
      .finally(() => setLoading(false));
  }, [nomeIngrediente]);

  if (loading) return <div className="flex items-center gap-1 text-xs text-gray-300"><RefreshCw size={10} className="animate-spin" /> caricamento storico...</div>;
  if (storico.length < 2) return null;

  // SVG sparkline
  const W = 120, H = 36, PAD = 4;
  const prezzi = storico.map(s => s.prezzo);
  const minP = Math.min(...prezzi);
  const maxP = Math.max(...prezzi);
  const rangeP = maxP - minP || 1;
  const pts = prezzi.map((p, i) => {
    const x = PAD + (i / (prezzi.length - 1)) * (W - PAD * 2);
    const y = PAD + (1 - (p - minP) / rangeP) * (H - PAD * 2);
    return `${x.toFixed(1)},${y.toFixed(1)}`;
  });
  const polyline = pts.join(" ");

  const primo = prezzi[0];
  const ultimo = prezzi[prezzi.length - 1];
  const delta = ((ultimo - primo) / primo * 100);
  const trend = delta > 0.5 ? "up" : delta < -0.5 ? "down" : "flat";
  const color = trend === "up" ? "#ef4444" : trend === "down" ? "#16a34a" : "#9ca3af";
  const TrendIcon = trend === "up" ? TrendingUp : trend === "down" ? TrendingDown : Minus;

  return (
    <div className="mt-3 border border-gray-100 rounded-xl p-3 bg-gray-50">
      <div className="flex items-center justify-between mb-1.5">
        <span className="text-[10px] font-semibold text-gray-400 uppercase tracking-wide">Storico prezzi</span>
        <div className="flex items-center gap-1.5">
          <TrendIcon size={11} style={{ color }} />
          <span className="text-[10px] font-bold" style={{ color }}>
            {trend === "flat" ? "stabile" : `${Math.abs(delta).toFixed(1)}%`}
          </span>
        </div>
      </div>

      <div className="flex items-end gap-3">
        <svg width={W} height={H} viewBox={`0 0 ${W} ${H}`}>
          {/* Area fill */}
          <defs>
            <linearGradient id={`grad-${nomeIngrediente?.slice(0,8)}`} x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor={color} stopOpacity="0.2" />
              <stop offset="100%" stopColor={color} stopOpacity="0" />
            </linearGradient>
          </defs>
          <polyline
            fill="none"
            stroke={color}
            strokeWidth="1.5"
            strokeLinecap="round"
            strokeLinejoin="round"
            points={polyline}
          />
          {/* Punti */}
          {pts.map((pt, i) => {
            const [cx, cy] = pt.split(",");
            return <circle key={i} cx={cx} cy={cy} r="2" fill={color} />;
          })}
        </svg>

        <div className="flex-1 space-y-0.5">
          {storico.slice(-4).map((s, i) => (
            <div key={i} className="flex items-center justify-between text-[10px] text-gray-500">
              <span className="text-gray-400">{new Date(s.data).toLocaleDateString("it-IT", { day: "2-digit", month: "short" })}</span>
              <span className="font-mono font-semibold text-gray-700">€{s.prezzo.toFixed(4)}/kg</span>
            </div>
          ))}
        </div>
      </div>

      <div className="flex items-center justify-between mt-1.5 text-[10px] text-gray-400">
        <span>Min: <strong>€{minP.toFixed(4)}</strong></span>
        <span>{storico.length} rilevazioni</span>
        <span>Max: <strong>€{maxP.toFixed(4)}</strong></span>
      </div>
    </div>
  );
};

export default SparklinePrezzo;
