/**
 * TabPrezziMargini.jsx — Tab Prezzi & Margini di SchedaProdottoView
 */
import { useState, useEffect, useCallback } from "react";
import axios from "axios";
import { toast } from "sonner";
import { RefreshCw } from "lucide-react";
import { API } from "../../../utils/constants";
import { BadgeMargine, InlinePrezzoEdit } from "./utils";
import SparklinePrezzo from "./SparklinePrezzo";

const TabPrezziMargini = ({ ricetta, onUpdated }) => {
  const [loading, setLoading] = useState(false);
  const [data, setData] = useState(null);

  const carica = useCallback(async () => {
    setLoading(true);
    try {
      const r = await axios.get(`${API}/ricette-prezzi`);
      const trovata = r.data.find(x => x.id === ricetta?.id);
      setData(trovata || null);
    } catch { toast.error("Errore caricamento prezzi"); }
    finally { setLoading(false); }
  }, [ricetta?.id]);

  useEffect(() => { carica(); }, [carica]);

  if (loading) return <div className="flex items-center justify-center py-16 text-gray-400"><RefreshCw className="animate-spin mr-2" size={18} /> Calcolo...</div>;
  if (!data) return <div className="text-center py-12 text-gray-400 text-sm">Nessun dato prezzi disponibile</div>;

  const margineEuro = data.prezzo_vendita > 0 && data.costo_pezzo > 0 ? data.prezzo_vendita - data.costo_pezzo : null;

  return (
    <div className="space-y-4">
      <div className="grid grid-cols-2 gap-3">
        <div className="bg-gray-50 border border-gray-200 rounded-xl p-4">
          <p className="text-xs text-gray-500 mb-1">Costo/pezzo</p>
          <p className="text-2xl font-bold text-gray-800 font-mono">
            {data.costo_pezzo > 0 ? `€${data.costo_pezzo.toFixed(3)}` : <span className="text-gray-300 text-base">—</span>}
          </p>
          <p className="text-xs text-gray-400 mt-1">Ricetta × {data.porzioni || 1} pezzi</p>
        </div>
        <div className="bg-blue-50 border border-blue-200 rounded-xl p-4">
          <p className="text-xs text-gray-500 mb-1">Prezzo vendita</p>
          <div className="text-2xl font-bold text-blue-800 font-mono">
            <InlinePrezzoEdit id={data.id} prezzo={data.prezzo_vendita || 0} onSaved={carica} />
          </div>
          <p className="text-xs text-gray-400 mt-1">Clicca per modificare</p>
        </div>
      </div>

      <div className={`rounded-xl p-4 border ${data.margine_pct > 0 ? (data.margine_pct >= 50 ? "bg-green-50 border-green-200" : data.margine_pct >= 30 ? "bg-amber-50 border-amber-200" : "bg-red-50 border-red-200") : "bg-gray-50 border-gray-200"}`}>
        <div className="flex items-center justify-between">
          <div>
            <p className="text-xs text-gray-500">Margine</p>
            <p className="text-2xl font-bold mt-1">
              <BadgeMargine pct={data.margine_pct} />
              {margineEuro != null && <span className="ml-2 text-base text-gray-600 font-mono">€{margineEuro.toFixed(2)}/pz</span>}
            </p>
          </div>
          {data.margine_pct > 0 && (
            <div className="w-20 h-20 relative flex-shrink-0">
              <svg viewBox="0 0 36 36" className="w-full h-full -rotate-90">
                <circle cx="18" cy="18" r="15.9" fill="none" stroke="#e5e7eb" strokeWidth="3" />
                <circle cx="18" cy="18" r="15.9" fill="none"
                  stroke={data.margine_pct >= 50 ? "#16a34a" : data.margine_pct >= 30 ? "#d97706" : "#dc2626"}
                  strokeWidth="3" strokeDasharray={`${Math.min(data.margine_pct, 100)} 100`}
                  strokeLinecap="round" />
              </svg>
              <div className="absolute inset-0 flex items-center justify-center">
                <span className="text-xs font-bold text-gray-700">{data.margine_pct?.toFixed(0)}%</span>
              </div>
            </div>
          )}
        </div>
      </div>

      {data.varianti?.length > 0 && (
        <div>
          <p className="text-xs font-semibold text-gray-500 uppercase tracking-wide mb-2">Varianti ({data.varianti.length})</p>
          <div className="space-y-2">
            {data.varianti.map(v => (
              <div key={v.id} className="flex items-center gap-3 px-4 py-2.5 bg-amber-50 border border-amber-200 rounded-xl">
                <span className="text-[10px] bg-amber-400 text-white px-1.5 py-0.5 rounded-full font-bold">VAR</span>
                <span className="flex-1 text-sm font-medium text-gray-800 capitalize truncate">{v.nome}</span>
                {v.ingrediente_variante?.nome && (
                  <span className="text-xs text-amber-700 bg-amber-100 px-2 py-0.5 rounded-full">
                    +{v.ingrediente_variante.quantita}{v.ingrediente_variante.unita} {v.ingrediente_variante.nome}
                  </span>
                )}
                <span className="text-sm font-bold font-mono text-gray-700">€{v.costo_pezzo.toFixed(3)}</span>
                <InlinePrezzoEdit id={v.id} prezzo={v.prezzo_vendita || 0} onSaved={carica} />
                <BadgeMargine pct={v.margine_pct} />
              </div>
            ))}
          </div>
        </div>
      )}

      <p className="text-xs text-gray-400 bg-gray-50 rounded-lg px-3 py-2">
        Il costo/pezzo si calcola automaticamente dal food cost degli ingredienti diviso per il numero di pezzi prodotti dalla ricetta.
        Clicca sul prezzo vendita per modificarlo inline.
      </p>

      {/* Sparkline storico prezzi per ingrediente principale */}
      {ricetta?.nome && (
        <SparklinePrezzo
          nomeIngrediente={ricetta.nome}
          prezzoCorrente={data?.costo_pezzo}
        />
      )}
    </div>
  );
};

export default TabPrezziMargini;
