import { useState, useCallback, useEffect } from "react";
import axios from "axios";
import { toast } from "sonner";
import { Search, Scale, ChefHat, X } from "lucide-react";
import { API } from "../../../utils/constants";

export function TabLibroRicette() {
  const [ricetteLibro, setRicetteLibro] = useState([]);
  const [searchLibro, setSearchLibro] = useState("");
  const [selectedLibro, setSelectedLibro] = useState(null);
  const [loading, setLoading] = useState(false);

  const loadRicette = useCallback(async (search = "") => {
    setLoading(true);
    try {
      const res = await axios.get(`${API}/ricette-libro`, { params: search ? { search } : {} });
      setRicetteLibro(res.data || []);
    } catch {
      toast.error("Errore caricamento libro ricette");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { loadRicette(); }, [loadRicette]);

  return (
    <div className="space-y-4">
      <div className="relative max-w-md">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
        <input
          type="text"
          placeholder="Cerca nel libro ricette..."
          value={searchLibro}
          onChange={(e) => { setSearchLibro(e.target.value); loadRicette(e.target.value); }}
          className="w-full pl-9 pr-4 py-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-orange-400"
        />
      </div>

      {loading ? (
        <div className="text-center py-16 text-gray-400">Caricamento ricette...</div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
          {ricetteLibro.map((r) => (
            <div
              key={r.id}
              onClick={() => setSelectedLibro(r)}
              className="bg-white border border-gray-100 rounded-xl p-4 cursor-pointer hover:border-orange-300 hover:shadow-md transition-all"
              data-testid={`ricetta-libro-${r.id}`}
            >
              <div className="flex items-start justify-between mb-2">
                <h3 className="font-semibold text-gray-800 text-base leading-snug">{r.nome}</h3>
                <span className={`text-xs px-2 py-0.5 rounded-full ml-2 flex-shrink-0 ${
                  r.difficolta === "Facile" ? "bg-green-50 text-green-700" :
                  r.difficolta === "Media" ? "bg-yellow-50 text-yellow-700" :
                  "bg-red-50 text-red-700"
                }`}>{r.difficolta}</span>
              </div>
              {r.descrizione && (
                <p className="text-sm text-gray-500 line-clamp-2 mb-3">{r.descrizione}</p>
              )}
              <div className="flex items-center gap-3 text-xs text-gray-400">
                {r.n_ingredienti > 0 && (
                  <span className="flex items-center gap-1"><Scale size={11} />{r.n_ingredienti} ingredienti</span>
                )}
                <span className="bg-orange-50 text-orange-600 px-2 py-0.5 rounded-full font-medium">
                  {r.categoria || "Pasticceria"}
                </span>
              </div>
            </div>
          ))}
        </div>
      )}

      {selectedLibro && (
        <div
          className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4"
          onClick={() => setSelectedLibro(null)}
        >
          <div
            className="bg-white rounded-2xl max-w-2xl w-full max-h-[90vh] overflow-y-auto shadow-2xl"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="p-6">
              <div className="flex items-start justify-between mb-5 pb-4 border-b">
                <div>
                  <h2 className="text-2xl font-bold text-gray-800">{selectedLibro.nome}</h2>
                  <div className="flex items-center gap-2 mt-1">
                    <span className={`text-sm px-3 py-1 rounded-full font-medium ${
                      selectedLibro.difficolta === "Facile" ? "bg-green-50 text-green-700" :
                      selectedLibro.difficolta === "Media" ? "bg-yellow-50 text-yellow-700" :
                      "bg-red-50 text-red-700"
                    }`}>{selectedLibro.difficolta}</span>
                    {selectedLibro.n_ingredienti > 0 && (
                      <span className="text-sm text-gray-400">{selectedLibro.n_ingredienti} ingredienti</span>
                    )}
                  </div>
                </div>
                <button
                  onClick={() => setSelectedLibro(null)}
                  className="text-gray-400 hover:text-gray-600 p-1 rounded-lg hover:bg-gray-100"
                >
                  <X size={22} />
                </button>
              </div>
              {selectedLibro.ingredienti_testo && (
                <div className="mb-5">
                  <h3 className="font-bold text-gray-700 mb-3 flex items-center gap-2">
                    <Scale size={16} className="text-orange-500" /> Ingredienti
                  </h3>
                  <div className="bg-orange-50 rounded-xl p-4 text-sm text-gray-700 whitespace-pre-line font-mono leading-relaxed border border-orange-100">
                    {selectedLibro.ingredienti_testo}
                  </div>
                </div>
              )}
              {selectedLibro.procedimento && (
                <div>
                  <h3 className="font-bold text-gray-700 mb-3 flex items-center gap-2">
                    <ChefHat size={16} className="text-orange-500" /> Procedimento
                  </h3>
                  <div className="bg-gray-50 rounded-xl p-4 text-sm text-gray-700 leading-relaxed border border-gray-100">
                    {selectedLibro.procedimento}
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
