import { useState, useEffect } from "react";
import "@/App.css";
import { Toaster } from "sonner";
import {
  BookOpen,
  Layers,
  ChefHat,
  AlertTriangle,
  AlertCircle,
  FileText,
  BarChart3,
  X,
  RefreshCw,
  Building2,
  Bug,
  Sparkles,
  Thermometer,
  Snowflake,
  Gift,
  TrendingUp,
  Flame,
  Truck,
  ShieldCheck,
  ShoppingCart,
} from "lucide-react";

import React from "react";
import ErrorBoundary from "./components/ErrorBoundary";
import HACCPPdfButton from "./components/haccp/HACCPPdfButton";
import { HACCPDropdown } from "./components/haccp/HACCPDropdown";
import { ImportDropdown, ImportaFatture } from "./components/haccp/ImportaFattureView";
import { SupervisoreBadge } from "./components/haccp/SupervisoreBadge";

// Hook personalizzati
import { useStats } from "./hooks/useStats";
import { useRicette } from "./hooks/useRicette";
import { useLotti } from "./hooks/useLotti";
import { useFornitori } from "./hooks/useFornitori";

// Componenti vista
import {
  DisinfestazioneView,
  SanificazioneView,
  TemperatureNegativeView,
  TemperaturePositiveView,
  AnomalieView,
  ManualeHACCPView,
  RicetteView,
  PECImportView,
  ProdottiVenditaView,
  ColazioneAcquavivaView,
} from "./components/haccp";
import { SchedaProdottoView } from "./components/haccp/SchedaProdottoView";
import { TabletView } from "./components/haccp/TabletView";
import { StoricoProduzioniView } from "./components/haccp/StoricoProduzioniView";
import { VenditaBancoView } from "./components/haccp/VenditaBancoView";
import ScontiMerceView from "./components/haccp/ScontiMerceView";
import FornitoriList from "./components/haccp/FornitoriList";
import LottiList from "./components/haccp/LottiList";
import MateriePrimeList from "./components/haccp/MateriePrimeList";
import DashboardView from "./components/haccp/DashboardView";
import BackupView from "./components/haccp/BackupView";
import RegistroAllergeniView from "./components/haccp/RegistroAllergeniView";
import ControlloOlioView from "./components/haccp/ControlloOlioView";
import TemperatureCotturaView from "./components/haccp/TemperatureCotturaView";
import RicezioneMerceView from "./components/haccp/RicezioneMerceView";
import SistemaAuditView from "./components/haccp/SistemaAuditView";
import OrdiniFornitoriView from "./components/haccp/OrdiniFornitoriView";

// ── UI primitivo condiviso ──────────────────────────────────
export const Modal = ({ isOpen, onClose, title, children }) => {
  if (!isOpen) return null;
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/50" onClick={onClose} />
      <div className="relative bg-white rounded-2xl shadow-2xl w-full max-w-lg mx-auto">
        <div className="flex items-center justify-between p-3 border-b bg-gray-50 rounded-t-2xl">
          <h2 className="text-lg font-bold text-gray-800">{title}</h2>
          <button onClick={onClose} className="p-1.5 hover:bg-gray-200 rounded-lg">
            <X size={18} />
          </button>
        </div>
        <div className="p-4">{children}</div>
      </div>
    </div>
  );
};

// ── Costanti navigazione ────────────────────────────────────
const TABS = [
  { id: "dashboard",          label: "Dashboard", icon: BarChart3 },
  { id: "fornitori",          label: "Fornitori", icon: Building2 },
  { id: "ricette",            label: "Ricette",   icon: ChefHat },
  { id: "prodotti",           label: "Prodotti",  icon: BookOpen },
  { id: "sconti_merce",       label: "Sconti",    icon: Gift },
  { id: "lotti",              label: "Lotti",     icon: Layers },
  { id: "ordini",             label: "Ordini",    icon: ShoppingCart },
  { id: "storico_produzioni", label: "Storico",   icon: TrendingUp },
  { id: "allergeni",          label: "Allergeni", icon: AlertTriangle },
  { id: "sistema_audit",      label: "Audit",     icon: ShieldCheck },
  { id: "backup",             label: "Backup",    icon: BarChart3 },
];

const TABS_HACCP = [
  { id: "disinfestazione", label: "Disinfestazione", icon: Bug,         color: "text-red-600" },
  { id: "sanificazione",   label: "Sanificazione",   icon: Sparkles,    color: "text-blue-600" },
  { id: "temp_negative",   label: "Temp. Negative",  icon: Snowflake,   color: "text-cyan-600" },
  { id: "temp_positive",   label: "Temp. Positive",  icon: Thermometer, color: "text-orange-600" },
  { id: "anomalie",        label: "Anomalie",        icon: AlertCircle, color: "text-amber-600" },
  { id: "controllo_olio",  label: "Olio Frittura",   icon: Flame,       color: "text-orange-600" },
  { id: "temp_cottura",    label: "Temp. Cottura",   icon: Thermometer, color: "text-red-600" },
  { id: "ricezione_merce", label: "Ricezione Merce", icon: Truck,       color: "text-blue-600" },
  { id: "manuale",         label: "Manuale HACCP",   icon: BookOpen,    color: "text-green-600" },
];

const VALID_TABS = [
  ...TABS.map((t) => t.id),
  ...TABS_HACCP.map((t) => t.id),
  "pec_import", "fatture", "materie", "ricettario", "food_cost", "colazione", "vendita_banco", "ordini",
];

function getInitialTab() {
  const hash = window.location.hash.replace("#", "");
  if (["materie", "ricettario", "food_cost"].includes(hash)) return "ricette";
  return VALID_TABS.includes(hash) ? hash : "dashboard";
}

// ── Router: Tablet vs App ──────────────────────────────────
function AppRouter() {
  const [hash, setHash] = useState(window.location.hash.replace("#", ""));
  useEffect(() => {
    const onHash = () => setHash(window.location.hash.replace("#", ""));
    window.addEventListener("hashchange", onHash);
    return () => window.removeEventListener("hashchange", onHash);
  }, []);

  if (hash.startsWith("tablet/")) {
    const reparto = hash.split("/")[1] || "rosticceria";
    const goHome = () => { window.location.hash = ""; };
    if (reparto === "vendita") return <VenditaBancoView onBack={goHome} />;
    return <TabletView reparto={reparto} onBack={goHome} />;
  }
  return <App />;
}

const ProdottiConTabFornitore = () => <ProdottiVenditaView />;

// ── App principale ─────────────────────────────────────────
function App() {
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState(getInitialTab);
  const [filtroSoloScaduti, setFiltroSoloScaduti] = useState(false);

  const { stats, fetchStats } = useStats();
  const {
    ricette, searchRicette, setSearchRicette, fetchRicette,
    handleAddRicetta, handleUpdateRicetta, handleDeleteRicetta, handleClonaRicetta,
  } = useRicette();
  const {
    lotti, searchLotti, setSearchLotti,
    filtroDataDaLotti, setFiltroDataDaLotti,
    filtroDataALotti, setFiltroDataALotti,
    fetchLotti, handleDeleteLotto, handleGeneraLotto,
  } = useLotti();
  const { fornitori, fetchFornitori, toggleFornitoreEscluso } = useFornitori();

  const handleTabChange = (tabId) => {
    setActiveTab(tabId);
    window.location.hash = tabId;
  };

  // Sync browser back/forward
  useEffect(() => {
    const onHash = () => {
      const hash = window.location.hash.replace("#", "").split("/")[0];
      if (hash && hash !== activeTab) setActiveTab(hash);
    };
    window.addEventListener("hashchange", onHash);
    return () => window.removeEventListener("hashchange", onHash);
  }, [activeTab]);

  // Caricamento iniziale
  useEffect(() => {
    const init = async () => {
      setLoading(true);
      const safety = setTimeout(() => setLoading(false), 10000);
      try {
        await Promise.all([fetchStats(), fetchRicette(), fetchLotti(), fetchFornitori()]);
      } catch (e) {
        console.error("Errore init:", e);
      } finally {
        clearTimeout(safety);
        setLoading(false);
      }
    };
    init();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const refreshAll = () =>
    Promise.all([fetchStats(), fetchRicette(), fetchLotti(), fetchFornitori()]);

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <RefreshCw className="animate-spin mx-auto mb-4 text-blue-600" size={40} />
          <p className="text-gray-600">Caricamento...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <Toaster position="top-right" />

      {/* Header fisso */}
      <header className="bg-white border-b sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-blue-600 rounded-xl">
                <FileText className="text-white" size={24} />
              </div>
              <div>
                <h1 className="text-xl font-bold text-gray-900">Tracciabilità Lotti</h1>
                <p className="text-sm text-gray-500">Sistema di gestione produzione</p>
              </div>
            </div>
            <div className="flex items-center gap-2">
              <HACCPDropdown tabsHACCP={TABS_HACCP} activeTab={activeTab} onTabChange={handleTabChange} />
              <SupervisoreBadge
                onNavigate={(route, alertId) => {
                  if (route?.startsWith("tablet/")) { window.location.hash = route; return; }
                  if (route) handleTabChange(route);
                  // Se l'alert riguarda lotti GIÀ scaduti (A3), filtra solo quelli scaduti
                  // A3b e scadenza_48h sono lotti in scadenza futura: naviga senza filtro
                  if (route === "lotti" && alertId === "A3") {
                    setFiltroSoloScaduti(true);
                  } else {
                    setFiltroSoloScaduti(false);
                  }
                }}
              />
            </div>
          </div>
        </div>
      </header>

      <div className="max-w-7xl mx-auto px-4 py-6">
        {/* Barra navigazione principale */}
        <div
          className="flex gap-0.5 mb-5 overflow-x-auto items-center relative"
          style={{ scrollbarWidth: "none", msOverflowStyle: "none", overflowY: "visible" }}
        >
          {TABS.map((tab) => (
            <button
              key={tab.id}
              onClick={() => handleTabChange(tab.id)}
              className={`flex items-center gap-1 px-2.5 py-1 rounded-md font-medium transition-all whitespace-nowrap text-xs ${
                activeTab === tab.id
                  ? "bg-blue-600 text-white shadow-md"
                  : "bg-white text-gray-600 hover:bg-gray-100 border"
              }`}
            >
              <tab.icon size={12} />
              {tab.label}
            </button>
          ))}
          <ImportDropdown activeTab={activeTab} onTabChange={handleTabChange} />
          <HACCPPdfButton />
          {/* Link al Gestionale Contabile — apre in nuova tab */}
          <a
            href="https://gestionale.ceraldiapp.it"
            target="_blank"
            rel="noopener noreferrer"
            data-testid="nav-gestionale"
            style={{
              marginLeft: 8,
              padding: '4px 12px',
              background: '#1e40af',
              color: '#fff',
              borderRadius: 6,
              fontSize: 12,
              fontWeight: 700,
              textDecoration: 'none',
              whiteSpace: 'nowrap',
              letterSpacing: 0.3,
            }}
          >
            🏦 Vai al Gestionale
          </a>
        </div>

        {/* ── Routing contenuto ── */}
        {activeTab === "dashboard" && (
          <DashboardView stats={stats} onRefresh={refreshAll} onNavigate={setActiveTab} />
        )}
        {activeTab === "pec_import" && (
          <PECImportView onImportComplete={() => Promise.all([fetchStats(), fetchFornitori()])} />
        )}
        {activeTab === "fatture" && (
          <ErrorBoundary>
            <ImportaFatture onImportComplete={() => Promise.all([fetchStats(), fetchFornitori()])} />
          </ErrorBoundary>
        )}
        {activeTab === "fornitori" && (
          <FornitoriList
            fornitori={fornitori}
            onToggleEscluso={toggleFornitoreEscluso}
            onRefresh={fetchFornitori}
          />
        )}
        {activeTab === "materie" && (
          <ErrorBoundary><MateriePrimeList /></ErrorBoundary>
        )}
        {activeTab === "prodotti" && (
          <ErrorBoundary><ProdottiConTabFornitore /></ErrorBoundary>
        )}
        {activeTab === "sconti_merce" && (
          <ErrorBoundary><ScontiMerceView /></ErrorBoundary>
        )}
        {activeTab === "ricette" && (
          <ErrorBoundary>
            <SchedaProdottoView
              ricette={ricette}
              onDeleteRicetta={handleDeleteRicetta}
              onAddRicetta={handleAddRicetta}
              onUpdateRicetta={handleUpdateRicetta}
              onClonaRicetta={handleClonaRicetta}
              searchRicette={searchRicette}
              setSearchRicette={setSearchRicette}
              onNavigateToLotti={() => setActiveTab("lotti")}
              onRicetteUpdate={fetchRicette}
            />
          </ErrorBoundary>
        )}
        {/* Legacy alias */}
        {(activeTab === "ricettario" || activeTab === "food_cost") && (
          <ErrorBoundary>
            <RicetteView onNavigateToLotti={() => setActiveTab("lotti")} />
          </ErrorBoundary>
        )}
        {activeTab === "lotti" && (
          <ErrorBoundary>
            <LottiList
              items={lotti}
              onDelete={handleDeleteLotto}
              onGeneraLotto={handleGeneraLotto}
              ricette={ricette}
              search={searchLotti}
              setSearch={setSearchLotti}
              filtroDataDa={filtroDataDaLotti}
              setFiltroDataDa={setFiltroDataDaLotti}
              filtroDataA={filtroDataALotti}
              setFiltroDataA={setFiltroDataALotti}
              filtroSoloScaduti={filtroSoloScaduti}
              setFiltroSoloScaduti={setFiltroSoloScaduti}
            />
          </ErrorBoundary>
        )}
        {activeTab === "storico_produzioni" && (
          <ErrorBoundary><StoricoProduzioniView /></ErrorBoundary>
        )}
        {activeTab === "colazione" && (
          <ErrorBoundary>
            <div className="relative" style={{ minHeight: "calc(100vh - 120px)" }}>
              <ColazioneAcquavivaView onClose={null} modoTablet={false} />
            </div>
          </ErrorBoundary>
        )}

        {/* Moduli HACCP */}
        {activeTab === "disinfestazione" && <DisinfestazioneView />}
        {activeTab === "sanificazione" && <SanificazioneView />}
        {activeTab === "temp_negative" && <TemperatureNegativeView />}
        {activeTab === "temp_positive" && <TemperaturePositiveView />}
        {activeTab === "anomalie" && <AnomalieView />}
        {activeTab === "manuale" && <ManualeHACCPView />}
        {activeTab === "controllo_olio" && <ControlloOlioView />}
        {activeTab === "temp_cottura" && <TemperatureCotturaView />}
        {activeTab === "ricezione_merce" && <RicezioneMerceView />}
        {activeTab === "backup" && <BackupView onBack={() => setActiveTab("dashboard")} />}
        {activeTab === "allergeni" && <RegistroAllergeniView />}
        {activeTab === "sistema_audit" && <SistemaAuditView />}
        {activeTab === "ordini" && (
          <ErrorBoundary><OrdiniFornitoriView /></ErrorBoundary>
        )}
      </div>
    </div>
  );
}

export default AppRouter;
