const Card = ({ children, className = "" }) => (
  <div className={`bg-white rounded-xl shadow-sm border border-gray-100 ${className}`}>
    {children}
  </div>
);

// ── Lista fatture con filtro anno ────────────────────────────────────────────
const FattureList = ({ fatture }) => {
  const [filtroAnno, setFiltroAnno] = useState("tutti");

  // Estrai l'anno da date in formato italiano (dd/mm/yyyy) o ISO (yyyy-mm-dd)
  const estraiAnno = (data = "") => {
    if (!data) return null;
    if (data.includes("/")) {
      const parts = data.split("/");
      return parts.length === 3 ? parts[2] : null;
    }
    if (data.includes("-")) {
      return data.substring(0, 4);
    }
    return null;
  };

  // Estrai anni unici dalle fatture
  const anni = [...new Set(
    fatture.map(f => estraiAnno(f.data)).filter(Boolean)
  )].sort((a, b) => b - a);

  const filtrate = filtroAnno === "tutti"
    ? fatture
    : fatture.filter(f => estraiAnno(f.data) === filtroAnno);

  return (
    <div>
      <div className="flex items-center justify-between mb-2">
        <p className="text-sm font-medium text-gray-700 flex items-center gap-1.5">
          <FileText size={14} className="text-blue-500" />
          Fatture
          <span className="text-xs text-gray-400 font-normal">({filtrate.length} di {fatture.length})</span>
        </p>
        {/* Filtro anni */}
        <div className="flex gap-1">
          <button onClick={() => setFiltroAnno("tutti")}
            className={`px-2 py-0.5 rounded text-xs font-bold ${filtroAnno === "tutti" ? "bg-blue-100 text-blue-700" : "text-gray-400 hover:text-gray-600"}`}>
            Tutte
          </button>
          {anni.map(a => (
            <button key={a} onClick={() => setFiltroAnno(a)}
              className={`px-2 py-0.5 rounded text-xs font-bold ${filtroAnno === a ? "bg-blue-100 text-blue-700" : "text-gray-400 hover:text-gray-600"}`}>
              {a}
            </button>
          ))}
        </div>
      </div>
      <div className="space-y-1 max-h-64 overflow-y-auto pr-1">
        {filtrate.length === 0 ? (
          <p className="text-xs text-gray-400 text-center py-4">Nessuna fattura per questo anno</p>
        ) : filtrate.map((f, i) => (
          <button
            key={i}
            onClick={() => {
              const id = f.id || f.numero;
              if (!id) return;
              window.open(`${process.env.REACT_APP_BACKEND_URL}/api/fatture/${id}/visualizza`, "_blank", "noopener,noreferrer");
            }}
            className="w-full flex justify-between items-center text-xs text-gray-600 py-1.5 px-2 border-b border-gray-100 hover:bg-blue-50 hover:text-blue-700 transition-colors rounded group cursor-pointer"
            data-testid={`fattura-row-${f.numero}`}
          >
            <span className="font-mono font-medium truncate max-w-[100px]">{f.numero?.substring(0, 20)}</span>
            <span className="text-gray-500 font-medium min-w-[70px] text-right">{f.data}</span>
            <span className="text-gray-400 min-w-[50px] text-right">{f.num_prodotti}prd</span>
            <div className="flex items-center gap-1 ml-1">
              {f.has_xml
                ? <span className="text-[10px] bg-green-100 text-green-700 px-1 py-0.5 rounded-full">XML</span>
                : <span className="text-[10px] bg-gray-100 text-gray-400 px-1 py-0.5 rounded-full" title="Fattura da database (senza XML originale)">Imp.</span>}
              <ExternalLink size={10} className="text-blue-400 opacity-0 group-hover:opacity-100" />
            </div>
          </button>
        ))}
      </div>
    </div>
  );
};

// ── Pannello Qualifica Fornitori Batch ─────────────────────────────────────
const QualificaBatchPanel = () => {
  const [aperto, setAperto]       = useState(false);
  const [lista, setLista]         = useState([]);
  const [loading, setLoading]     = useState(false);
  const [saving, setSaving]       = useState(false);
  const [selezionati, setSelezionati] = useState(new Set());

  const carica = async () => {
    setLoading(true);
    try {
      const res = await axios.get(`${API}/fornitori/qualifica/in-attesa`);
      setLista(res.data || []);
    } catch { toast.error("Errore caricamento fornitori in attesa"); }
    finally { setLoading(false); }
  };

  useEffect(() => { if (aperto && lista.length === 0) carica(); }, [aperto]); // eslint-disable-line react-hooks/exhaustive-deps

  const toggleSel = (piva) =>
    setSelezionati(prev => {
      const n = new Set(prev);
      n.has(piva) ? n.delete(piva) : n.add(piva);
      return n;
    });

  const selezionaTutti = () =>
    setSelezionati(new Set(lista.map(f => f.piva).filter(Boolean)));

  const approva = async (includi) => {
    const pive = Array.from(selezionati);
    if (pive.length === 0) { toast.warning("Seleziona almeno un fornitore"); return; }
    setSaving(true);
    try {
      const res = await axios.post(`${API}/fornitori/qualifica/approva-batch`, { pive, includi });
      toast.success(`${res.data.aggiornati} fornitore/i ${includi ? "qualificati" : "esclusi"}`);
      setLista(prev => prev.filter(f => !selezionati.has(f.piva)));
      setSelezionati(new Set());
    } catch { toast.error("Errore durante l'approvazione"); }
    finally { setSaving(false); }
  };

  const autoQualificaTutti = async () => {
    setSaving(true);
    try {
      const res = await axios.post(`${API}/fornitori/qualifica/auto-qualifica-tutti`);
      toast.success(`Auto-qualifica completata: ${res.data.aggiornati} fornitori qualificati automaticamente`);
      setLista([]);
      setSelezionati(new Set());
    } catch { toast.error("Errore auto-qualifica"); }
    finally { setSaving(false); }
  };

  const count = lista.length;

  return (
    <Card>
      <button
        onClick={() => setAperto(v => !v)}
        className="w-full p-4 flex items-center justify-between hover:bg-gray-50 rounded-xl transition-colors"
        data-testid="toggle-qualifica-batch"
      >
        <div className="flex items-center gap-3">
          <ClipboardList size={20} className={count > 0 ? "text-amber-500" : "text-green-500"} />
          <div className="text-left">
            <div className="flex items-center gap-2">
              <p className="font-semibold text-gray-800">Registro Qualifica Fornitori HACCP</p>
              {count > 0 && (
                <span className="bg-amber-500 text-white text-[10px] font-bold px-2 py-0.5 rounded-full">
                  {count} in attesa
                </span>
              )}
            </div>
            <p className="text-xs text-gray-500 mt-0.5">
              Reg. CE 178/2002 art. 18 · Approvazione rapida dei fornitori
            </p>
          </div>
        </div>
        {aperto ? <ChevronDown size={18} className="text-gray-400" /> : <ChevronRight size={18} className="text-gray-400" />}
      </button>

      {aperto && (
        <div className="border-t">
          {/* Banner normativa */}
          <div className="px-4 py-2 bg-amber-50 border-b border-amber-100 text-xs text-amber-800 flex gap-2">
            <AlertTriangle size={13} className="flex-shrink-0 mt-0.5 text-amber-600" />
            <span>
              <strong>Reg. CE 178/2002 — Art. 18:</strong> Ogni fornitore deve essere formalmente qualificato.
              Usa <strong>Auto-qualifica</strong> per qualificare automaticamente tutti i fornitori con fatture attive.
            </span>
          </div>

          {/* Pulsante Auto-qualifica prominente */}
          {lista.length > 0 && (
            <div className="px-4 py-3 bg-green-50 border-b border-green-100 flex items-center justify-between gap-3">
              <div>
                <p className="text-sm font-semibold text-green-800">{lista.length} fornitori in attesa di qualifica</p>
                <p className="text-xs text-green-600 mt-0.5">I fornitori con fatture attive vengono qualificati automaticamente. Solo i fornitori esclusi manualmente rimangono esclusi.</p>
              </div>
              <button
                onClick={autoQualificaTutti}
                disabled={saving}
                className="flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-lg text-sm font-bold hover:bg-green-700 disabled:opacity-40 whitespace-nowrap"
                data-testid="btn-auto-qualifica-tutti"
              >
                <Zap size={15} /> {saving ? "In corso..." : "Auto-qualifica Automatica"}
              </button>
            </div>
          )}

          {/* Barra azioni manuali */}
          {lista.length > 0 && (
            <div className="px-4 py-2.5 border-b bg-gray-50 flex items-center gap-2 flex-wrap">
              <button onClick={selezionaTutti} className="text-xs text-blue-600 underline">
                Seleziona tutti ({lista.length})
              </button>
              <div className="flex-1" />
              <span className="text-xs text-gray-500">{selezionati.size} selezionati</span>
              <button
                onClick={() => approva(false)}
                disabled={saving || selezionati.size === 0}
                className="flex items-center gap-1.5 px-3 py-1.5 border border-red-200 text-red-600 rounded-lg text-xs font-medium hover:bg-red-50 disabled:opacity-40"
                data-testid="btn-escludi-batch"
              >
                <UserX size={13} /> Escludi
              </button>
              <button
                onClick={() => approva(true)}
                disabled={saving || selezionati.size === 0}
                className="flex items-center gap-1.5 px-3 py-1.5 bg-green-600 text-white rounded-lg text-xs font-semibold hover:bg-green-700 disabled:opacity-40"
                data-testid="btn-qualifica-batch"
              >
                <UserCheck size={13} /> {saving ? "Salvataggio..." : "Qualifica"}
              </button>
              <button
                onClick={async () => { setSelezionati(new Set(lista.map(f=>f.piva).filter(Boolean))); await approva(true); }}
                disabled={saving}
                className="flex items-center gap-1.5 px-3 py-1.5 bg-blue-600 text-white rounded-lg text-xs font-semibold hover:bg-blue-700 disabled:opacity-40"
                data-testid="btn-qualifica-tutti"
              >
                <Zap size={13} /> Qualifica Tutti
              </button>
            </div>
          )}

          {/* Lista fornitori */}
          {loading ? (
            <div className="p-8 text-center text-gray-400">
              <RefreshCw size={22} className="animate-spin mx-auto mb-2" />
              Caricamento...
            </div>
          ) : lista.length === 0 ? (
            <div className="p-8 text-center">
              <CheckCircle2 size={36} className="mx-auto mb-2 text-green-400" />
              <p className="text-sm font-medium text-green-700">Tutti i fornitori sono qualificati</p>
              <p className="text-xs text-gray-400 mt-1">Nessuna azione richiesta</p>
            </div>
          ) : (
            <div className="divide-y max-h-[480px] overflow-y-auto">
              {lista.map(f => (
                <label
                  key={f.piva || f.nome_fornitore}
                  className="flex items-center gap-3 px-4 py-3 hover:bg-gray-50 cursor-pointer"
                  data-testid={`qualifica-row-${f.piva}`}
                >
                  <input
                    type="checkbox"
                    checked={selezionati.has(f.piva)}
                    onChange={() => toggleSel(f.piva)}
                    className="w-4 h-4 rounded border-gray-300 accent-green-600"
                  />
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-semibold text-gray-800 truncate">{f.nome_fornitore}</p>
                    <div className="flex items-center gap-2 mt-0.5 flex-wrap">
                      <span className="text-[10px] text-gray-400 font-mono">{f.piva}</span>
                      <span className="text-[10px] text-gray-300">·</span>
                      <span className="text-[10px] text-gray-500">{f.num_fatture || 0} fatture</span>
                      {f.ultima_consegna && (
                        <>
                          <span className="text-[10px] text-gray-300">·</span>
                          <span className="text-[10px] text-gray-500">Ultima: {f.ultima_consegna}</span>
                        </>
                      )}
                    </div>
                    {f.prodotti_campione?.length > 0 && (
                      <p className="text-[10px] text-gray-400 mt-0.5 truncate">
                        {f.prodotti_campione.slice(0, 3).join(" · ")}
                      </p>
                    )}
                  </div>
                  <div className="text-right flex-shrink-0">
                    {f.totale_acquistato > 0 && (
                      <p className="text-xs font-semibold text-gray-700">€{f.totale_acquistato?.toFixed(0)}</p>
                    )}
                    <span className="text-[9px] text-amber-600 bg-amber-50 px-1.5 py-0.5 rounded-full font-medium">
                      In attesa
                    </span>
                  </div>
                </label>
              ))}
            </div>
          )}
        </div>
      )}
    </Card>
  );
};



// ── Note Operatore per scheda ricevimento ────────────────────────────────────
const NoteRicevimento = ({ idFattura }) => {
  const [nota, setNota]       = useState("");
  const [salvata, setSalvata] = useState("");
  const [saving, setSaving]   = useState(false);
  const [loaded, setLoaded]   = useState(false);

  useEffect(() => {
    axios.get(`${API}/note_ricevimento/${idFattura}`)
      .then(r => { setNota(r.data.nota || ""); setSalvata(r.data.nota || ""); })
      .catch(() => {})
      .finally(() => setLoaded(true));
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [idFattura]);

  const salva = async () => {
    setSaving(true);
    try {
      await axios.post(`${API}/fornitori/schede-ricevimento/${idFattura}/nota?nota=${encodeURIComponent(nota)}`);
      setSalvata(nota);
      toast.success("Nota salvata");
    } catch { toast.error("Errore salvataggio nota"); }
    setSaving(false);
  };

  if (!loaded) return null;

  return (
    <div className="mt-2 pt-2 border-t border-gray-100">
      <p className="text-[10px] text-gray-500 font-medium mb-1 uppercase tracking-wide">Note operatore</p>
      <div className="flex gap-2">
        <textarea
          value={nota}
          onChange={e => setNota(e.target.value)}
          placeholder="Anomalie, non conformità, stato imballaggio..."
          className="flex-1 text-[11px] border border-gray-200 rounded-lg px-2 py-1.5 resize-none h-14 focus:ring-1 focus:ring-blue-300 outline-none"
          data-testid={`nota-ricevimento-${idFattura}`}
        />
        <button
          onClick={salva}
          disabled={saving || nota === salvata}
          className={`px-3 py-1 rounded-lg text-[10px] font-bold transition-all flex-shrink-0 self-end ${
            nota !== salvata && !saving
              ? "bg-blue-600 text-white hover:bg-blue-700"
              : "bg-gray-100 text-gray-400 cursor-not-allowed"
          }`}
        >
          {saving ? "..." : "Salva"}
        </button>
      </div>
      {salvata && <p className="text-[9px] text-green-600 mt-1">Nota salvata: {salvata.slice(0,60)}</p>}
    </div>
  );
};


const BADGE_TIPO = {
  surgelato:   { label: "Surgelato",    bg: "bg-cyan-100",   text: "text-cyan-700",   icon: "❄️" },
  refrigerato: { label: "Refrigerato",  bg: "bg-blue-100",   text: "text-blue-700",   icon: "🧊" },
  ambiente:    { label: "Ambiente",     bg: "bg-gray-100",   text: "text-gray-600",   icon: "📦" },
};

const SchedeRicevimentoPanel = () => {
  const [schede, setSchede]       = useState([]);
  const [loading, setLoading]     = useState(false);
  const [aperta, setAperta]       = useState(false);
  const [espansa, setEspansa]     = useState(null); // id_fattura espanso
  const [raggruppa, setRaggruppa] = useState(true); // raggruppa per fornitore

  const carica = async () => {
    setLoading(true);
    try {
      const res = await axios.get(`${API}/fornitori/schede-ricevimento?limit=100`);
      setSchede(res.data || []);
    } catch {
      toast.error("Errore caricamento schede ricevimento");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (aperta && schede.length === 0) carica();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [aperta]);

  // Raggruppa schede per fornitore (mostra ultima consegna + conteggio)
  const schedeVista = raggruppa
    ? Object.values(
        schede.reduce((acc, s) => {
          const k = s.fornitore;
          if (!acc[k] || s.data_consegna > acc[k].data_consegna) {
            acc[k] = { ...s, num_consegne: (acc[k]?.num_consegne || 0) + 1 };
          } else {
            acc[k].num_consegne = (acc[k].num_consegne || 1) + 1;
          }
          return acc;
        }, {})
      ).sort((a, b) => b.data_consegna?.localeCompare(a.data_consegna))
    : schede;

  const surgelati   = schede.filter(s => s.tipo_conservazione === "surgelato");
  const refrigerati = schede.filter(s => s.tipo_conservazione === "refrigerato");
  const ambiente    = schede.filter(s => s.tipo_conservazione === "ambiente");

  const renderBadgeTemp = (scheda) => {
    const tipo = BADGE_TIPO[scheda.tipo_conservazione] || BADGE_TIPO.ambiente;
    if (scheda.temperatura_rilevata === null) {
      return (
        <span className={`inline-flex items-center gap-1 text-[10px] font-bold px-2 py-0.5 rounded-full ${tipo.bg} ${tipo.text}`}>
          {tipo.icon} N/A
        </span>
      );
    }
    return (
      <span className={`inline-flex items-center gap-1 text-[10px] font-bold px-2 py-0.5 rounded-full ${tipo.bg} ${tipo.text}`}>
        {tipo.icon} {scheda.temperatura_rilevata > 0 ? "+" : ""}{scheda.temperatura_rilevata}°C
      </span>
    );
  };

  return (
    <Card>
      <button
        onClick={() => setAperta(v => !v)}
        className="w-full p-4 flex items-center justify-between hover:bg-gray-50 rounded-xl transition-colors"
        data-testid="toggle-schede-ricevimento"
      >
        <div className="flex items-center gap-3">
          <Thermometer size={20} className="text-blue-600" />
          <div className="text-left">
            <p className="font-semibold text-gray-800">Registro Ricevimento Merci — Temperature</p>
            <p className="text-xs text-gray-500 mt-0.5">
              Reg. CE 852/2004 · Temperature pre-compilate nei range di legge · {schede.length > 0 ? `${schede.length} consegne` : "Clicca per caricare"}
            </p>
          </div>
        </div>
        {aperta ? <ChevronDown size={18} className="text-gray-400" /> : <ChevronRight size={18} className="text-gray-400" />}
      </button>

      {aperta && (
        <div className="border-t">
          {/* Banner normativa + toggle raggruppa */}
          <div className="px-4 py-2.5 bg-blue-50 border-b border-blue-100 flex items-center gap-2 text-xs text-blue-800">
            <CheckCircle2 size={14} className="flex-shrink-0 mt-0.5 text-blue-600" />
            <span className="flex-1">
              <strong>Conforme Reg. CE 852/2004:</strong> Temperature registrate automaticamente. I fornitori esclusi sono esclusi da questa lista.
            </span>
            <button
              onClick={() => setRaggruppa(v => !v)}
              className={`ml-auto flex-shrink-0 px-2.5 py-1 rounded-full text-[10px] font-bold border transition-all ${raggruppa ? 'bg-blue-600 text-white border-blue-700' : 'bg-white text-blue-600 border-blue-300'}`}
              data-testid="toggle-raggruppa-fornitori"
              title={raggruppa ? "Mostra tutte le consegne" : "Raggruppa per fornitore"}
            >
              {raggruppa ? "Per fornitore" : "Tutte le consegne"}
            </button>
          </div>

          {/* Riepilogo per tipo */}
          {schede.length > 0 && (
            <div className="grid grid-cols-3 border-b text-center text-xs py-2.5 bg-gray-50">
              <div>
                <div className="font-bold text-cyan-600 text-lg">{surgelati.length}</div>
                <div className="text-gray-500">❄️ Surgelati</div>
                <div className="text-[10px] text-cyan-700 font-medium">≤ -18°C</div>
              </div>
              <div>
                <div className="font-bold text-blue-600 text-lg">{refrigerati.length}</div>
                <div className="text-gray-500">🧊 Refrigerati</div>
                <div className="text-[10px] text-blue-700 font-medium">0 – 4°C</div>
              </div>
              <div>
                <div className="font-bold text-gray-500 text-lg">{ambiente.length}</div>
                <div className="text-gray-500">📦 Ambiente</div>
                <div className="text-[10px] text-gray-400 font-medium">N/A</div>
              </div>
            </div>
          )}

          {/* Lista schede */}
          {loading ? (
            <div className="p-8 text-center text-gray-400">
              <RefreshCw size={24} className="animate-spin mx-auto mb-2" />
              Caricamento schede...
            </div>
          ) : schede.length === 0 ? (
            <div className="p-8 text-center text-gray-400">
              <Package size={36} className="mx-auto mb-2 opacity-30" />
              <p className="text-sm">Nessuna scheda ricevimento</p>
              <p className="text-xs mt-1">Importa fatture per generare le schede</p>
            </div>
          ) : (
            <div className="divide-y max-h-[520px] overflow-y-auto">
              {schedeVista.map(s => {
                const rowKey = s.id_fattura || s.fornitore;
                const isEspansa = espansa === rowKey;
                const tipo = BADGE_TIPO[s.tipo_conservazione] || BADGE_TIPO.ambiente;
                return (
                  <div key={rowKey} className="hover:bg-gray-50 transition-colors">
                    <button
                      onClick={() => setEspansa(isEspansa ? null : rowKey)}
                      className="w-full text-left px-4 py-2.5 flex items-center gap-3"
                      data-testid={`scheda-ricevimento-${rowKey}`}
                    >
                      <span className="text-base flex-shrink-0">{tipo.icon}</span>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 flex-wrap">
                          <span className="text-xs font-semibold text-gray-800 truncate">{s.fornitore}</span>
                          <span className="text-[10px] text-gray-400 font-mono">{s.numero_documento}</span>
                          {raggruppa && s.num_consegne > 1 && (
                            <span className="text-[10px] bg-blue-100 text-blue-700 font-bold px-1.5 py-0.5 rounded-full">
                              {s.num_consegne} consegne
                            </span>
                          )}
                        </div>
                        <div className="flex items-center gap-2 mt-0.5">
                          <span className="text-[10px] text-gray-500">{s.data_consegna}</span>
                          <span className="text-[10px] text-gray-400">·</span>
                          <span className="text-[10px] text-gray-500">{s.num_prodotti} prodotti</span>
                        </div>
                      </div>
                      {/* Badge temperatura */}
                      <div className="flex-shrink-0 flex flex-col items-end gap-1">
                        {renderBadgeTemp(s)}
                        <span className="text-[9px] text-green-600 font-bold flex items-center gap-0.5">
                          <Check size={9} /> Conforme
                        </span>
                      </div>
                      {isEspansa
                        ? <ChevronDown size={14} className="text-gray-400 flex-shrink-0" />
                        : <ChevronRight size={14} className="text-gray-400 flex-shrink-0" />
                      }
                    </button>

                    {/* Dettaglio espanso */}
                    {isEspansa && (
                      <div className="px-4 pb-3 border-t border-gray-100 bg-gray-50">
                        {/* Info temperatura */}
                        <div className={`mt-2 mb-2 rounded-lg px-3 py-2 ${tipo.bg} border border-opacity-50`}>
                          <div className="flex items-start gap-2">
                            <Thermometer size={14} className={`flex-shrink-0 mt-0.5 ${tipo.text}`} />
                            <div>
                              <p className={`text-[11px] font-bold ${tipo.text}`}>
                                Temperatura rilevata al ricevimento:{" "}
                                {s.temperatura_rilevata !== null
                                  ? `${s.temperatura_rilevata > 0 ? "+" : ""}${s.temperatura_rilevata}°C`
                                  : "Non applicabile"}
                              </p>
                              {s.temperatura_min !== null && (
                                <p className="text-[10px] text-gray-600 mt-0.5">
                                  Range: {s.temperatura_min}°C / {s.temperatura_max}°C
                                </p>
                              )}
                              <p className="text-[10px] text-gray-500 mt-0.5 italic">{s.note_temperatura}</p>
                            </div>
                          </div>
                        </div>

                        {/* Prodotti + Lotti */}
                        {s.prodotti?.length > 0 && (
                          <div className="mt-1">
                            <p className="text-[10px] text-gray-500 font-medium mb-1 uppercase tracking-wide">
                              Prodotti consegnati — trascrizione lotti
                            </p>
                            <div className="space-y-1 max-h-48 overflow-y-auto">
                              {s.prodotti.map((p, i) => (
                                <div key={i} className="flex items-center justify-between text-[10px] py-1.5 px-2 rounded-lg bg-white border border-gray-100">
                                  <div className="flex-1 min-w-0 mr-2">
                                    <span className="text-gray-700 font-medium truncate block">{p.descrizione}</span>
                                    <span className="text-gray-400">{p.quantita} {p.unita_misura}</span>
                                    {p.lotto && (
                                      <span className="ml-2 text-blue-600 font-mono text-[9px] bg-blue-50 px-1 rounded">
                                        Lotto: {p.lotto}
                                      </span>
                                    )}
                                    {p.scadenza && (
                                      <span className="ml-1 text-amber-600 text-[9px]">Scad: {p.scadenza}</span>
                                    )}
                                  </div>
                                  {p.totale > 0 && (
                                    <span className="text-gray-600 font-semibold flex-shrink-0">€{p.totale.toFixed(2)}</span>
                                  )}
                                </div>
                              ))}
                            </div>
                          </div>
                        )}

                        {/* Note operatore */}
                        <NoteRicevimento idFattura={s.id_fattura} />
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </div>
      )}
    </Card>
  );
};


const FornitoriList = ({ fornitori, onToggleEscluso, onRefresh }) => {
  const [search, setSearch] = useState("");
  const [filtroStato, setFiltroStato] = useState("tutti");
  const [selectedFornitore, setSelectedFornitore] = useState(null);
  const [anagrafica, setAnagrafica] = useState(null);
  const [loadingAnagrafica, setLoadingAnagrafica] = useState(false);
  const [annoFiltro, setAnnoFiltro] = useState(new Date().getFullYear());
  const [anniDisponibili, setAnniDisponibili] = useState([new Date().getFullYear()]);

  const fornitoriAttivi = fornitori.filter(f => !f.escluso && !f.in_attesa).length;
  const fornitoriEsclusi = fornitori.filter(f => f.escluso).length;
  const fornitoriInAttesa = fornitori.filter(f => f.in_attesa).length;

  const filteredFornitori = fornitori.filter(f => {
    const matchSearch = f.nome?.toLowerCase().includes(search.toLowerCase());
    if (!matchSearch) return false;
    if (filtroStato === "attivo") return !f.escluso && !f.in_attesa;
    if (filtroStato === "escluso") return f.escluso;
    if (filtroStato === "in_attesa") return f.in_attesa;
    return true;
  });

  const loadAnagrafica = async (nome, anno) => {
    setSelectedFornitore(nome);
    setLoadingAnagrafica(true);
    try {
      // Prima carica senza filtro anno per scoprire gli anni disponibili
      const resAll = await axios.get(`${API}/fornitori/${encodeURIComponent(nome)}/anagrafica?anno=tutti`);
      const tutteAnni = (resAll.data?.anni_disponibili || []).sort((a, b) => b - a);

      let annoUsato = anno;
      if (!annoUsato) {
        // Usa l'anno più recente con dati, altrimenti l'anno corrente
        annoUsato = tutteAnni.length > 0 ? tutteAnni[0] : new Date().getFullYear();
      }

      setAnniDisponibili(tutteAnni.length > 0 ? tutteAnni : [new Date().getFullYear()]);
      setAnnoFiltro(annoUsato);

      // Poi carica i dati per l'anno scelto
      const res = await axios.get(`${API}/fornitori/${encodeURIComponent(nome)}/anagrafica?anno=${annoUsato}`);
      setAnagrafica(res.data);
    } catch (e) {
      toast.error("Errore caricamento anagrafica");
    } finally {
      setLoadingAnagrafica(false);
    }
  };

  const cambiaAnno = (nuovoAnno) => {
    setAnnoFiltro(nuovoAnno);
    if (selectedFornitore) {
      setLoadingAnagrafica(true);
      axios.get(`${API}/fornitori/${encodeURIComponent(selectedFornitore)}/anagrafica?anno=${nuovoAnno}`)
        .then(r => setAnagrafica(r.data))
        .catch(() => toast.error("Errore"))
        .finally(() => setLoadingAnagrafica(false));
    }
  };

  const approvaFornitore = async (nome, includi) => {
    try {
      await axios.post(`${API}/fornitori/approva?nome=${encodeURIComponent(nome)}&includi=${includi}`);
      toast.success(includi ? `${nome} incluso tra i fornitori attivi` : `${nome} escluso`);
      onRefresh();
    } catch (e) {
      toast.error("Errore approvazione fornitore");
    }
  };

  // ── Schede qualifica HACCP ───────────────────────────────────────────────
  const [schedeQualifica, setSchedeQualifica] = useState([]);
  const [showQualifica, setShowQualifica]     = useState(false);
  const [approvandoQ, setApprovandoQ]         = useState(null);

  useEffect(() => {
    axios.get(`${API}/haccp-auto-manuale/schede-qualifica`)
      .then(r => setSchedeQualifica(r.data || []))
      .catch(() => {});
  }, [fornitori]);

  const approvaQualifica = async (nome, approva) => {
    setApprovandoQ(nome);
    try {
      await axios.post(`${API}/haccp-auto-manuale/qualifica-fornitore?nome=${encodeURIComponent(nome)}&approva=${approva}`);
      toast.success(approva ? `${nome} — qualificato nel registro HACCP` : `${nome} — sospeso`);
      const res = await axios.get(`${API}/haccp-auto-manuale/schede-qualifica`);
      setSchedeQualifica(res.data || []);
    } catch { toast.error("Errore aggiornamento qualifica"); }
    finally { setApprovandoQ(null); }
  };

  return (
    <div className="space-y-4">
      {/* Notifica fornitori in attesa */}
      {fornitoriInAttesa > 0 && (
        <div className="bg-amber-50 border border-amber-300 rounded-xl p-4 flex items-start gap-3">
          <AlertTriangle className="text-amber-600 flex-shrink-0 mt-0.5" size={20} />
          <div className="flex-1">
            <p className="font-semibold text-amber-800">{fornitoriInAttesa} nuovo/i fornitore/i richiede approvazione</p>
            <p className="text-sm text-amber-700 mt-1">Nuove fatture importate da fornitori mai visti prima. Decidi se includerli o escluderli.</p>
          </div>
          <button onClick={() => setFiltroStato("in_attesa")}
            className="px-3 py-1.5 bg-amber-500 text-white rounded-lg text-sm font-medium hover:bg-amber-600">
            Vedi
          </button>
        </div>
      )}

      <Card>
        <div className="p-4 border-b flex items-center justify-between">
          <div>
            <h3 className="text-lg font-semibold flex items-center gap-2">
              <Building2 className="text-blue-600" size={24} />
              Gestione Fornitori
            </h3>
            <p className="text-sm text-gray-500 mt-1">
              Gestisci i fornitori: includi, escludi e visualizza la scheda anagrafica
            </p>
          </div>
          <button onClick={onRefresh} className="p-2 text-gray-500 hover:bg-gray-100 rounded-lg">
            <RefreshCw size={18} />
          </button>
        </div>

        {/* Stats */}
        <div className="p-4 bg-gray-50 border-b grid grid-cols-4 gap-4">
          {[
            { label: "Totale", value: fornitori.length, color: "text-blue-600", stato: "tutti", tooltip: "Tutti i fornitori registrati" },
            { label: "Attivi", value: fornitoriAttivi, color: "text-green-600", stato: "attivo", tooltip: "Fornitori con fatture attive e qualificati" },
            { label: "In Attesa", value: fornitoriInAttesa, color: "text-amber-600", stato: "in_attesa", tooltip: "In attesa di qualifica — nessuna fattura ricevuta ancora" },
            { label: "Esclusi", value: fornitoriEsclusi, color: "text-red-600", stato: "escluso", tooltip: "Fornitori esclusi manualmente. Le loro fatture vengono saltate durante l'import PEC." },
          ].map(s => (
            <button key={s.stato} onClick={() => setFiltroStato(s.stato === filtroStato ? "tutti" : s.stato)}
              title={s.tooltip}
              className={`text-center p-2 rounded-lg transition-all ${filtroStato === s.stato ? "ring-2 ring-blue-400 bg-white" : ""}`}>
              <p className={`text-2xl font-bold ${s.color}`}>{s.value}</p>
              <p className="text-xs text-gray-500">{s.label}</p>
            </button>
          ))}
        </div>

        {/* Aggiorna listino Acquaviva */}
        <div className="px-4 py-3 bg-amber-50 border-b border-amber-100 flex items-center gap-3">
          <div className="flex-1">
            <p className="text-sm font-semibold text-amber-800">Aggiorna prezzi listino Acquaviva</p>
            <p className="text-xs text-amber-600">Carica il PDF 2026 per aggiornare i prezzi sui 352 prodotti esistenti (no duplicati)</p>
          </div>
          <input type="file" accept=".pdf" id="listino-acquaviva-pdf" style={{ display: "none" }}
            onChange={async (e) => {
              const file = e.target.files[0];
              if (!file) return;
              const formData = new FormData();
              formData.append("file", file);
              try {
                const res = await axios.post(`${API}/acquaviva/import-listino-pdf`, formData, {
                  headers: { "Content-Type": "multipart/form-data" }
                });
                toast.success(`Aggiornati ${res.data.aggiornati_nel_db} prodotti su ${res.data.estratti_da_pdf} estratti`);
              } catch (err) {
                toast.error("Errore import: " + (err.response?.data?.detail || err.message));
              }
              e.target.value = "";
            }} />
          <button onClick={() => document.getElementById("listino-acquaviva-pdf").click()}
            className="px-3 py-2 bg-amber-500 text-white rounded-lg text-sm font-semibold hover:bg-amber-600 whitespace-nowrap flex-shrink-0">
            Carica PDF
          </button>
        </div>

        {/* Search */}
        <div className="p-4 border-b">
          <div className="relative">
            <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
            <input type="text" value={search} onChange={(e) => setSearch(e.target.value)}
              placeholder="Cerca fornitore..." data-testid="search-fornitore"
              className="w-full pl-10 pr-4 py-2.5 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>
        </div>

        {/* Lista */}
        <div className="divide-y max-h-[500px] overflow-y-auto">
          {filteredFornitori.length === 0 ? (
            <div className="p-8 text-center text-gray-500">
              <Building2 size={48} className="mx-auto mb-3 opacity-30" />
              <p>Nessun fornitore trovato</p>
              <p className="text-xs mt-1">Importa fatture XML per vedere i fornitori</p>
            </div>
          ) : (
            filteredFornitori.map((f, idx) => (
              <div key={f.nome || idx}
                className={`p-3 flex items-center justify-between transition-colors ${
                  f.in_attesa ? "bg-amber-50" : f.escluso ? "bg-red-50" : "hover:bg-gray-50"
                }`}
              >
                <div className="flex items-center gap-3 flex-1 min-w-0">
                  <div className={`w-9 h-9 rounded-full flex items-center justify-center flex-shrink-0 ${
                    f.in_attesa ? "bg-amber-100 text-amber-600" :
                    f.escluso ? "bg-red-100 text-red-600" : "bg-blue-100 text-blue-600"
                  }`}>
                    {f.in_attesa ? <AlertTriangle size={18} /> : f.escluso ? <Ban size={18} /> : <Building2 size={18} />}
                  </div>
                  <div className="min-w-0">
                    <p className={`font-medium text-sm truncate ${f.escluso ? "text-red-700 line-through" : f.in_attesa ? "text-amber-800" : "text-gray-900"}`}>
                      {f.nome}
                    </p>
                    <p className="text-xs text-gray-500">
                      {f.num_fatture || 0} fatture
                      {f.piva && ` • P.IVA: ${f.piva}`}
                      {f.ultima_fattura && ` • ultima: ${f.ultima_fattura}`}
                    </p>
                  </div>
                </div>

                <div className="flex gap-1.5 flex-shrink-0 ml-2">
                  <button onClick={() => loadAnagrafica(f.nome)}
                    className="p-1.5 text-blue-600 hover:bg-blue-50 rounded" title="Scheda anagrafica">
                    <FileText size={15} />
                  </button>

                  {f.in_attesa && (
                    <>
                      <button onClick={() => approvaFornitore(f.nome, true)}
                        className="px-2 py-1 text-xs bg-green-100 text-green-700 rounded hover:bg-green-200 font-medium">
                        <Check size={13} className="inline mr-0.5" />Includi
                      </button>
                      <button onClick={() => approvaFornitore(f.nome, false)}
                        className="px-2 py-1 text-xs bg-red-100 text-red-700 rounded hover:bg-red-200 font-medium">
                        <Ban size={13} className="inline mr-0.5" />Escludi
                      </button>
                    </>
                  )}

                  {!f.in_attesa && (
                    <button onClick={() => onToggleEscluso(f.nome, !f.escluso)}
                      className={`px-2 py-1 rounded text-xs font-medium flex items-center gap-1 transition-colors ${
                        f.escluso
                          ? "bg-green-100 text-green-700 hover:bg-green-200"
                          : "bg-red-100 text-red-700 hover:bg-red-200"
                      }`}
                    >
                      {f.escluso ? <><Check size={13} />Includi</> : <><Ban size={13} />Escludi</>}
                    </button>
                  )}
                </div>
              </div>
            ))
          )}
        </div>
      </Card>

      {/* ── Registro Qualifica Fornitori HACCP ──────────────────────────── */}
      <Card>
        <button
          onClick={() => setShowQualifica(v => !v)}
          className="w-full p-4 flex items-center justify-between hover:bg-gray-50 rounded-xl transition-colors"
        >
          <div className="flex items-center gap-3">
            <ShieldCheck size={20} className="text-green-600" />
            <div className="text-left">
              <p className="font-semibold text-gray-800">Registro Qualifica Fornitori — HACCP</p>
              <p className="text-xs text-gray-500 mt-0.5">
                Reg. CE 178/2002 art. 18 ·{" "}
                {schedeQualifica.filter(s => s.stato === "approvato").length} approvati ·{" "}
                {schedeQualifica.filter(s => s.stato === "in_attesa_verifica").length} in attesa ·{" "}
                {schedeQualifica.filter(s => s.stato === "sospeso").length} sospesi
              </p>
            </div>
          </div>
          {showQualifica ? <ChevronDown size={18} className="text-gray-400" /> : <ChevronRight size={18} className="text-gray-400" />}
        </button>

        {showQualifica && (
          <div className="border-t">
            <div className="p-3 bg-amber-50 border-b text-xs text-amber-800 flex gap-2">
              <AlertTriangle size={14} className="flex-shrink-0 mt-0.5" />
              <span>
                <strong>Obbligo HACCP:</strong> Ogni fornitore deve essere qualificato prima di accettarne le forniture.
                Clicca <Check size={10} className="inline" /> per approvare o <X size={10} className="inline" /> per sospendere.
              </span>
            </div>
            <div className="divide-y max-h-[500px] overflow-y-auto">
              {schedeQualifica.map(s => (
                <div key={s.id || s.nome_fornitore} className="p-3 flex items-start gap-3 hover:bg-gray-50">
                  <div className="flex-shrink-0 mt-0.5">
                    {s.stato === "approvato"           && <ShieldCheck size={18} className="text-green-500" />}
                    {s.stato === "in_attesa_verifica"  && <Clock size={18} className="text-amber-500" />}
                    {s.stato === "sospeso"             && <ShieldAlert size={18} className="text-red-500" />}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium text-gray-800 truncate">{s.nome_fornitore}</p>
                    <div className="flex flex-wrap gap-x-3 gap-y-0.5 mt-0.5">
                      <span className="text-xs text-gray-500">{s.categoria_merceologica}</span>
                      <span className="text-xs text-gray-400">T°: {s.temperatura_stoccaggio_richiesta}</span>
                      <span className="text-xs text-gray-400">{s.num_fatture} fatture · {s.ultima_fornitura}</span>
                    </div>
                    <div className="mt-1 flex flex-wrap gap-1">
                      {(s.criteri_qualifica?.certificazioni_richieste || []).map(c => (
                        <span key={c} className="text-[10px] bg-blue-50 text-blue-600 px-1.5 py-0.5 rounded">{c}</span>
                      ))}
                    </div>
                  </div>
                  <div className="flex gap-1.5 flex-shrink-0">
                    {s.stato !== "approvato" && (
                      <button
                        onClick={() => approvaQualifica(s.nome_fornitore, true)}
                        disabled={approvandoQ === s.nome_fornitore}
                        className="p-1.5 bg-green-100 text-green-700 hover:bg-green-200 rounded-lg transition-colors disabled:opacity-40"
                        title="Approva"
                      ><Check size={14} /></button>
                    )}
                    {s.stato !== "sospeso" && (
                      <button
                        onClick={() => approvaQualifica(s.nome_fornitore, false)}
                        disabled={approvandoQ === s.nome_fornitore}
                        className="p-1.5 bg-red-100 text-red-700 hover:bg-red-200 rounded-lg transition-colors disabled:opacity-40"
                        title="Sospendi"
                      ><X size={14} /></button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </Card>

      {/* Modale Anagrafica */}
      {selectedFornitore && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-xl max-h-[80vh] flex flex-col">
            <div className="px-4 py-3 border-b flex justify-between items-center">
              <h3 className="font-semibold flex items-center gap-2">
                <Building2 size={18} className="text-blue-600" />
                Scheda Anagrafica Fornitore
              </h3>
              {/* ── Selettore anno globale ── */}
              <div className="flex items-center gap-2">
                <span className="text-xs text-gray-500 font-medium">Anno:</span>
                <div className="flex gap-1">
                  {anniDisponibili.map(a => (
                    <button
                      key={a}
                      onClick={() => cambiaAnno(a)}
                      className={`px-2.5 py-1 rounded-lg text-xs font-bold transition-all ${
                        annoFiltro === a
                          ? 'bg-blue-600 text-white shadow-sm'
                          : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                      }`}
                    >
                      {a}
                    </button>
                  ))}
                </div>
                <button onClick={() => { setSelectedFornitore(null); setAnagrafica(null); }}
                  className="text-gray-400 hover:text-gray-600 ml-2">
                  <X size={18} />
                </button>
              </div>
            </div>
            <div className="overflow-y-auto flex-1 p-4">
              {loadingAnagrafica ? (
                <div className="text-center py-8 text-gray-400">Caricamento...</div>
              ) : anagrafica ? (
                <div className="space-y-4">
                  <div className="grid grid-cols-2 gap-3">
                    <div className="col-span-2">
                      <p className="text-xs text-gray-500 font-medium">Ragione Sociale</p>
                      <p className="font-semibold text-gray-900">{anagrafica.nome}</p>
                    </div>
                    <div>
                      <p className="text-xs text-gray-500 font-medium">P.IVA / C.F.</p>
                      <p className="text-sm">{anagrafica.piva || "-"}</p>
                    </div>
                    <div>
                      <p className="text-xs text-gray-500 font-medium">Stato</p>
                      <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${
                        anagrafica.escluso ? "bg-red-100 text-red-700" :
                        anagrafica.in_attesa ? "bg-amber-100 text-amber-700" :
                        "bg-green-100 text-green-700"
                      }`}>
                        {anagrafica.escluso ? "Escluso" : anagrafica.in_attesa ? "In Attesa" : "Attivo"}
                      </span>
                    </div>
                    <div>
                      <p className="text-xs text-gray-500 font-medium">
                        N° Fatture {anagrafica.anno_filtro && `(${anagrafica.anno_filtro})`}
                      </p>
                      <p className="text-sm font-medium">
                        {anagrafica.num_fatture}
                        {anagrafica.num_fatture_totali !== anagrafica.num_fatture && (
                          <span className="text-xs text-gray-400 ml-1">/ {anagrafica.num_fatture_totali} tot.</span>
                        )}
                      </p>
                    </div>
                    <div>
                      <p className="text-xs text-gray-500 font-medium">
                        Totale Acquistato {anagrafica.anno_filtro && `(${anagrafica.anno_filtro})`}
                      </p>
                      <p className="text-sm font-bold text-blue-600">€{(anagrafica.totale_acquistato || 0).toFixed(2)}</p>
                    </div>
                    <div>
                      <p className="text-xs text-gray-500 font-medium">Prodotti Diversi</p>
                      <p className="text-sm">{anagrafica.num_prodotti_diversi}</p>
                    </div>
                    {anagrafica.indirizzo && (
                      <div className="col-span-2">
                        <p className="text-xs text-gray-500 font-medium">Indirizzo</p>
                        <p className="text-sm">{anagrafica.indirizzo}</p>
                      </div>
                    )}
                    {anagrafica.note && (
                      <div className="col-span-2">
                        <p className="text-xs text-gray-500 font-medium">Note</p>
                        <p className="text-sm">{anagrafica.note}</p>
                      </div>
                    )}
                  </div>

                  {/* ── TRACKER COLLI OMAGGIO ─────────────────────────────── */}
                  {anagrafica.colli_pagati > 0 && (
                    <div className="rounded-xl border-2 border-amber-200 bg-amber-50 p-4">
                      <div className="flex items-center gap-2 mb-3">
                        <span className="text-lg">🎁</span>
                        <p className="font-semibold text-amber-800 text-sm">
                          Tracker Colli Omaggio {anagrafica.anno_filtro && <span className="text-amber-500">— {anagrafica.anno_filtro}</span>}
                        </p>
                        <span className="ml-auto text-xs text-amber-600 bg-amber-100 px-2 py-0.5 rounded-full">
                          ogni {anagrafica.soglia_omaggio} pagati = 1 omaggio
                        </span>
                      </div>

                      {/* KPI principali: 4 box */}
                      <div className="grid grid-cols-4 gap-2 text-center mb-3">
                        <div className="bg-white rounded-lg p-2 border border-amber-100">
                          <p className="text-xl font-bold text-gray-800">{anagrafica.colli_pagati}</p>
                          <p className="text-[10px] text-gray-500 font-medium uppercase">Colli Pagati</p>
                        </div>
                        <div className="bg-white rounded-lg p-2 border border-green-200">
                          <p className="text-xl font-bold text-green-600">{anagrafica.colli_omaggio_maturati}</p>
                          <p className="text-[10px] text-gray-500 font-medium uppercase">Maturati</p>
                          <p className="text-[9px] text-green-500">(guadagnati)</p>
                        </div>
                        <div className={`rounded-lg p-2 border ${anagrafica.colli_omaggio_ricevuti > anagrafica.colli_omaggio_maturati ? 'bg-orange-50 border-orange-200' : 'bg-green-50 border-green-200'}`}>
                          <p className={`text-xl font-bold ${anagrafica.colli_omaggio_ricevuti > anagrafica.colli_omaggio_maturati ? 'text-orange-600' : 'text-green-600'}`}>
                            {anagrafica.colli_omaggio_ricevuti}
                          </p>
                          <p className="text-[10px] text-gray-500 font-medium uppercase">Ricevuti</p>
                          <p className="text-[9px] text-gray-400">(effettivi)</p>
                        </div>
                        <div className={`rounded-lg p-2 border ${
                          anagrafica.colli_credito > 0 ? 'bg-blue-50 border-blue-200'
                          : anagrafica.colli_credito < 0 ? 'bg-orange-50 border-orange-200'
                          : 'bg-gray-50 border-gray-200'}`}>
                          <p className={`text-xl font-bold ${
                            anagrafica.colli_credito > 0 ? 'text-blue-600'
                            : anagrafica.colli_credito < 0 ? 'text-orange-600'
                            : 'text-gray-500'}`}>
                            {anagrafica.colli_credito > 0 ? `+${anagrafica.colli_credito}` : anagrafica.colli_credito}
                          </p>
                          <p className="text-[10px] text-gray-500 font-medium uppercase">Saldo</p>
                          <p className="text-[9px] text-gray-400">
                            {anagrafica.colli_credito > 0 ? 'da ricevere' : anagrafica.colli_credito < 0 ? 'anticipato' : 'in pari'}
                          </p>
                        </div>
                      </div>

                      {/* Stato saldo: anticipo vs credito */}
                      <div className={`flex items-center gap-2 text-xs font-semibold py-2 px-3 rounded-lg mb-3 ${
                        anagrafica.colli_credito > 0 ? 'bg-blue-100 text-blue-700'
                        : anagrafica.colli_credito < 0 ? 'bg-orange-100 text-orange-700'
                        : 'bg-green-100 text-green-700'
                      }`}>
                        <span>
                          {anagrafica.colli_credito > 0
                            ? `Hai ${anagrafica.colli_credito} omaggi da ricevere`
                            : anagrafica.colli_credito < 0
                              ? `Hai ricevuto ${Math.abs(anagrafica.colli_credito)} omaggio in anticipo`
                              : 'Sei in pari con gli omaggi'}
                        </span>
                      </div>

                      {/* Prossimo omaggio: quanti colli mancano */}
                      <div className="bg-white rounded-lg border border-amber-200 p-3 mb-3">
                        <div className="flex justify-between items-start mb-2">
                          <div>
                            <p className="text-xs font-bold text-amber-800">Prossimo Omaggio</p>
                            {anagrafica.colli_al_prossimo_omaggio > 0 && (
                              <p className="text-[10px] text-gray-500 mt-0.5">
                                {anagrafica.colli_credito < 0
                                  ? `Devi prima rientrare dall'anticipo (${Math.abs(anagrafica.colli_credito)}×${anagrafica.soglia_omaggio}) + ciclo corrente`
                                  : `Mancano ${anagrafica.soglia_omaggio - (anagrafica.colli_pagati % anagrafica.soglia_omaggio || anagrafica.soglia_omaggio)} colli per completare il ciclo`
                                }
                              </p>
                            )}
                          </div>
                          <div className="text-right">
                            {anagrafica.colli_al_prossimo_omaggio === 0
                              ? <span className="text-green-600 font-bold text-sm">Omaggio disponibile!</span>
                              : <span className="text-amber-700 font-bold text-lg">{anagrafica.colli_al_prossimo_omaggio} colli</span>
                            }
                          </div>
                        </div>

                        {/* Barra progresso visiva */}
                        {(() => {
                          const soglia = anagrafica.soglia_omaggio || 10;
                          const nel_ciclo = anagrafica.colli_pagati % soglia || 0;
                          const pct_ciclo = Math.round((nel_ciclo / soglia) * 100);
                          const anticipo = anagrafica.colli_credito < 0 ? Math.abs(anagrafica.colli_credito) : 0;
                          return (
                            <div>
                              {anticipo > 0 && (
                                <p className="text-[9px] text-orange-600 mb-1">
                                  Ciclo attuale: {nel_ciclo}/{soglia} ({pct_ciclo}%) · poi serviranno {anticipo}×{soglia} colli extra per l'anticipo
                                </p>
                              )}
                              <div className="w-full bg-amber-100 rounded-full h-2 overflow-hidden">
                                <div className="bg-amber-500 h-2 rounded-full transition-all" style={{ width: `${pct_ciclo}%` }} />
                              </div>
                              <p className="text-[9px] text-gray-500 mt-1">
                                Ciclo corrente: {nel_ciclo} / {soglia} colli
                              </p>
                            </div>
                          );
                        })()}
                      </div>

                      {/* Credito/Debito omaggio */}
                      {anagrafica.colli_credito !== 0 && (
                        <div className={`text-center text-xs font-semibold py-1.5 rounded-lg mb-3 ${
                          anagrafica.colli_credito > 0
                            ? 'bg-blue-100 text-blue-700'
                            : 'bg-orange-100 text-orange-700'
                        }`}>
                          {anagrafica.colli_credito > 0
                            ? `Il fornitore ti deve ancora ${anagrafica.colli_credito} omaggio`
                            : `Anticipo: hai ricevuto ${Math.abs(anagrafica.colli_credito)} omaggio non ancora maturato — serve acquistare altri ${anagrafica.colli_al_prossimo_omaggio} colli`}
                        </div>
                      )}

                      {/* ── VALORE ECONOMICO OMAGGI ────────────────────── */}
                      {(anagrafica.valore_omaggi_ricevuti > 0 || anagrafica.incasso_omaggi_vendita > 0) && (
                        <div className="bg-white rounded-xl border-2 border-emerald-200 p-3">
                          <div className="flex items-center justify-between mb-3">
                            <div className="flex items-center gap-2">
                              <span className="text-sm">💰</span>
                              <p className="text-sm font-bold text-emerald-800">Valore Recuperato dagli Omaggi</p>
                            </div>
                            <div className="text-right">
                              <span className="text-2xl font-bold text-emerald-700">€{(anagrafica.incasso_omaggi_vendita || 0).toFixed(2)}</span>
                              <p className="text-[9px] text-emerald-600">totale recuperato</p>
                            </div>
                          </div>

                          {/* Due righe: incasso + risparmio + costo acquisto */}
                          <div className="grid grid-cols-3 gap-2 text-center mb-3">
                            <div className="bg-emerald-50 rounded-lg p-2 border border-emerald-100">
                              <p className="text-base font-bold text-emerald-600">
                                €{(anagrafica.omaggi_dettaglio || []).filter(o=>o.tipo==='prodotto_finito').reduce((s,o)=>s+(o.valore_economico||0),0).toFixed(2)}
                              </p>
                              <p className="text-[9px] text-emerald-700 font-semibold">Incasso Vendita</p>
                              <p className="text-[8px] text-gray-400">prodotti finiti venduti</p>
                            </div>
                            <div className="bg-blue-50 rounded-lg p-2 border border-blue-100">
                              <p className="text-base font-bold text-blue-600">
                                €{(anagrafica.omaggi_dettaglio || []).filter(o=>o.tipo==='ingrediente_ricetta').reduce((s,o)=>s+(o.valore_economico||0),0).toFixed(2)}
                              </p>
                              <p className="text-[9px] text-blue-700 font-semibold">Risparmio Food Cost</p>
                              <p className="text-[8px] text-gray-400">ingredienti non pagati</p>
                            </div>
                            <div className="bg-gray-50 rounded-lg p-2 border border-gray-100">
                              <p className="text-base font-bold text-orange-500">
                                €{(anagrafica.valore_omaggi_ricevuti || 0).toFixed(2)}
                              </p>
                              <p className="text-[9px] text-gray-600 font-semibold">Costo Acquisto</p>
                              <p className="text-[8px] text-gray-400">quanto valgono all'acquisto</p>
                            </div>
                          </div>

                          {/* Barra recupero */}
                          <div className="mb-3">
                            <div className="w-full bg-gray-100 rounded-full h-2.5 relative overflow-hidden">
                              <div className="bg-emerald-500 h-2.5 rounded-full transition-all" style={{ width: `${Math.min(anagrafica.perc_recupero_su_fatture || 0, 100)}%` }} />
                            </div>
                            <p className="text-[10px] text-emerald-700 mt-1 font-medium text-center">
                              {anagrafica.perc_recupero_su_fatture}% del totale fatture recuperato tramite omaggi
                              <span className="text-gray-400 ml-1">(su €{(anagrafica.totale_acquistato || 0).toFixed(2)} acquistati)</span>
                            </p>
                          </div>

                          {/* Dettaglio per prodotto */}
                          {anagrafica.omaggi_dettaglio?.length > 0 && (
                            <details>
                              <summary className="text-xs text-emerald-700 cursor-pointer font-medium hover:text-emerald-900 mb-2">
                                Dettaglio per prodotto ({anagrafica.colli_omaggio_ricevuti} KAR · {anagrafica.pezzi_omaggio_totali} pezzi totali)
                              </summary>
                              <div className="mt-2 space-y-2 max-h-64 overflow-y-auto">
                                {/* Legenda */}
                                <div className="flex gap-2 flex-wrap">
                                  <span className="text-[8px] bg-emerald-100 text-emerald-700 px-1.5 py-0.5 rounded-full font-bold">Prodotto = incasso vendita</span>
                                  <span className="text-[8px] bg-blue-100 text-blue-700 px-1.5 py-0.5 rounded-full font-bold">Ingrediente = risparmio food cost</span>
                                  <span className="text-[8px] bg-gray-100 text-gray-500 px-1.5 py-0.5 rounded-full font-bold">? = stima costo acq.</span>
                                </div>
                                {anagrafica.omaggi_dettaglio.map((od, i) => {
                                  const tipo = od.tipo || 'sconosciuto';
                                  const badgeClass = tipo === 'prodotto_finito' ? 'bg-emerald-100 text-emerald-700' : tipo === 'ingrediente_ricetta' ? 'bg-blue-100 text-blue-700' : 'bg-gray-100 text-gray-500';
                                  const badgeLabel = tipo === 'prodotto_finito' ? 'Prodotto' : tipo === 'ingrediente_ricetta' ? 'Ingrediente' : '?';
                                  const valore = od.valore_economico || od.valore_totale || 0;
                                  const valoreCls = tipo === 'ingrediente_ricetta' ? 'text-blue-600' : tipo === 'prodotto_finito' ? 'text-emerald-600' : 'text-orange-500';
                                  return (
                                    <div key={i} className="bg-gray-50 rounded-lg p-2 border border-gray-100">
                                      {/* Riga 1: badge + nome + valore */}
                                      <div className="flex items-start justify-between gap-2">
                                        <div className="flex-1 min-w-0">
                                          <div className="flex items-center gap-1 mb-0.5">
                                            <span className={`text-[7px] font-bold px-1.5 py-0.5 rounded-full shrink-0 ${badgeClass}`}>{badgeLabel}</span>
                                            <span className="text-[10px] text-gray-700 font-semibold truncate" title={od.prodotto}>
                                              {od.prodotto.replace(/^AQV\s+/i,'').replace(/\s+\d+G\s+\d+\.?\d*KG.*/i,'').substring(0,35)}
                                            </span>
                                          </div>
                                          {/* Dettaglio calcolo */}
                                          {tipo === 'prodotto_finito' && od.prezzo_vendita_pezzo > 0 && (
                                            <p className="text-[9px] text-emerald-600 ml-0.5">
                                              {od.stima ? '~' : ''}€{od.prezzo_vendita_pezzo.toFixed(2)}/pz × {od.pezzi_totali} pz = <strong>€{valore.toFixed(2)}</strong>
                                              {od.stima && <span className="text-gray-400 ml-1">(stima per categoria)</span>}
                                            </p>
                                          )}
                                          {tipo === 'ingrediente_ricetta' && (
                                            <div className="ml-0.5">
                                              <p className="text-[9px] text-blue-600">
                                                {od.qty_cartoni} KAR × €{od.prezzo_unitario.toFixed(2)}/KAR = <strong>€{valore.toFixed(2)}</strong> risparmio
                                              </p>
                                              {od.ricette_collegate?.length > 0 && (
                                                <p className="text-[8px] text-blue-500">
                                                  Usato in: {od.ricette_collegate.map(r=>r.nome_ricetta).join(', ')}
                                                </p>
                                              )}
                                            </div>
                                          )}
                                          {tipo === 'sconosciuto' && (
                                            <p className="text-[9px] text-gray-500 ml-0.5">
                                              {od.qty_cartoni} KAR × €{od.prezzo_unitario > 0 ? od.prezzo_unitario.toFixed(2) : '?'}/KAR
                                            </p>
                                          )}
                                        </div>
                                        <div className="text-right shrink-0">
                                          <span className={`text-sm font-bold ${valore > 0 ? valoreCls : 'text-gray-300'}`}>
                                            {valore > 0 ? `€${valore.toFixed(2)}` : 'N/D'}
                                          </span>
                                        </div>
                                      </div>
                                    </div>
                                  );
                                })}
                              </div>
                            </details>
                          )}
                        </div>
                      )}

                      {/* Dettaglio colli per fattura */}
                      {anagrafica.colli_per_fattura?.filter(f => f.pagati > 0 || f.omaggio > 0).length > 0 && (
                        <details className="mt-3">
                          <summary className="text-xs text-amber-700 cursor-pointer font-medium hover:text-amber-900">
                            Dettaglio colli per fattura
                          </summary>
                          <div className="mt-2 space-y-1 max-h-36 overflow-y-auto">
                            {anagrafica.colli_per_fattura.filter(f => f.pagati > 0 || f.omaggio > 0).map((f, i) => (
                              <div key={i} className="flex items-center justify-between text-xs py-1 border-b border-amber-100 last:border-0">
                                <span className="text-gray-500 w-24 flex-shrink-0">{f.data}</span>
                                <span className="font-mono text-gray-600 w-20 flex-shrink-0 truncate">{f.numero}</span>
                                <span className="text-gray-700">{f.pagati} pagati</span>
                                {f.omaggio > 0 && (
                                  <span className="text-green-600 font-semibold">+{f.omaggio} omaggio</span>
                                )}
                              </div>
                            ))}
                          </div>
                        </details>
                      )}
                    </div>
                  )}

                  {anagrafica.storico_fatture?.length > 0 && (
                    <FattureList fatture={anagrafica.storico_fatture} />
                  )}
                </div>
              ) : null}
            </div>
          </div>
        </div>
      )}

      {/* ── Qualifica Fornitori Batch ───────────────────────────────────── */}
      <QualificaBatchPanel />

      {/* ── Registro Ricevimento Merci Temperature ─────────────────────── */}
      <SchedeRicevimentoPanel />

      {/* Info Box */}
      <Card className="p-4 bg-amber-50 border-amber-200">
        <div className="flex items-start gap-3">
          <AlertTriangle className="text-amber-600 flex-shrink-0" size={20} />
          <div>
            <p className="font-medium text-amber-800">Come funziona esclusione</p>
            <ul className="text-sm text-amber-700 mt-2 list-disc list-inside">
              <li>I fornitori esclusi non vengono inclusi nel mapping materie prime e nel Food Cost</li>
              <li>Le fatture rimangono nel database ma vengono ignorate nell'analisi</li>
              <li>I nuovi fornitori appaiono "In Attesa" finché non approvi o escludi</li>
            </ul>
          </div>
        </div>
      </Card>
    </div>
  );
};

export default FornitoriList;
