import { useState, useCallback } from "react";
import axios from "axios";
import { toast } from "sonner";
import { API } from "../utils/constants";

export function useFornitori() {
  const [fornitori, setFornitori] = useState([]);

  const fetchFornitori = useCallback(async () => {
    try {
      const res = await axios.get(`${API}/fornitori`);
      setFornitori(res.data);
    } catch (e) {
      console.error("Errore fornitori:", e);
    }
  }, []);

  const toggleFornitoreEscluso = async (nome, escludi) => {
    try {
      await axios.post(`${API}/fornitori/escludi?nome=${encodeURIComponent(nome)}&escludi=${escludi}`);
      toast.success(`Fornitore ${escludi ? "escluso" : "incluso"}`);
      await fetchFornitori();
    } catch (e) {
      console.error("Errore toggle fornitore:", e);
      toast.error("Errore nell'aggiornamento");
    }
  };

  return { fornitori, fetchFornitori, toggleFornitoreEscluso };
}
