import { useState, useEffect } from "react";
import axios from "axios";
import { toast } from "sonner";
import {
  Mail,
  Download,
  RefreshCw,
  CheckCircle,
  XCircle,
  AlertTriangle,
  FileText,
  Eye,
  Play,
  Inbox,
  Settings,
  Package,
  ChevronDown,
  ChevronUp,
  Zap,
  Clock,
  TrendingUp
} from "lucide-react";
import { API } from "../../utils/constants";

const Card = ({ children, className = "" }) => (
  <div className={`bg-white rounded-xl shadow-sm border border-gray-100 ${className}`}>
    {children}
  </div>
);

// ── Riga espandibile singola fattura ──
const FatturaRow = ({ fattura, index, onFornitoreToggled }) => {
  const [expanded, setExpanded] = useState(false);
  const [toggling, setToggling] = useState(false);
  const [escluso, setEscluso] = useState(false);
  const prodotti = fattura.prodotti || [];

  // Controlla stato fornitore al mount
  useEffect(() => {
    const checkStato = async () => {
      try {
        const res = await axios.get(`${API}/fornitori?stato=escluso`);
        const nomiEsclusi = (res.data || []).map(f => f.nome?.toLowerCase() || "");
        setEscluso(nomiEsclusi.some(n => fattura.fornitore?.toLowerCase().includes(n) || n.includes(fattura.fornitore?.toLowerCase() || "")));
      } catch {}
    };
    checkStato();
  }, [fattura.fornitore]);

  const toggleEscluso = async (e) => {
    e.stopPropagation();
    setToggling(true);
    try {
      await axios.post(`${API}/fornitori/escludi`, null, {
        params: { nome: fattura.fornitore, escludi: !escluso }
      });
      setEscluso(!escluso);
      toast.success(!escluso
        ? `"${fattura.fornitore}" escluso — le sue fatture non verranno più importate`
        : `"${fattura.fornitore}" riattivato`);
      if (onFornitoreToggled) onFornitoreToggled();
    } catch (err) {
      toast.error("Errore: " + (err.response?.data?.detail || err.message));
    }
    setToggling(false);
  };

  return (
    <>
      <tr
        className={`hover:bg-gray-50 transition-colors cursor-pointer ${escluso ? "opacity-50" : ""}`}
        onClick={() => setExpanded(v => !v)}
        data-testid={`fattura-row-${index}`}
      >
        <td className="px-3 py-2 text-gray-400">
          {expanded ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
        </td>
        <td className="px-3 py-2 text-gray-800 font-medium max-w-xs">
          <div className="flex items-center gap-2">
            <span className="truncate block max-w-xs">{fattura.fornitore || "—"}</span>
            {escluso && (
              <span className="px-1.5 py-0.5 bg-red-100 text-red-600 rounded text-xs font-semibold flex-shrink-0">
                ESCLUSO
              </span>
            )}
          </div>
        </td>
        <td className="px-3 py-2 text-gray-500 font-mono text-xs">
          {fattura.numero_fattura || "—"}
        </td>
        <td className="px-3 py-2 text-gray-500 text-xs">
          {fattura.data_fattura || "—"}
        </td>
        <td className="px-3 py-2 text-right">
          <span className="px-2 py-0.5 bg-blue-50 text-blue-700 rounded-full text-xs font-bold">
            {prodotti.length} righe
          </span>
        </td>
      </tr>
      {expanded && (
        <tr>
          <td colSpan={5} className="bg-indigo-50 border-b border-indigo-100 px-0 py-0">
            <div className="px-6 py-3">
              <div className="flex items-center justify-between mb-2">
                <p className="text-xs font-semibold text-indigo-700 uppercase tracking-wide">
                  Prodotti in questa fattura
                </p>
                <button
                  onClick={toggleEscluso}
                  disabled={toggling}
                  className={`px-3 py-1.5 rounded-lg text-xs font-semibold flex items-center gap-1.5 transition-colors ${
                    escluso
                      ? "bg-green-100 text-green-700 hover:bg-green-200 border border-green-300"
                      : "bg-red-100 text-red-700 hover:bg-red-200 border border-red-300"
                  }`}
                  data-testid={`btn-toggle-fornitore-${index}`}
                >
                  {toggling ? (
                    <RefreshCw size={12} className="animate-spin" />
                  ) : escluso ? (
                    <><CheckCircle size={12} /> Riattiva Fornitore</>
                  ) : (
                    <><XCircle size={12} /> Escludi Fornitore</>
                  )}
                </button>
              </div>
              {prodotti.length === 0 ? (
                <p className="text-xs text-gray-400 italic">Nessun dettaglio disponibile</p>
              ) : (
                <table className="w-full text-xs">
                  <thead>
                    <tr className="text-indigo-600">
                      <th className="text-left py-1 pr-4 font-semibold">Descrizione</th>
                      <th className="text-right py-1 pr-4 font-semibold w-16">Qtà</th>
                      <th className="text-right py-1 pr-4 font-semibold w-20">Prezzo</th>
                      <th className="text-left py-1 font-semibold w-12">U.M.</th>
                    </tr>
                  </thead>
                  <tbody>
                    {prodotti.map((p, j) => (
                      <tr key={j} className="border-t border-indigo-100">
                        <td className="py-1 pr-4 text-gray-700 max-w-sm">{p.descrizione || "—"}</td>
                        <td className="py-1 pr-4 text-right text-gray-600">{p.quantita || "—"}</td>
                        <td className="py-1 pr-4 text-right font-medium text-gray-800">
                          {p.prezzo ? `€${parseFloat(p.prezzo).toFixed(2)}` : "—"}
                        </td>
                        <td className="py-1 text-gray-400">{p.unita_misura || "PZ"}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              )}
            </div>
          </td>
        </tr>
      )}
    </>
  );
};

export const PECImportView = ({ onImportComplete }) => {
  const [status, setStatus] = useState(null);
  const [loading, setLoading] = useState(false);
  const [importing, setImporting] = useState(false);
  const [preview, setPreview] = useState(null);
  const [importResult, setImportResult] = useState(null);
  const [fattureImportate, setFattureImportate] = useState([]);
  const [loadingFatture, setLoadingFatture] = useState(false);
  const [showFatture, setShowFatture] = useState(true);
  const [filtroFornitore, setFiltroFornitore] = useState("");
  const [pipelineStatus, setPipelineStatus] = useState(null);
  const [runningPipeline, setRunningPipeline] = useState(false);
  const [settings, setSettings] = useState({
    onlyUnread: false,
    maxMessages: 100,
    markAsRead: false,
    forceReimport: false
  });

  // Verifica stato connessione PEC
  const checkStatus = async () => {
    setLoading(true);
    try {
      const res = await axios.get(`${API}/pec/status`);
      setStatus(res.data);
    } catch (e) {
      setStatus({ connected: false, error: e.response?.data?.detail || e.message });
    } finally {
      setLoading(false);
    }
  };

  // Carica fatture importate
  const loadFatture = async () => {
    setLoadingFatture(true);
    try {
      const res = await axios.get(`${API}/fatture?escludi_fornitori=false`);
      setFattureImportate(res.data || []);
    } catch (e) {
      toast.error("Errore caricamento fatture: " + (e.response?.data?.detail || e.message));
    } finally {
      setLoadingFatture(false);
    }
  };

  // Anteprima messaggi
  const loadPreview = async () => {
    setLoading(true);
    try {
      const res = await axios.get(`${API}/pec/anteprima?max_messages=${settings.maxMessages}`);
      setPreview(res.data);
    } catch (e) {
      toast.error("Errore caricamento anteprima: " + (e.response?.data?.detail || e.message));
    } finally {
      setLoading(false);
    }
  };

  // Importa fatture (solo non letti, hardcoded)
  const handleImport = async () => {
    setImporting(true);
    setImportResult(null);
    try {
      // Import normale: legge solo messaggi non letti, max 100, marca come letti
      // I duplicati sono già gestiti lato backend tramite numero_fattura
      const res = await axios.post(`${API}/pec/import`, null, {
        params: {
          only_unread: true,
          max_messages: 100,
          mark_as_read: true,
          force_reimport: false
        }
      });
      setImportResult(res.data);
      
      if (res.data.imported_count > 0) {
        toast.success(`Importate ${res.data.imported_count} fatture!`);
        if (onImportComplete) onImportComplete();
        await loadFatture();
      } else if (res.data.skipped_already_present > 0) {
        toast.info(`Nessuna nuova fattura. ${res.data.skipped_already_present} già presenti nel sistema.`);
      } else {
        toast.info("Nessuna fattura trovata nei messaggi non letti.");
      }
      await checkStatus();
    } catch (e) {
      toast.error("Errore importazione: " + (e.response?.data?.detail || e.message));
    } finally {
      setImporting(false);
    }
  };

  // Reimporta: forza tutti i messaggi (anche letti), utile per recupero
  const handleForceReimport = async () => {
    setImporting(true);
    setImportResult(null);
    try {
      const res = await axios.post(`${API}/pec/import`, null, {
        params: {
          only_unread: false,
          max_messages: 100,
          mark_as_read: false,
          force_reimport: true
        }
      });
      setImportResult(res.data);
      if (res.data.imported_count > 0) {
        toast.success(`Reimportate ${res.data.imported_count} fatture!`);
        if (onImportComplete) onImportComplete();
        await loadFatture();
      } else {
        toast.info("Nessuna nuova fattura trovata nemmeno con reimporta.");
      }
      await checkStatus();
    } catch (e) {
      toast.error("Errore reimport: " + (e.response?.data?.detail || e.message));
    } finally {
      setImporting(false);
    }
  };

  // Carica stato pipeline
  const loadPipelineStatus = async () => {
    try {
      const res = await axios.get(`${API}/pipeline/status`);
      setPipelineStatus(res.data);
    } catch {}
  };

  const eseguiPipeline = async () => {
    setRunningPipeline(true);
    try {
      const res = await axios.post(`${API}/pipeline/esegui`);
      setPipelineStatus(res.data);
      const steps = res.data.steps || [];
      const pv = steps.find(s => s.step === "prodotti_vendita");
      const fc = steps.find(s => s.step === "food_cost");
      toast.success(`Pipeline completata in ${res.data.duration_ms}ms · ${fc?.ricette_aggiornate || 0} ricette · ${pv?.aggiornati || 0} prodotti aggiornati`);
      await loadFatture();
    } catch (e) {
      toast.error("Errore pipeline: " + (e.response?.data?.detail || e.message));
    }
    setRunningPipeline(false);
  };

  useEffect(() => {
    checkStatus();
    loadFatture();
    loadPipelineStatus();
  }, []);

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex justify-between items-start flex-wrap gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-800 flex items-center gap-3">
            <Mail className="text-blue-600" size={28} />
            Importazione PEC
          </h2>
          <p className="text-gray-500 mt-1">Importa automaticamente le fatture dalla casella PEC</p>
        </div>
        <button
          onClick={checkStatus}
          disabled={loading}
          className="px-4 py-2 bg-gray-100 text-gray-700 rounded-lg flex items-center gap-2 hover:bg-gray-200 disabled:opacity-50"
        >
          <RefreshCw size={18} className={loading ? "animate-spin" : ""} />
          Aggiorna
        </button>
      </div>

      {/* Stato Connessione */}
      <Card className="p-6">
        <h3 className="font-semibold text-gray-800 mb-4 flex items-center gap-2">
          <Settings size={18} />
          Stato Connessione PEC
        </h3>
        
        {loading && !status ? (
          <div className="flex items-center gap-3 text-gray-500">
            <RefreshCw className="animate-spin" size={20} />
            Verifica connessione...
          </div>
        ) : status ? (
          <div className="space-y-4">
            <div className="flex items-center gap-3">
              {status.connected ? (
                <div className="flex items-center gap-2 text-green-600">
                  <CheckCircle size={20} />
                  <span className="font-medium">Connesso</span>
                </div>
              ) : (
                <div className="flex items-center gap-2 text-red-600">
                  <XCircle size={20} />
                  <span className="font-medium">Non connesso</span>
                </div>
              )}
            </div>
            
            {status.connected && (
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="p-4 bg-blue-50 rounded-lg">
                  <p className="text-sm text-blue-600">Email PEC</p>
                  <p className="font-medium text-blue-800">{status.email}</p>
                </div>
                <div className="p-4 bg-gray-50 rounded-lg">
                  <p className="text-sm text-gray-600">Messaggi Totali</p>
                  <p className="text-2xl font-bold text-gray-800">{status.total_messages}</p>
                </div>
                <div className="p-4 bg-orange-50 rounded-lg">
                  <p className="text-sm text-orange-600">Non Letti</p>
                  <p className="text-2xl font-bold text-orange-800">{status.unread_messages}</p>
                </div>
              </div>
            )}
            
            {status.error && (
              <div className="p-4 bg-red-50 border border-red-200 rounded-lg flex items-start gap-3">
                <AlertTriangle className="text-red-500 mt-0.5" size={20} />
                <div>
                  <p className="font-medium text-red-800">Errore connessione</p>
                  <p className="text-sm text-red-600">{status.error}</p>
                </div>
              </div>
            )}
            
            {status.unread_messages === 0 && !status.error && (
              <div className="p-4 bg-amber-50 border border-amber-200 rounded-lg flex items-start gap-3">
                <AlertTriangle className="text-amber-500 mt-0.5" size={20} />
                <div>
                  <p className="font-medium text-amber-800">Nessuna email non letta</p>
                  <p className="text-sm text-amber-600">
                    Tutte le {status.total_messages} email sono già state lette. 
                    Deseleziona "Solo messaggi non letti" per reimportare le fatture esistenti.
                  </p>
                </div>
              </div>
            )}
          </div>
        ) : null}
      </Card>

      {/* Pulsanti Import */}
      {status?.connected && (
        <Card className="p-4">
          <div className="flex gap-3 items-center">
            <button onClick={handleImport} disabled={importing}
              className="px-6 py-2.5 bg-blue-600 text-white rounded-xl font-semibold flex items-center gap-2 hover:bg-blue-700 disabled:opacity-50">
              <Download size={18} />
              {importing ? "Importazione..." : "Importa Fatture PEC"}
            </button>
            <button onClick={handleForceReimport} disabled={importing}
              className="px-4 py-2 bg-amber-50 border border-amber-300 text-amber-700 rounded-xl text-sm font-medium flex items-center gap-2 hover:bg-amber-100 disabled:opacity-50"
              title="Reimporta controllando anche le fatture già presenti">
              <RefreshCw size={15} />
              Reimporta
            </button>
          </div>
        </Card>
      )}

      {/* Anteprima */}
      {preview && (
        <Card className="p-6">
          <h3 className="font-semibold text-gray-800 mb-4 flex items-center gap-2">
            <Inbox size={18} />
            Anteprima Messaggi ({preview.total_unread} non letti)
          </h3>
          
          <div className="space-y-3 max-h-96 overflow-y-auto">
            {preview.messages.map((msg, i) => (
              <div 
                key={i}
                className={`p-4 rounded-lg border ${
                  msg.has_invoice ? "bg-green-50 border-green-200" : "bg-gray-50 border-gray-200"
                }`}
              >
                <div className="flex items-start justify-between gap-4">
                  <div className="flex-1 min-w-0">
                    <p className="font-medium text-gray-800 truncate">{msg.subject || "(Nessun oggetto)"}</p>
                    <p className="text-sm text-gray-500 truncate">{msg.from}</p>
                    <p className="text-xs text-gray-400">{msg.date}</p>
                  </div>
                  {msg.has_invoice && (
                    <div className="flex items-center gap-1 px-2 py-1 bg-green-100 text-green-700 rounded text-xs">
                      <FileText size={14} />
                      {msg.attachments.length} fattura/e
                    </div>
                  )}
                </div>
                {msg.attachments.length > 0 && (
                  <div className="mt-2 flex flex-wrap gap-2">
                    {msg.attachments.map((att, j) => (
                      <span key={j} className="px-2 py-1 bg-white border rounded text-xs text-gray-600">
                        {att}
                      </span>
                    ))}
                  </div>
                )}
              </div>
            ))}
            
            {preview.messages.length === 0 && (
              <p className="text-center text-gray-400 py-8">Nessun messaggio non letto</p>
            )}
          </div>
        </Card>
      )}

      {/* Risultato Import */}
      {importResult && (
        <Card className="p-6">
          <h3 className="font-semibold text-gray-800 mb-4 flex items-center gap-2">
            {importResult.imported_count > 0 ? (
              <CheckCircle className="text-green-600" size={20} />
            ) : (
              <AlertTriangle className="text-amber-600" size={20} />
            )}
            Risultato Importazione
          </h3>
          
          {/* Riepilogo 4 colonne */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
            <div className="p-4 bg-green-50 rounded-xl text-center border border-green-200">
              <p className="text-3xl font-bold text-green-600">{importResult.imported_count}</p>
              <p className="text-sm text-green-700 font-medium">Fatture Importate</p>
              <p className="text-xs text-green-500 mt-0.5">Nuove nel sistema</p>
            </div>
            <div className="p-4 bg-amber-50 rounded-xl text-center border border-amber-200">
              <p className="text-3xl font-bold text-amber-600">{importResult.skipped_already_present ?? importResult.skipped_count}</p>
              <p className="text-sm text-amber-700 font-medium">Già Presenti</p>
              <p className="text-xs text-amber-500 mt-0.5">Saltate (duplicati)</p>
            </div>
            <div className="p-4 bg-orange-50 rounded-xl text-center border border-orange-200">
              <p className="text-3xl font-bold text-orange-600">{importResult.skipped_excluded ?? 0}</p>
              <p className="text-sm text-orange-700 font-medium">Fornitori Esclusi</p>
              <p className="text-xs text-orange-500 mt-0.5">Ignorati da impostazioni</p>
            </div>
          </div>
          
          {/* Dettagli separati per categoria */}
          {importResult.details && importResult.details.length > 0 && (() => {
            const importate = importResult.details.filter(d => !d.reason);
            const saltate = importResult.details.filter(d => d.reason === 'Fattura già importata');
            const escluse = importResult.details.filter(d => d.reason && d.reason.includes('escluso'));
            
            return (
              <div className="space-y-4">
                {/* Importate */}
                {importate.length > 0 && (
                  <div>
                    <p className="text-sm font-semibold text-green-700 mb-2 flex items-center gap-1.5">
                      <CheckCircle size={14} /> Fatture importate ({importate.length})
                    </p>
                    <div className="space-y-1.5 max-h-48 overflow-y-auto">
                      {importate.map((d, i) => (
                        <div key={i} className="px-3 py-2 bg-green-50 rounded-lg border border-green-100 flex justify-between items-center text-sm">
                          <div>
                            <span className="font-medium text-gray-800">{d.fornitore}</span>
                            <span className="text-gray-500 ml-2 text-xs">N° {d.numero}</span>
                          </div>
                          <span className="text-green-600 text-xs">{d.totale_prodotti} prodotti · {d.materie_match} match</span>
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                {/* Già presenti */}
                {saltate.length > 0 && (
                  <div>
                    <p className="text-sm font-semibold text-amber-700 mb-2 flex items-center gap-1.5">
                      <AlertTriangle size={14} /> Già presenti — saltate ({saltate.length})
                    </p>
                    <div className="space-y-1 max-h-32 overflow-y-auto">
                      {saltate.map((d, i) => (
                        <div key={i} className="px-3 py-1.5 bg-amber-50 rounded-lg border border-amber-100 flex justify-between items-center text-xs text-amber-700">
                          <span className="font-medium">{d.fornitore}</span>
                          <span>N° {d.numero}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            );
          })()}

          {importResult.errors.length > 0 && (
            <div className="mt-4 p-4 bg-red-50 rounded-lg border border-red-200">
              <p className="text-sm font-medium text-red-700 mb-2">Errori tecnici ({importResult.errors.length}):</p>
              <ul className="text-sm text-red-600 space-y-1 max-h-32 overflow-y-auto">
                {importResult.errors.map((err, i) => (
                  <li key={i} className="flex items-start gap-1.5">
                    <span className="text-red-400 mt-0.5">•</span>{err}
                  </li>
                ))}
              </ul>
            </div>
          )}
        </Card>
      )}

      {/* ── PIPELINE STATUS ── */}
      <Card className="p-6 border-2 border-violet-100 bg-gradient-to-br from-violet-50 to-indigo-50">
        <div className="flex items-center justify-between flex-wrap gap-3">
          <div>
            <h3 className="font-semibold text-gray-800 flex items-center gap-2">
              <Zap size={18} className="text-violet-600" />
              Pipeline Automatica
            </h3>
            <p className="text-xs text-gray-500 mt-0.5">
              Aggiorna prezzi, food cost e prodotti in vendita dopo ogni import fatture
            </p>
          </div>
          <div className="flex items-center gap-3">
            {pipelineStatus && !pipelineStatus.mai_eseguita && (
              <div className="text-right text-xs text-gray-500">
                <p className="flex items-center gap-1 justify-end">
                  <Clock size={11} />
                  Ultima: {new Date(pipelineStatus.started_at).toLocaleString("it-IT")}
                </p>
                <p className="flex items-center gap-1 justify-end">
                  <TrendingUp size={11} className="text-green-500" />
                  {pipelineStatus.duration_ms}ms ·&nbsp;
                  {pipelineStatus.success
                    ? <span className="text-green-600 font-semibold">OK</span>
                    : <span className="text-red-600 font-semibold">{pipelineStatus.errori?.length} errori</span>
                  }
                </p>
              </div>
            )}
            <button
              onClick={eseguiPipeline}
              disabled={runningPipeline}
              className="px-4 py-2 bg-violet-600 text-white rounded-lg text-sm font-semibold flex items-center gap-2 hover:bg-violet-700 disabled:opacity-60 transition-colors"
              data-testid="esegui-pipeline-btn"
            >
              {runningPipeline
                ? <><RefreshCw size={15} className="animate-spin" /> Elaborazione...</>
                : <><Zap size={15} /> Esegui Ora</>
              }
            </button>
          </div>
        </div>

        {/* Step risultati ultima pipeline */}
        {pipelineStatus && !pipelineStatus.mai_eseguita && pipelineStatus.steps?.length > 0 && (
          <div className="mt-4 grid grid-cols-2 sm:grid-cols-4 gap-2">
            {[
              { key: "dizionario",       label: "Prezzi aggiornati",  icon: "💰", color: "blue" },
              { key: "food_cost",        label: "Ricette ricalcolate", icon: "🍽",  color: "green" },
              { key: "prodotti_vendita", label: "Prodotti sync",       icon: "🛒",  color: "amber" },
              { key: "semilavorati",     label: "Semilav. aggiornati", icon: "🏭",  color: "violet" },
            ].map(({ key, label, icon, color }) => {
              const step = pipelineStatus.steps?.find(s => s.step === key) || {};
              const val = step.aggiornati ?? step.ricette_aggiornate ?? step.con_costo ?? "—";
              const ok = step.success !== false && !step.error;
              return (
                <div key={key} className={`bg-white rounded-lg px-3 py-2 border ${ok ? "border-gray-200" : "border-red-200"}`}>
                  <p className="text-base">{icon}</p>
                  <p className="text-sm font-bold text-gray-800 mt-0.5">{ok ? val : "ERR"}</p>
                  <p className="text-xs text-gray-400">{label}</p>
                </div>
              );
            })}
          </div>
        )}
      </Card>

      {/* ── FATTURE IMPORTATE ── */}
      <Card className="p-6">
        <div
          className="flex items-center justify-between cursor-pointer"
          onClick={() => setShowFatture(v => !v)}
          data-testid="toggle-fatture-importate"
        >
          <h3 className="font-semibold text-gray-800 flex items-center gap-2">
            <Package size={18} className="text-indigo-600" />
            Fatture Importate nel Sistema
            <span className="ml-2 px-2 py-0.5 bg-indigo-100 text-indigo-700 rounded-full text-xs font-bold">
              {fattureImportate.length}
            </span>
          </h3>
          <div className="flex items-center gap-3">
            <button
              onClick={e => { e.stopPropagation(); loadFatture(); }}
              disabled={loadingFatture}
              className="px-3 py-1 bg-gray-100 text-gray-600 rounded-lg text-sm flex items-center gap-1 hover:bg-gray-200"
            >
              <RefreshCw size={14} className={loadingFatture ? "animate-spin" : ""} />
              Aggiorna
            </button>
            {showFatture ? <ChevronUp size={18} className="text-gray-400" /> : <ChevronDown size={18} className="text-gray-400" />}
          </div>
        </div>

        {showFatture && (
          <div className="mt-4">
            {/* Filtro fornitore */}
            <input
              type="text"
              placeholder="Filtra per fornitore..."
              value={filtroFornitore}
              onChange={e => setFiltroFornitore(e.target.value)}
              className="w-full px-3 py-2 border rounded-lg text-sm mb-4"
              data-testid="filtro-fornitore-fatture"
            />

            {loadingFatture ? (
              <div className="flex items-center gap-2 text-gray-400 py-4">
                <RefreshCw className="animate-spin" size={18} />
                Caricamento fatture...
              </div>
            ) : (
              <div className="overflow-x-auto">
                <table className="w-full text-sm" data-testid="tabella-fatture-importate">
                  <thead>
                    <tr className="bg-gray-50 border-b border-gray-200">
                      <th className="text-left px-3 py-2 font-semibold text-gray-600 w-8"></th>
                      <th className="text-left px-3 py-2 font-semibold text-gray-600">Fornitore</th>
                      <th className="text-left px-3 py-2 font-semibold text-gray-600">N° Fattura</th>
                      <th className="text-left px-3 py-2 font-semibold text-gray-600">Data</th>
                      <th className="text-right px-3 py-2 font-semibold text-gray-600">Prodotti</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-100">
                    {fattureImportate
                      .filter(f => !filtroFornitore || f.fornitore?.toLowerCase().includes(filtroFornitore.toLowerCase()))
                      .map((f, i) => (
                        <FatturaRow key={f.id || i} fattura={f} index={i} onFornitoreToggled={loadFatture} />
                      ))}
                  </tbody>
                </table>
                {fattureImportate.filter(f => !filtroFornitore || f.fornitore?.toLowerCase().includes(filtroFornitore.toLowerCase())).length === 0 && (
                  <p className="text-center text-gray-400 py-8">Nessuna fattura trovata</p>
                )}
              </div>
            )}
          </div>
        )}
      </Card>
    </div>
  );
};

export default PECImportView;
