import React, { useState, useEffect } from "react";
import axios from "axios";
import { toast } from "sonner";

import { ModalCambioFoto }    from "./tablet/ModalCambioFoto";
import { ModalRegistraLotto } from "./tablet/ModalRegistraLotto";
import { ModalAcquaviva }     from "./tablet/ModalAcquaviva";
import { ModalAlpha }         from "./tablet/ModalAlpha";
import CardProdotto           from "./tablet/CardProdotto";
import PannelloReparti        from "./tablet/PannelloReparti";

import { API } from "../../utils/constants";

// ==================== COMPONENTE PRINCIPALE TABLET ====================
export const TabletView = ({ reparto: repartoIniziale = "rosticceria", onBack }) => {
  const [reparto, setReparto]                   = useState(repartoIniziale);
  const [prodotti, setProdotti]                 = useState([]);
  const [loading, setLoading]                   = useState(true);
  const [search, setSearch]                     = useState("");
  const [prodottoSelezionato, setProdottoSelezionato] = useState(null);
  const [showAdmin, setShowAdmin]               = useState(false);
  const [ultimiLotti, setUltimiLotti]           = useState([]);
  const [cambiaFotoProdotto, setCambiaFotoProdotto] = useState(null);
  const [showAcquaviva, setShowAcquaviva]       = useState(false);
  const [showAlpha, setShowAlpha]               = useState(false);
  const [idConVarianti, setIdConVarianti]       = useState(new Set());
  const [venditeOggi, setVenditeOggi]           = useState([]);
  const [attrezzature, setAttrezzature]         = useState({ frigoriferi: [], congelatori: [] });

  const caricaProdotti = async () => {
    setLoading(true);
    try {
      const [resProdotti, resRicette] = await Promise.all([
        axios.get(`${API}/tablet/${reparto}`),
        axios.get(`${API}/ricette`)
      ]);
      setProdotti(resProdotti.data.prodotti || []);
      const tutteRicette = resRicette.data || [];
      const baseIds = new Set(tutteRicette.filter(r => r.ricetta_base_id).map(r => r.ricetta_base_id));
      setIdConVarianti(baseIds);
    } catch {
      toast.error("Errore caricamento prodotti");
    } finally {
      setLoading(false);
    }
  };

  const caricaUltimiLotti = async () => {
    try {
      const res = await axios.get(`${API}/lotti?limit=8`);
      setUltimiLotti(res.data.slice(0, 8));
    } catch {}
  };

  const caricaVenditeOggi = async () => {
    try {
      const res = await axios.get(`${API}/vendita-banco/oggi`);
      setVenditeOggi(res.data || []);
    } catch {}
  };

  const caricaAttrezzature = async () => {
    try {
      const res = await axios.get(`${API}/attrezzature/`);
      setAttrezzature({
        frigoriferi: res.data.frigoriferi || [],
        congelatori: res.data.congelatori || []
      });
    } catch {}
  };

  useEffect(() => {
    caricaProdotti();
    caricaUltimiLotti();
    caricaVenditeOggi();
    caricaAttrezzature();
  }, [reparto]);

  const prodottiFiltrati = [...prodotti]
    .filter(p => !search || p.nome?.toLowerCase().includes(search.toLowerCase()))
    .sort((a, b) => (a.nome || "").localeCompare(b.nome || "", "it"));

  const coloreHeader = reparto === "pasticceria"
    ? "linear-gradient(135deg, #f59e0b, #d97706)"
    : "linear-gradient(135deg, #3b82f6, #1d4ed8)";

  return (
    <div style={{ minHeight: "100vh", background: "#f8fafc", display: "flex", flexDirection: "column" }}>
      {/* Header */}
      <div style={{ background: coloreHeader, padding: "16px 20px", boxShadow: "0 4px 12px rgba(0,0,0,0.15)" }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 14 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            {onBack && (
              <button onClick={onBack} style={{
                background: "rgba(255,255,255,0.2)", border: "2px solid rgba(255,255,255,0.4)",
                color: "#fff", borderRadius: 10, padding: "7px 11px",
                fontWeight: 700, fontSize: 13, cursor: "pointer"
              }}>←</button>
            )}
            <div style={{ fontSize: 28 }}>{reparto === "pasticceria" ? "🍰" : "🥙"}</div>
            <div>
              <h1 style={{ color: "#fff", margin: 0, fontSize: 20, fontWeight: 800, textTransform: "capitalize", letterSpacing: "-0.5px" }}>
                {reparto === "pasticceria" ? "Pasticceria" : "Rosticceria"}
              </h1>
              <p style={{ color: "rgba(255,255,255,0.8)", margin: 0, fontSize: 12 }}>
                {prodotti.length} prodotti
              </p>
            </div>
          </div>
          <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
            <a href="#tablet/vendita" style={{
              padding: "8px 14px", borderRadius: 10,
              border: "2px solid rgba(255,165,0,0.7)",
              background: "rgba(249,115,22,0.25)", color: "#fff", fontWeight: 700,
              fontSize: 12, cursor: "pointer", textDecoration: "none",
              backdropFilter: "blur(4px)", display: "flex", alignItems: "center", gap: 5
            }} title="Apri tablet registro invenduto">
              🛒 Vendita
            </a>
            <button
              onClick={() => setReparto(reparto === "pasticceria" ? "rosticceria" : "pasticceria")}
              style={{
                padding: "8px 14px", borderRadius: 10, border: "2px solid rgba(255,255,255,0.5)",
                background: "rgba(255,255,255,0.15)", color: "#fff", fontWeight: 600,
                fontSize: 13, cursor: "pointer", backdropFilter: "blur(4px)"
              }}>
              {reparto === "pasticceria" ? "🥙 Rosticceria" : "🍰 Pasticceria"}
            </button>
            <button
              onClick={() => setShowAdmin(true)}
              style={{
                padding: "8px 10px", borderRadius: 10, border: "2px solid rgba(255,255,255,0.4)",
                background: "rgba(255,255,255,0.1)", color: "#fff", cursor: "pointer", fontSize: 16
              }}
              title="Gestione reparti">⚙</button>
          </div>
        </div>

        <div style={{ position: "relative" }}>
          <span style={{ position: "absolute", left: 14, top: "50%", transform: "translateY(-50%)", color: "rgba(255,255,255,0.7)", fontSize: 16 }}>🔍</span>
          <input
            type="text"
            placeholder={`Cerca prodotto ${reparto === "pasticceria" ? "dolce" : "salato"}...`}
            value={search}
            onChange={e => setSearch(e.target.value)}
            style={{
              width: "100%", padding: "12px 16px 12px 42px", borderRadius: 12, border: "none",
              background: "rgba(255,255,255,0.2)", color: "#fff", fontSize: 16,
              backdropFilter: "blur(8px)", outline: "none", boxSizing: "border-box"
            }}
          />
        </div>
      </div>

      {/* Griglia prodotti */}
      <div style={{ flex: 1, padding: "16px", overflowY: "auto" }}>
        {loading ? (
          <div style={{ textAlign: "center", padding: "60px 0", color: "#94a3b8", fontSize: 16 }}>
            Caricamento prodotti...
          </div>
        ) : prodottiFiltrati.length === 0 ? (
          <div style={{ textAlign: "center", padding: "60px 0", color: "#94a3b8" }}>
            <div style={{ fontSize: 48, marginBottom: 12 }}>🔍</div>
            <p style={{ fontSize: 16 }}>Nessun prodotto trovato</p>
          </div>
        ) : (
          <div style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fill, minmax(150px, 1fr))",
            gap: 12
          }}>
            {/* Card speciale Acquaviva — solo in pasticceria */}
            {reparto === "pasticceria" && (
              <div
                onClick={() => setShowAcquaviva(true)}
                style={{
                  borderRadius: 16, overflow: "hidden", cursor: "pointer",
                  boxShadow: "0 2px 12px rgba(146,64,14,0.2)",
                  border: "2px solid #92400e",
                  background: "linear-gradient(135deg, #fef3c7 0%, #fde68a 100%)",
                  display: "flex", flexDirection: "column",
                  minHeight: 100, userSelect: "none",
                  transition: "transform 0.12s, box-shadow 0.12s"
                }}
                onMouseDown={e => { e.currentTarget.style.transform = "scale(0.96)"; }}
                onMouseUp={e => { e.currentTarget.style.transform = "scale(1)"; }}
                onTouchStart={e => { e.currentTarget.style.transform = "scale(0.96)"; }}
                onTouchEnd={e => { e.currentTarget.style.transform = "scale(1)"; }}
              >
                <div style={{
                  flex: 1, display: "flex", flexDirection: "column",
                  alignItems: "center", justifyContent: "center",
                  padding: "14px 10px 8px", textAlign: "center"
                }}>
                  <p style={{ margin: "0 0 4px", fontSize: 22 }}>🏭</p>
                  <p style={{ margin: 0, fontWeight: 900, fontSize: 13, color: "#92400e", lineHeight: 1.2, letterSpacing: "-0.3px" }}>ACQUAVIVA</p>
                  <p style={{ margin: "2px 0 0", fontSize: 9, color: "#b45309", fontWeight: 600 }}>semilavorati</p>
                </div>
                <div style={{ background: "#92400e", padding: "5px 8px", textAlign: "center" }}>
                  <p style={{ margin: 0, fontSize: 10, color: "#fef3c7", fontWeight: 700 }}>tocca → catalogo</p>
                </div>
              </div>
            )}

            {/* Card speciale Progetto Alpha — solo in pasticceria */}
            {reparto === "pasticceria" && (
              <div
                onClick={() => setShowAlpha(true)}
                data-testid="card-progetto-alpha"
                style={{
                  borderRadius: 16, overflow: "hidden", cursor: "pointer",
                  boxShadow: "0 2px 12px rgba(5,150,105,0.2)",
                  border: "2px solid #059669",
                  background: "linear-gradient(135deg, #d1fae5 0%, #a7f3d0 100%)",
                  display: "flex", flexDirection: "column",
                  minHeight: 100, userSelect: "none",
                  transition: "transform 0.12s, box-shadow 0.12s"
                }}
                onMouseDown={e => { e.currentTarget.style.transform = "scale(0.96)"; }}
                onMouseUp={e => { e.currentTarget.style.transform = "scale(1)"; }}
                onTouchStart={e => { e.currentTarget.style.transform = "scale(0.96)"; }}
                onTouchEnd={e => { e.currentTarget.style.transform = "scale(1)"; }}
              >
                <div style={{
                  flex: 1, display: "flex", flexDirection: "column",
                  alignItems: "center", justifyContent: "center",
                  padding: "14px 10px 8px", textAlign: "center"
                }}>
                  <p style={{ margin: "0 0 4px", fontSize: 22 }}>🌿</p>
                  <p style={{ margin: 0, fontWeight: 900, fontSize: 13, color: "#065f46", lineHeight: 1.2, letterSpacing: "-0.3px" }}>PROGETTO<br/>ALPHA</p>
                  <p style={{ margin: "2px 0 0", fontSize: 9, color: "#059669", fontWeight: 600 }}>senza glutine</p>
                </div>
                <div style={{ background: "#059669", padding: "5px 8px", textAlign: "center" }}>
                  <p style={{ margin: 0, fontSize: 10, color: "#d1fae5", fontWeight: 700 }}>tocca → catalogo</p>
                </div>
              </div>
            )}

            {prodottiFiltrati.map(p => (
              <CardProdotto
                key={p.id}
                prodotto={p}
                reparto={reparto}
                onTap={setProdottoSelezionato}
                onCambiaFoto={prod => setCambiaFotoProdotto(prod)}
                hasVarianti={idConVarianti.has(p.id)}
              />
            ))}
          </div>
        )}
      </div>

      {/* Prodotti al Banco Oggi */}
      {venditeOggi.length > 0 && (
        <div style={{ background: "#fff", borderTop: "2px solid #d1fae5", padding: "12px 16px" }}>
          <p style={{ margin: "0 0 8px", fontSize: 11, fontWeight: 700, color: "#059669", textTransform: "uppercase", letterSpacing: "0.5px" }}>
            Al Banco Oggi — {venditeOggi.length} referenze
          </p>
          <div style={{ display: "flex", gap: 8, overflowX: "auto", paddingBottom: 4 }}>
            {venditeOggi.map(v => {
              const rimasti = (v.pezzi_prodotti || 0) - (v.pezzi_venduti || 0);
              return (
                <div key={v.id} style={{
                  flexShrink: 0, background: rimasti > 0 ? "#f0fdf4" : "#f9fafb",
                  border: `1px solid ${rimasti > 0 ? "#bbf7d0" : "#e5e7eb"}`,
                  borderRadius: 10, padding: "6px 12px", fontSize: 11
                }}>
                  <p style={{ margin: 0, fontWeight: 700, color: "#1e293b", whiteSpace: "nowrap", maxWidth: 120, overflow: "hidden", textOverflow: "ellipsis" }}>
                    {v.prodotto_nome}
                  </p>
                  <p style={{ margin: "2px 0 0", fontSize: 10, color: rimasti > 0 ? "#059669" : "#9ca3af" }}>
                    {rimasti} pz rimanenti
                  </p>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* Footer: ultimi lotti */}
      {ultimiLotti.length > 0 && (
        <div style={{ background: "#fff", borderTop: "1px solid #f1f5f9", padding: "10px 16px" }}>
          <p style={{ margin: "0 0 6px", fontSize: 11, fontWeight: 700, color: "#94a3b8", textTransform: "uppercase", letterSpacing: "0.5px" }}>
            Ultimi lotti registrati
          </p>
          <div style={{ display: "flex", gap: 8, overflowX: "auto", paddingBottom: 4 }}>
            {ultimiLotti.map(l => (
              <div key={l.id} style={{
                flexShrink: 0, background: "#f8fafc", border: "1px solid #e2e8f0",
                borderRadius: 8, padding: "4px 10px", fontSize: 11, whiteSpace: "nowrap"
              }}>
                <span style={{ fontWeight: 700, color: "#374151", textTransform: "capitalize" }}>{l.prodotto}</span>
                <span style={{ color: "#94a3b8", marginLeft: 6, fontFamily: "monospace", fontSize: 10 }}>{l.numero_lotto}</span>
                {l.frigo_numero && <span style={{ color: "#2563eb", marginLeft: 4 }}>• {l.frigo_numero}</span>}
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Modali */}
      {cambiaFotoProdotto && (
        <ModalCambioFoto
          prodotto={cambiaFotoProdotto}
          onClose={() => setCambiaFotoProdotto(null)}
          onSalvato={() => caricaProdotti()}
        />
      )}

      {prodottoSelezionato && (
        <ModalRegistraLotto
          prodotto={prodottoSelezionato}
          reparto={reparto}
          frigoriferi={attrezzature.frigoriferi}
          congelatori={attrezzature.congelatori}
          onClose={() => setProdottoSelezionato(null)}
          onHome={() => { setProdottoSelezionato(null); window.location.hash = ""; }}
          onSuccess={() => { setProdottoSelezionato(null); caricaUltimiLotti(); }}
        />
      )}

      {showAdmin && <PannelloReparti onClose={() => { setShowAdmin(false); caricaProdotti(); }} />}
      {showAcquaviva && <ModalAcquaviva onClose={() => setShowAcquaviva(false)} />}
      {showAlpha && <ModalAlpha onClose={() => setShowAlpha(false)} />}
    </div>
  );
};

export default TabletView;
