/**
 * TabCalcolatore.jsx — Calcolatore produzione di SchedaProdottoView
 */
import { useState, useEffect, useCallback, useMemo } from "react";
import axios from "axios";
import { toast } from "sonner";
import { Scale, PlayCircle, History, RefreshCw } from "lucide-react";
import { API } from "../../../utils/constants";
import { formatPeso, useAttrezzature } from "./utils";

const TabCalcolatore = ({ ricetta }) => {
  const [dettaglio, setDettaglio] = useState(null);
  const [loading, setLoading] = useState(false);
  const pezziBaseDefault = ricetta?.pezzi_ricetta_base || ricetta?.porzioni || 10;
  const [pezziBase, setPezziBase] = useState(pezziBaseDefault);
  const [pezziDaProdurre, setPezziDaProdurre] = useState(pezziBaseDefault);
  const [unitaProduzione, setUnitaProduzione] = useState("pz");
  const [frigoNumero, setFrigoNumero] = useState("");
  const [storico, setStorico] = useState([]);
  const attrezzature = useAttrezzature();

  const carica = useCallback(async () => {
    if (!ricetta?.id) return;
    setLoading(true);
    try {
      const [r1, r2] = await Promise.all([
        axios.get(`${API}/food-cost/calcola/${ricetta.id}`),
        axios.get(`${API}/produzioni/?ricetta_id=${ricetta.id}&limit=10`)
      ]);
      setDettaglio(r1.data);
      setStorico(r2.data || []);
      const base = ricetta.pezzi_ricetta_base || r1.data.porzioni || ricetta.porzioni || 10;
      setPezziBase(base);
      setPezziDaProdurre(base);
    } catch { toast.error("Errore caricamento"); }
    finally { setLoading(false); }
  }, [ricetta?.id, ricetta?.porzioni, ricetta?.pezzi_ricetta_base]);

  useEffect(() => { carica(); }, [carica]);

  const moltiplicatore = pezziBase > 0 ? pezziDaProdurre / pezziBase : 1;

  const pesoTotaleBase = useMemo(() => {
    if (!dettaglio?.ingredienti) return 0;
    return dettaglio.ingredienti.reduce((sum, ing) => {
      const qty = parseFloat(ing.quantita) || 0;
      const u = (ing.unita || "g").toLowerCase();
      if (u === "kg" || u === "lt" || u === "l") return sum + qty * 1000;
      return sum + qty;
    }, 0);
  }, [dettaglio]);

  const costoPerPezzo = dettaglio?.costo_totale > 0 && pezziBase > 0 ? dettaglio.costo_totale / pezziBase : 0;
  const costoTotProd = costoPerPezzo * pezziDaProdurre;

  const registra = async () => {
    if (!dettaglio) return;
    setLoading(true);
    try {
      const res = await axios.post(`${API}/registra-produzione-lotto`, null, {
        params: {
          ricetta_id: dettaglio.ricetta_id,
          pezzi: pezziDaProdurre,
          pezzi_base: pezziBase,
          costo_totale: costoTotProd,
          data_produzione: new Date().toISOString().split("T")[0],
          ...(frigoNumero ? { frigo_numero: frigoNumero } : {})
        }
      });
      const r = res.data;
      const nLotti = r.lotti_fornitori?.lotti_scalati?.length || 0;
      toast.success(`Lotto ${r.numero_lotto} — ${pezziDaProdurre} pz${nLotti > 0 ? ` | ${nLotti} lotti scalati` : ""}`, { duration: 5000 });
      const r2 = await axios.get(`${API}/produzioni/?ricetta_id=${ricetta.id}&limit=10`);
      setStorico(r2.data || []);
      window.dispatchEvent(new CustomEvent("haccp:lotti-changed"));
    } catch (e) {
      toast.error("Errore: " + (e.response?.data?.detail || e.message));
    } finally { setLoading(false); }
  };

  if (loading && !dettaglio) return <div className="flex items-center justify-center py-16 text-gray-400"><RefreshCw className="animate-spin mr-2" size={18} /> Caricamento...</div>;

  return (
    <div className="space-y-4">
      <div className="bg-gradient-to-br from-orange-400 to-orange-500 rounded-xl p-4 text-white space-y-3">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Scale size={18} />
            <span className="font-semibold">Calcolatore Produzione</span>
          </div>
          <span className="text-orange-200 text-sm">Peso base: {formatPeso(pesoTotaleBase)}</span>
        </div>

        <div className="bg-white/15 rounded-lg p-3">
          <div className="flex items-center justify-between mb-1">
            <label className="text-xs opacity-80">Ricetta base produce (pz)</label>
            <button
              onClick={async () => {
                try {
                  await axios.patch(`${API}/ricette/${ricetta.id}`, { pezzi_ricetta_base: pezziBase });
                  toast.success(`Ricetta base: ${pezziBase} pz salvati`);
                } catch { toast.error("Errore salvataggio"); }
              }}
              className="text-[10px] bg-white/20 hover:bg-white/40 text-white px-2 py-0.5 rounded-full font-semibold transition-colors"
            >
              Salva come base
            </button>
          </div>
          <input type="number" min="1" value={pezziBase}
            onChange={e => setPezziBase(Math.max(1, parseInt(e.target.value) || 1))}
            className="w-full mt-1 px-3 py-2 rounded-lg bg-white text-gray-800 font-bold text-center" />
        </div>

        <div className="bg-white/20 rounded-lg p-3 space-y-2">
          <div className="flex items-center justify-between">
            <label className="text-xs opacity-80">Voglio produrre</label>
            <div className="flex bg-black/20 rounded-lg p-0.5 gap-0.5">
              {["pz","kg"].map(u => (
                <button key={u} onClick={() => { setUnitaProduzione(u); setPezziDaProdurre(u === "kg" ? 1 : pezziBase); }}
                  className={`px-3 py-1 rounded-md text-xs font-bold transition-all ${unitaProduzione === u ? "bg-white text-orange-600 shadow" : "text-white/80 hover:text-white"}`}>
                  {u}
                </button>
              ))}
            </div>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={() => setPezziDaProdurre(v => unitaProduzione === "kg" ? Math.max(0.5, parseFloat((v-0.5).toFixed(1))) : Math.max(1, v-1))}
              className="w-10 h-10 rounded-lg bg-white/30 hover:bg-white/50 font-bold text-xl flex items-center justify-center">−</button>
            <input type="number" min={unitaProduzione === "kg" ? "0.5" : "1"} step={unitaProduzione === "kg" ? "0.5" : "1"}
              value={pezziDaProdurre}
              onChange={e => setPezziDaProdurre(unitaProduzione === "kg" ? parseFloat(e.target.value)||0.5 : Math.max(1,parseInt(e.target.value)||1))}
              className="flex-1 px-3 py-2 rounded-lg bg-white text-gray-800 font-bold text-center text-lg" />
            <button onClick={() => setPezziDaProdurre(v => unitaProduzione === "kg" ? parseFloat((v+0.5).toFixed(1)) : v+1)}
              className="w-10 h-10 rounded-lg bg-white/30 hover:bg-white/50 font-bold text-xl flex items-center justify-center">+</button>
          </div>
          <div className="flex flex-wrap gap-1">
            {(unitaProduzione === "kg" ? [0.5,1,2,3,5,10,20] : [5,10,15,20,25,50,100]).map(v => (
              <button key={v} onClick={() => setPezziDaProdurre(v)}
                className={`px-2 py-1 rounded text-xs font-bold ${pezziDaProdurre === v ? "bg-white text-orange-600" : "bg-white/20 hover:bg-white/40"}`}>
                {v}{unitaProduzione}
              </button>
            ))}
          </div>
          <p className="text-xs opacity-70">Moltiplicatore: ×{moltiplicatore.toFixed(1)} | Peso totale: {formatPeso(pesoTotaleBase * moltiplicatore)}</p>
        </div>

        <div className="grid grid-cols-2 gap-2">
          <div className="bg-white/20 rounded-lg p-3 text-center">
            <p className="text-xs opacity-80">Costo/pezzo</p>
            <p className="text-xl font-bold">€{costoPerPezzo.toFixed(3)}</p>
          </div>
          <div className="bg-white/30 rounded-lg p-3 text-center">
            <p className="text-xs opacity-80">Costo totale</p>
            <p className="text-xl font-bold">€{costoTotProd.toFixed(2)}</p>
          </div>
        </div>
      </div>

      <div className="space-y-2">
        <div>
          <label className="text-xs text-gray-500 font-medium mb-1 block">Luogo di stoccaggio</label>
          <select value={frigoNumero} onChange={e => setFrigoNumero(e.target.value)}
            className="w-full px-3 py-2 border border-gray-200 rounded-xl text-sm focus:ring-2 focus:ring-blue-400 focus:outline-none bg-white">
            <option value="">-- Nessun luogo specificato --</option>
            {attrezzature.frigoriferi.length > 0 && (
              <optgroup label="Frigoriferi (0°C / +4°C)">
                {attrezzature.frigoriferi.map(f => (
                  <option key={`f-${f.numero}`} value={f.nome}>{f.nome}</option>
                ))}
              </optgroup>
            )}
            {attrezzature.congelatori.length > 0 && (
              <optgroup label="Congelatori (-22°C / -18°C)">
                {attrezzature.congelatori.map(c => (
                  <option key={`c-${c.numero}`} value={c.nome}>{c.nome}</option>
                ))}
              </optgroup>
            )}
          </select>
        </div>
        <button onClick={registra} disabled={loading}
          className="w-full py-3.5 bg-blue-600 text-white rounded-xl font-semibold flex items-center justify-center gap-2 hover:bg-blue-700 transition-colors disabled:opacity-50">
          <PlayCircle size={20} />
          Registra Produzione ({pezziDaProdurre} {unitaProduzione})
          {frigoNumero && <span className="text-blue-300 text-sm">— {frigoNumero}</span>}
        </button>
      </div>

      {dettaglio?.ingredienti?.length > 0 && (
        <div className="bg-white border border-gray-100 rounded-xl overflow-hidden">
          <div className="px-4 py-2 bg-gray-50 border-b border-gray-100">
            <p className="text-xs font-semibold text-gray-600">Ingredienti per {pezziDaProdurre} {unitaProduzione} (×{moltiplicatore.toFixed(1)})</p>
          </div>
          <div className="divide-y divide-gray-50">
            {dettaglio.ingredienti.map((ing, i) => {
              const qBase = parseFloat(ing.quantita) || 0;
              const qScalata = qBase * moltiplicatore;
              return (
                <div key={i} className="flex items-center gap-3 px-4 py-2.5 text-sm">
                  <span className="flex-1 text-gray-700 capitalize">{ing.nome}</span>
                  <span className="text-gray-400">{qBase} {ing.unita || "g"}</span>
                  <span className="text-orange-600 font-semibold w-20 text-right">{qScalata.toFixed(1)} {ing.unita || "g"}</span>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {storico.length > 0 && (
        <div className="space-y-1.5">
          <p className="text-xs font-semibold text-gray-500 uppercase tracking-wide flex items-center gap-1"><History size={12} /> Ultime produzioni</p>
          {storico.slice(0, 5).map(p => {
            let dataDisplay = p.data || "";
            if (dataDisplay && !dataDisplay.includes("/")) {
              try { dataDisplay = new Date(dataDisplay).toLocaleDateString("it-IT", { day: "2-digit", month: "2-digit", year: "2-digit" }); } catch {}
            }
            return (
              <div key={p.id} className="flex items-center gap-3 px-3 py-2 bg-gray-50 rounded-xl text-sm border border-gray-100">
                <span className="text-gray-500">{dataDisplay}</span>
                <span className="flex-1 font-medium">{p.pezzi} pz</span>
                {p.numero_lotto && <span className="text-[10px] bg-blue-50 text-blue-600 px-1.5 py-0.5 rounded font-mono">{p.numero_lotto}</span>}
                <span className="text-green-600 font-bold">€{(p.costo_totale||0).toFixed(2)}</span>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default TabCalcolatore;
