import { useState, useEffect, useRef } from "react";
import { ShieldCheck, ChevronDown } from "lucide-react";

export function HACCPDropdown({ tabsHACCP, activeTab, onTabChange }) {
  const [open, setOpen] = useState(false);
  const ref = useRef(null);
  const isActive = tabsHACCP.some((t) => t.id === activeTab);

  useEffect(() => {
    const handler = (e) => {
      if (ref.current && !ref.current.contains(e.target)) setOpen(false);
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  return (
    <div ref={ref} className="relative flex-shrink-0">
      <button
        onClick={() => setOpen((o) => !o)}
        data-testid="haccp-dropdown-btn"
        className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg font-medium text-xs whitespace-nowrap transition-all ${
          isActive
            ? "bg-green-600 text-white shadow-md"
            : "bg-white text-gray-600 hover:bg-gray-100 border"
        }`}
      >
        <ShieldCheck size={14} />
        Conformità HACCP
        <ChevronDown size={11} className={`transition-transform ${open ? "rotate-180" : ""}`} />
      </button>
      {open && (
        <div className="absolute top-full left-0 mt-1 bg-white border border-gray-200 rounded-xl shadow-lg z-50 py-1 min-w-[200px]">
          {tabsHACCP.map((tab) => (
            <button
              key={tab.id}
              onClick={() => { onTabChange(tab.id); setOpen(false); }}
              data-testid={`haccp-menu-${tab.id}`}
              className={`w-full text-left px-4 py-2 text-sm flex items-center gap-2 hover:bg-gray-50 transition-colors ${
                activeTab === tab.id ? "text-green-700 font-semibold bg-green-50" : "text-gray-700"
              }`}
            >
              <tab.icon size={14} className={activeTab === tab.id ? "text-green-600" : tab.color} />
              {tab.label}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}
