import { useState, useCallback, useEffect } from "react";
import axios from "axios";
import { toast } from "sonner";
import { API } from "../utils/constants";

export function useLotti() {
  const [lotti, setLotti] = useState([]);
  const [searchLotti, setSearchLotti] = useState("");
  const [filtroDataDaLotti, setFiltroDataDaLotti] = useState("");
  const [filtroDataALotti, setFiltroDataALotti] = useState("");

  const fetchLotti = useCallback(async () => {
    try {
      const res = await axios.get(`${API}/lotti`, {
        params: {
          search: searchLotti || undefined,
          data_da: filtroDataDaLotti || undefined,
          data_a: filtroDataALotti || undefined,
        },
      });
      setLotti(res.data);
    } catch (e) {
      console.error("Errore lotti:", e);
    }
  }, [searchLotti, filtroDataDaLotti, filtroDataALotti]);

  useEffect(() => {
    const timer = setTimeout(() => fetchLotti(), 300);
    return () => clearTimeout(timer);
  }, [searchLotti, filtroDataDaLotti, filtroDataALotti, fetchLotti]);

  const handleDeleteLotto = async (id) => {
    if (!id || id === "__refresh__") {
      await fetchLotti();
      window.dispatchEvent(new CustomEvent("haccp:lotti-changed"));
      return;
    }
    try {
      await axios.delete(`${API}/lotti/${id}`);
      toast.success("Lotto eliminato");
      await fetchLotti();
      window.dispatchEvent(new CustomEvent("haccp:lotti-changed"));
    } catch (e) {
      toast.error("Errore nell'eliminazione: " + (e.response?.data?.detail || e.message));
    }
  };

  const handleGeneraLotto = async (ricetta, dataProduzione, dataScadenza, moltiplicatore, note, frigoNumero) => {
    try {
      const params = {
        ricetta_nome: ricetta.nome,
        data_produzione: dataProduzione || new Date().toISOString().split("T")[0],
        data_scadenza: dataScadenza || "",
        moltiplicatore: moltiplicatore || 1,
        frigo_numero: frigoNumero || 1,
        note: note || "",
      };
      const res = await axios.post(`${API}/registra-produzione-lotto`, null, { params });
      toast.success(`Lotto ${res.data?.numero_lotto || ""} creato`);
      await fetchLotti();
    } catch (e) {
      toast.error("Errore creazione lotto: " + (e.response?.data?.detail || e.message));
    }
  };

  return {
    lotti,
    searchLotti,
    setSearchLotti,
    filtroDataDaLotti,
    setFiltroDataDaLotti,
    filtroDataALotti,
    setFiltroDataALotti,
    fetchLotti,
    handleDeleteLotto,
    handleGeneraLotto,
  };
}
