/**
 * TabLotti.jsx — Tab Lotti & Recall di SchedaProdottoView
 */
import { useState, useEffect, useCallback } from "react";
import axios from "axios";
import { toast } from "sonner";
import { AlertTriangle, Layers, ChevronRight, Search, Snowflake, Thermometer, RefreshCw } from "lucide-react";
import { API } from "../../../utils/constants";

const StorageIcon = ({ frigo }) => {
  if (!frigo) return null;
  const isCongelatore = /congelat|freezer|surgelat/i.test(frigo);
  return isCongelatore
    ? <span className="flex items-center gap-0.5 text-cyan-600"><Snowflake size={11} /> {frigo}</span>
    : <span className="flex items-center gap-0.5 text-orange-600"><Thermometer size={11} /> {frigo}</span>;
};

const TabLotti = ({ ricetta, onNavigateToLotti }) => {
  const [lotti, setLotti] = useState([]);
  const [loading, setLoading] = useState(false);
  const [recallIng, setRecallIng] = useState("");
  const [recallResult, setRecallResult] = useState(null);
  const [recallLoading, setRecallLoading] = useState(false);
  const [recallMesi, setRecallMesi] = useState(2);

  const carica = useCallback(async () => {
    if (!ricetta?.nome) return;
    setLoading(true);
    try {
      const r = await axios.get(`${API}/lotti`, { params: { search: ricetta.nome, limit: 20 } });
      setLotti(r.data || []);
    } catch { toast.error("Errore caricamento lotti"); }
    finally { setLoading(false); }
  }, [ricetta?.nome]);

  useEffect(() => { carica(); }, [carica]);

  const cercaRecall = async () => {
    if (!recallIng.trim()) return;
    setRecallLoading(true);
    try {
      const r = await axios.get(`${API}/lotti/recall/cerca`, {
        params: { ingrediente: recallIng, mesi: recallMesi }
      });
      setRecallResult(r.data);
    } catch { toast.error("Errore recall"); }
    finally { setRecallLoading(false); }
  };

  if (loading) return <div className="flex items-center justify-center py-16 text-gray-400"><RefreshCw className="animate-spin mr-2" size={18} /> Caricamento...</div>;

  return (
    <div className="space-y-4">
      <div>
        <div className="flex items-center justify-between mb-2">
          <p className="text-xs font-semibold text-gray-500 uppercase tracking-wide">Lotti produzione ({lotti.length})</p>
          <button onClick={() => onNavigateToLotti && onNavigateToLotti()}
            className="text-xs text-blue-600 hover:text-blue-800 flex items-center gap-1">
            Vedi tutti <ChevronRight size={12} />
          </button>
        </div>
        {lotti.length === 0 ? (
          <div className="text-center py-8 text-gray-400">
            <Layers size={32} className="mx-auto mb-2 opacity-30" />
            <p className="text-sm">Nessun lotto per questa ricetta</p>
          </div>
        ) : (
          <div className="space-y-2">
            {lotti.slice(0, 8).map(l => (
              <div key={l.id} className="flex items-center gap-3 px-3 py-2.5 bg-gray-50 rounded-xl border border-gray-100 text-sm">
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2">
                    <span className="font-mono text-xs bg-blue-50 text-blue-700 px-2 py-0.5 rounded">{l.numero_lotto}</span>
                    <span className="text-gray-700 truncate">{l.prodotto}</span>
                  </div>
                  <div className="flex items-center gap-3 mt-0.5 text-xs text-gray-400 flex-wrap">
                    <span>Prod: {l.data_produzione}</span>
                    <span>Scad: {l.data_scadenza}</span>
                    {l.frigo_numero && <StorageIcon frigo={l.frigo_numero} />}
                  </div>
                </div>
                <span className="text-orange-600 font-semibold flex-shrink-0">{l.quantita} pz</span>
              </div>
            ))}
          </div>
        )}
      </div>

      <div className="bg-red-50 border border-red-200 rounded-xl p-4 space-y-3">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <AlertTriangle size={16} className="text-red-600" />
            <p className="text-sm font-semibold text-red-800">Recall Ingrediente (Reg. CE 178/2002)</p>
          </div>
          <div className="flex items-center gap-1">
            <span className="text-xs text-red-600">Ultimi</span>
            <select value={recallMesi} onChange={e => setRecallMesi(Number(e.target.value))}
              className="text-xs px-1.5 py-0.5 border border-red-200 rounded bg-white text-red-700 font-semibold">
              <option value={1}>1 mese</option>
              <option value={2}>2 mesi</option>
              <option value={3}>3 mesi</option>
              <option value={6}>6 mesi</option>
              <option value={12}>12 mesi</option>
            </select>
          </div>
        </div>

        <div className="flex gap-2">
          <input type="text" value={recallIng} onChange={e => setRecallIng(e.target.value)}
            onKeyDown={e => e.key === "Enter" && cercaRecall()}
            placeholder="Es. olio d'oliva, SAIMA farina..."
            className="flex-1 px-3 py-2 border border-red-200 rounded-xl text-sm bg-white focus:ring-2 focus:ring-red-400 focus:outline-none" />
          <button onClick={cercaRecall} disabled={recallLoading}
            className="px-4 py-2 bg-red-600 text-white rounded-xl text-sm font-medium hover:bg-red-700 disabled:opacity-50 flex items-center gap-1.5">
            {recallLoading ? <RefreshCw size={14} className="animate-spin" /> : <Search size={14} />} Cerca
          </button>
        </div>

        {recallResult && (
          <div className="space-y-2">
            <p className="text-xs font-semibold text-red-700">
              {recallResult.lotti?.length || 0} lotti coinvolti per: <em>{recallIng}</em>
              <span className="ml-2 text-red-500 font-normal">(ultimi {recallMesi} mesi)</span>
            </p>
            {(recallResult.lotti || []).slice(0, 8).map((l, i) => (
              <div key={i} className="flex items-center gap-2 px-3 py-2 bg-white border border-red-100 rounded-lg text-xs">
                <span className="font-mono text-red-600">{l.numero_lotto}</span>
                <span className="flex-1 text-gray-700">{l.prodotto}</span>
                {l.frigo_numero && (
                  <span className="text-[10px] bg-blue-50 text-blue-600 px-1.5 py-0.5 rounded flex items-center gap-0.5">
                    <Thermometer size={8} /> {l.frigo_numero}
                  </span>
                )}
                <span className="text-gray-400">{l.data_scadenza}</span>
              </div>
            ))}
            {(recallResult.lotti || []).length > 8 && (
              <p className="text-xs text-gray-400 text-center">…e altri {recallResult.lotti.length - 8} lotti</p>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default TabLotti;
