import { useState, useEffect } from "react";
import axios from "axios";
import { API } from "../../../utils/constants";

const BADGE = [
  { key: "kcal",   label: "Calorie",      unit: "kcal", color: "#ef4444", bg: "#fef2f2" },
  { key: "prot",   label: "Proteine",     unit: "g",    color: "#3b82f6", bg: "#eff6ff" },
  { key: "carb",   label: "Carboidrati",  unit: "g",    color: "#f59e0b", bg: "#fffbeb" },
  { key: "grassi", label: "Grassi",       unit: "g",    color: "#8b5cf6", bg: "#f5f3ff" },
];

export default function TabNutrizionali({ ricettaId }) {
  const [dati, setDati]     = useState(null);
  const [loading, setLoading] = useState(true);
  const [errore, setErrore]  = useState(null);

  useEffect(() => {
    if (!ricettaId) return;
    setLoading(true);
    setErrore(null);
    axios.get(`${API}/ricette/${ricettaId}/nutrizionali`)
      .then(r => setDati(r.data))
      .catch(() => setErrore("Impossibile calcolare i valori nutrizionali per questa ricetta."))
      .finally(() => setLoading(false));
  }, [ricettaId]);

  if (loading) return (
    <div style={{ padding: 40, textAlign: "center", color: "#94a3b8" }}>Calcolo in corso...</div>
  );

  if (errore) return (
    <div style={{ padding: 20, color: "#dc2626", background: "#fef2f2", borderRadius: 10, margin: 16 }}>{errore}</div>
  );

  if (!dati) return null;

  const copertura = dati.ingredienti_totali > 0
    ? Math.round((dati.ingredienti_coperti / dati.ingredienti_totali) * 100)
    : 0;

  return (
    <div style={{ padding: "16px 0" }}>
      {/* Intestazione */}
      <div style={{ marginBottom: 16, padding: "0 4px" }}>
        <p style={{ margin: 0, fontSize: 13, fontWeight: 700, color: "#374151" }}>
          Valori Nutrizionali per Porzione
        </p>
        <p style={{ margin: "2px 0 0", fontSize: 11, color: "#94a3b8" }}>
          Stima su {dati.ingredienti_coperti}/{dati.ingredienti_totali} ingredienti mappati ({copertura}% copertura) · {dati.porzioni} pz/ricetta
        </p>
      </div>

      {/* 4 badge grandi */}
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginBottom: 16 }}>
        {BADGE.map(b => {
          const val = dati.per_porzione?.[b.key] ?? 0;
          return (
            <div key={b.key} style={{
              background: b.bg,
              border: `1.5px solid ${b.color}30`,
              borderRadius: 12,
              padding: "12px 14px",
              textAlign: "center",
            }}>
              <p style={{ margin: 0, fontSize: 22, fontWeight: 800, color: b.color }}>
                {val.toFixed(1)}
              </p>
              <p style={{ margin: "2px 0 0", fontSize: 10, fontWeight: 700, color: b.color, opacity: 0.8, textTransform: "uppercase", letterSpacing: "0.5px" }}>
                {b.unit}
              </p>
              <p style={{ margin: "2px 0 0", fontSize: 11, color: "#6b7280" }}>
                {b.label}
              </p>
            </div>
          );
        })}
      </div>

      {/* Barra macro */}
      {(() => {
        const p = dati.per_porzione || {};
        const protKcal = (p.prot   || 0) * 4;
        const carbKcal = (p.carb   || 0) * 4;
        const fatKcal  = (p.grassi || 0) * 9;
        const totMacro = protKcal + carbKcal + fatKcal || 1;
        return (
          <div style={{ marginBottom: 16 }}>
            <p style={{ margin: "0 0 6px", fontSize: 11, fontWeight: 700, color: "#64748b" }}>
              Distribuzione macronutrienti
            </p>
            <div style={{ display: "flex", borderRadius: 8, overflow: "hidden", height: 18 }}>
              <div style={{ width: `${Math.round(protKcal/totMacro*100)}%`, background: "#3b82f6" }} title={`Proteine ${Math.round(protKcal/totMacro*100)}%`} />
              <div style={{ width: `${Math.round(carbKcal/totMacro*100)}%`, background: "#f59e0b" }} title={`Carboidrati ${Math.round(carbKcal/totMacro*100)}%`} />
              <div style={{ width: `${Math.round(fatKcal/totMacro*100)}%`,  background: "#8b5cf6" }} title={`Grassi ${Math.round(fatKcal/totMacro*100)}%`} />
            </div>
            <div style={{ display: "flex", gap: 12, marginTop: 4 }}>
              {[
                { label: "Prot", pct: Math.round(protKcal/totMacro*100), color: "#3b82f6" },
                { label: "Carb", pct: Math.round(carbKcal/totMacro*100), color: "#f59e0b" },
                { label: "Gras", pct: Math.round(fatKcal/totMacro*100),  color: "#8b5cf6" },
              ].map(m => (
                <span key={m.label} style={{ fontSize: 10, color: m.color, fontWeight: 700 }}>
                  {m.label} {m.pct}%
                </span>
              ))}
            </div>
          </div>
        );
      })()}

      {/* Dettaglio per ingrediente */}
      {dati.dettaglio?.length > 0 && (
        <div>
          <p style={{ margin: "0 0 8px", fontSize: 11, fontWeight: 700, color: "#64748b" }}>
            Dettaglio ingredienti calcolati
          </p>
          <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
            {dati.dettaglio.sort((a, b) => b.kcal - a.kcal).map((ing, i) => (
              <div key={i} style={{
                display: "flex", justifyContent: "space-between", alignItems: "center",
                padding: "5px 10px", background: "#f8fafc", borderRadius: 7,
                fontSize: 12,
              }}>
                <span style={{ color: "#374151", textTransform: "capitalize", fontWeight: 500 }}>{ing.nome}</span>
                <span style={{ color: "#64748b" }}>{ing.grammi}g</span>
                <span style={{ color: "#ef4444", fontWeight: 700 }}>{ing.kcal} kcal</span>
              </div>
            ))}
          </div>
        </div>
      )}

      <p style={{ margin: "12px 0 0", fontSize: 10, color: "#cbd5e1", textAlign: "center" }}>
        {dati.nota}
      </p>
    </div>
  );
}
