import { useState, useEffect } from "react";
import axios from "axios";
import { toast } from "sonner";
import {
  Clock,
  Play,
  Pause,
  RefreshCw,
  CheckCircle,
  XCircle,
  Calendar,
  Mail,
  Thermometer,
  Settings
} from "lucide-react";
import { API } from "../../utils/constants";

const Card = ({ children, className = "" }) => (
  <div className={`bg-white rounded-xl shadow-sm border border-gray-100 ${className}`}>
    {children}
  </div>
);

export const SchedulerView = () => {
  const [status, setStatus] = useState(null);
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(false);

  const fetchStatus = async () => {
    try {
      const res = await axios.get(`${API}/scheduler/status`);
      setStatus(res.data);
    } catch (e) {
      console.error(e);
    }
  };

  const fetchLogs = async () => {
    try {
      const res = await axios.get(`${API}/scheduler/logs?limit=20`);
      setLogs(res.data || []);
    } catch (e) {
      console.error(e);
    }
  };

  useEffect(() => {
    fetchStatus();
    fetchLogs();
    
    // Aggiorna ogni 30 secondi
    const interval = setInterval(() => {
      fetchStatus();
      fetchLogs();
    }, 30000);
    
    return () => clearInterval(interval);
  }, []);

  const runPecNow = async () => {
    setLoading(true);
    try {
      await axios.post(`${API}/scheduler/run-pec-now`);
      toast.success("Import PEC avviato");
      setTimeout(() => {
        fetchStatus();
        fetchLogs();
      }, 2000);
    } catch (e) {
      toast.error("Errore: " + (e.response?.data?.detail || e.message));
    } finally {
      setLoading(false);
    }
  };

  const runHaccpNow = async () => {
    setLoading(true);
    try {
      await axios.post(`${API}/scheduler/run-haccp-now`);
      toast.success("Generazione HACCP avviata");
      setTimeout(() => {
        fetchStatus();
        fetchLogs();
      }, 2000);
    } catch (e) {
      toast.error("Errore: " + (e.response?.data?.detail || e.message));
    } finally {
      setLoading(false);
    }
  };

  const formatDate = (dateStr) => {
    if (!dateStr) return "-";
    try {
      const d = new Date(dateStr);
      return d.toLocaleString('it-IT', { 
        day: '2-digit', month: '2-digit', year: 'numeric',
        hour: '2-digit', minute: '2-digit'
      });
    } catch {
      return dateStr;
    }
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex justify-between items-start flex-wrap gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-800 flex items-center gap-3">
            <Clock className="text-indigo-600" size={28} />
            Scheduler Automatico
          </h2>
          <p className="text-gray-500 mt-1">Task automatici notturni per PEC e HACCP</p>
        </div>
        <button
          onClick={() => { fetchStatus(); fetchLogs(); }}
          className="px-4 py-2 bg-gray-100 text-gray-700 rounded-lg flex items-center gap-2 hover:bg-gray-200"
        >
          <RefreshCw size={18} />
          Aggiorna
        </button>
      </div>

      {/* Stato Generale */}
      <Card className="p-6">
        <div className="flex items-center justify-between mb-4">
          <h3 className="font-semibold text-gray-800 flex items-center gap-2">
            <Settings size={18} />
            Stato Scheduler
          </h3>
          {status?.running ? (
            <span className="px-3 py-1 bg-green-100 text-green-700 rounded-full text-sm flex items-center gap-1">
              <CheckCircle size={14} />
              Attivo
            </span>
          ) : (
            <span className="px-3 py-1 bg-red-100 text-red-700 rounded-full text-sm flex items-center gap-1">
              <XCircle size={14} />
              Inattivo
            </span>
          )}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {status?.jobs?.map((job) => (
            <div key={job.id} className="p-4 bg-gray-50 rounded-lg">
              <div className="flex items-center gap-3 mb-2">
                {job.id.includes('pec') ? (
                  <Mail className="text-blue-600" size={20} />
                ) : (
                  <Thermometer className="text-orange-600" size={20} />
                )}
                <span className="font-medium">{job.name}</span>
              </div>
              <p className="text-sm text-gray-600">
                Prossima esecuzione: <span className="font-medium">{formatDate(job.next_run)}</span>
              </p>
              <p className="text-xs text-gray-400 mt-1">
                Trigger: {job.trigger}
              </p>
            </div>
          ))}
        </div>
      </Card>

      {/* Esecuzione Manuale */}
      <Card className="p-6">
        <h3 className="font-semibold text-gray-800 mb-4 flex items-center gap-2">
          <Play size={18} />
          Esecuzione Manuale
        </h3>
        
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <button
            onClick={runPecNow}
            disabled={loading}
            className="p-4 bg-blue-50 hover:bg-blue-100 rounded-lg text-left transition-colors disabled:opacity-50"
          >
            <div className="flex items-center gap-3 mb-2">
              <Mail className="text-blue-600" size={24} />
              <span className="font-semibold text-blue-800">Import PEC Ora</span>
            </div>
            <p className="text-sm text-blue-600">
              Importa subito le nuove fatture dalla casella PEC
            </p>
          </button>
          
          <button
            onClick={runHaccpNow}
            disabled={loading}
            className="p-4 bg-orange-50 hover:bg-orange-100 rounded-lg text-left transition-colors disabled:opacity-50"
          >
            <div className="flex items-center gap-3 mb-2">
              <Thermometer className="text-orange-600" size={24} />
              <span className="font-semibold text-orange-800">Genera HACCP Ora</span>
            </div>
            <p className="text-sm text-orange-600">
              Genera i dati HACCP per oggi (temperature, sanificazione)
            </p>
          </button>
        </div>
      </Card>

      {/* Log Recenti */}
      <Card className="p-6">
        <h3 className="font-semibold text-gray-800 mb-4 flex items-center gap-2">
          <Calendar size={18} />
          Log Recenti
        </h3>
        
        {logs.length > 0 ? (
          <div className="space-y-2 max-h-64 overflow-y-auto">
            {logs.map((log, i) => (
              <div 
                key={i}
                className={`p-3 rounded-lg text-sm flex items-center justify-between ${
                  log.success ? "bg-green-50" : "bg-red-50"
                }`}
              >
                <div className="flex items-center gap-3">
                  {log.success ? (
                    <CheckCircle className="text-green-600" size={16} />
                  ) : (
                    <XCircle className="text-red-600" size={16} />
                  )}
                  <div>
                    <span className="font-medium">
                      {log.job === 'pec_import' ? 'Import PEC' : 'HACCP Giornaliero'}
                    </span>
                    {log.imported !== undefined && (
                      <span className="text-gray-500 ml-2">
                        ({log.imported} importate, {log.skipped} saltate)
                      </span>
                    )}
                    {log.error && (
                      <span className="text-red-600 ml-2">{log.error}</span>
                    )}
                  </div>
                </div>
                <span className="text-gray-400 text-xs">
                  {formatDate(log.timestamp)}
                </span>
              </div>
            ))}
          </div>
        ) : (
          <p className="text-center text-gray-400 py-8">
            Nessun log disponibile. I log appariranno dopo la prima esecuzione.
          </p>
        )}
      </Card>
    </div>
  );
};

export default SchedulerView;
