import React, { useState, useEffect } from "react";
import axios from "axios";
import { toast } from "sonner";
import ColazioneAcquavivaView from "../ColazioneAcquavivaView";
import { API } from "../../../utils/constants";

export function ModalAcquaviva({ onClose }) {
  const [prodotti, setProdotti] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [categoria, setCategoria] = useState("tutti");
  const [categorie, setCategorie] = useState([]);
  const [prodottoVendita, setProdottoVendita] = useState(null);
  const [pezziVendita, setPezziVendita] = useState(1);
  const [saving, setSaving] = useState(false);
  const [mostraColazione, setMostraColazione] = useState(false);

  useEffect(() => {
    const load = async () => {
      try {
        const [pr, cat] = await Promise.all([
          axios.get(`${API}/acquaviva/prodotti`),
          axios.get(`${API}/acquaviva/categorie`)
        ]);
        setProdotti(pr.data);
        setCategorie(cat.data);
      } catch { toast.error("Errore caricamento prodotti Acquaviva"); }
      setLoading(false);
    };
    load();
  }, []);

  const catPrincipali = ["tutti", ...new Set(
    categorie.map(c => c.split(">")[0].trim()).filter(Boolean)
  )];

  const filtrati = prodotti
    .filter(p => !search || p.nome.toLowerCase().includes(search.toLowerCase()))
    .filter(p => categoria === "tutti" || p.categoria?.includes(categoria))
    .sort((a, b) => a.nome.localeCompare(b.nome, "it"));

  const registraVendita = async () => {
    if (!prodottoVendita || pezziVendita < 1) return;
    setSaving(true);
    try {
      await axios.post(`${API}/acquaviva/registra-vendita`, null, {
        params: {
          prodotto_id: prodottoVendita.id,
          pezzi_messi_in_vendita: pezziVendita,
          pezzi_venduti: 0
        }
      });
      toast.success(`${pezziVendita} pz "${prodottoVendita.nome}" messi in vendita`);
      setProdottoVendita(null);
      setPezziVendita(1);
    } catch (e) {
      toast.error("Errore registrazione: " + (e.response?.data?.detail || e.message));
    }
    setSaving(false);
  };

  return (
    <div style={{
      position: "fixed", inset: 0, zIndex: 9999,
      background: "rgba(0,0,0,0.7)", display: "flex", flexDirection: "column"
    }}>
      {mostraColazione && (
        <ColazioneAcquavivaView
          modoTablet={true}
          onClose={() => { setMostraColazione(false); onClose(); }}
        />
      )}

      <div style={{
        background: "linear-gradient(135deg, #92400e, #b45309)",
        padding: "16px 20px",
        display: "flex", alignItems: "center", justifyContent: "space-between"
      }}>
        <div>
          <h2 style={{ color: "#fff", margin: 0, fontSize: 20, fontWeight: 800 }}>Dolciaria Acquaviva</h2>
          <p style={{ color: "rgba(255,255,255,0.75)", margin: 0, fontSize: 12 }}>
            {filtrati.length} prodotti semilavorati
          </p>
        </div>
        <div style={{ display: "flex", gap: 8 }}>
          <button
            onClick={() => setMostraColazione(true)}
            data-testid="avvia-colazione-btn"
            style={{
              background: "linear-gradient(135deg, #fbbf24, #f59e0b)",
              border: "none", color: "#78350f", borderRadius: 10, padding: "8px 14px",
              fontWeight: 800, cursor: "pointer", fontSize: 13,
              display: "flex", alignItems: "center", gap: 6
            }}>
            Colazione
          </button>
          <button onClick={() => { setProdottoVendita(null); setPezziVendita(1); setSaving(false); onClose(); }}
            style={{
              background: "rgba(255,255,255,0.2)", border: "2px solid rgba(255,255,255,0.4)",
              color: "#fff", borderRadius: 10, padding: "8px 14px", fontWeight: 700, cursor: "pointer"
            }}>✕ Chiudi</button>
        </div>
      </div>

      <div style={{ background: "#fff", padding: "12px 16px", borderBottom: "1px solid #e5e7eb" }}>
        <input type="text" placeholder="Cerca prodotto..."
          value={search} onChange={e => setSearch(e.target.value)}
          style={{
            width: "100%", padding: "10px 16px", borderRadius: 10,
            border: "2px solid #d1d5db", fontSize: 16, outline: "none", boxSizing: "border-box"
          }} />
        <div style={{ display: "flex", gap: 6, marginTop: 8, overflowX: "auto", paddingBottom: 2 }}>
          {catPrincipali.map(c => (
            <button key={c} onClick={() => setCategoria(c)}
              style={{
                padding: "4px 12px", borderRadius: 20, border: "2px solid",
                borderColor: categoria === c ? "#92400e" : "#e5e7eb",
                background: categoria === c ? "#92400e" : "#fff",
                color: categoria === c ? "#fff" : "#6b7280",
                fontSize: 12, fontWeight: 700, cursor: "pointer", whiteSpace: "nowrap", flexShrink: 0
              }}>
              {c === "tutti" ? "Tutti" : c}
            </button>
          ))}
        </div>
      </div>

      <div style={{ flex: 1, overflowY: "auto", padding: 16, background: "#f9fafb" }}>
        {loading ? (
          <div style={{ textAlign: "center", padding: 40, color: "#9ca3af" }}>Caricamento...</div>
        ) : (
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(140px, 1fr))", gap: 10 }}>
            {filtrati.map(prod => (
              <div key={prod.id}
                onClick={() => { setProdottoVendita(prod); setPezziVendita(prod.pz_confezione || 1); }}
                style={{
                  background: "#fff", borderRadius: 12, overflow: "hidden",
                  border: "2px solid #f3f4f6", cursor: "pointer",
                  boxShadow: "0 2px 8px rgba(0,0,0,0.06)",
                  transition: "transform 0.12s, box-shadow 0.12s"
                }}
                onMouseDown={e => { e.currentTarget.style.transform = "scale(0.96)"; }}
                onMouseUp={e => { e.currentTarget.style.transform = "scale(1)"; }}
                onTouchStart={e => { e.currentTarget.style.transform = "scale(0.96)"; }}
                onTouchEnd={e => { e.currentTarget.style.transform = "scale(1)"; }}
              >
                <div style={{ height: 100, overflow: "hidden", background: "#f3f4f6" }}>
                  {prod.foto_url ? (
                    <img src={prod.foto_url} alt={prod.nome}
                      style={{ width: "100%", height: "100%", objectFit: "cover" }}
                      onError={e => { e.target.style.display = "none"; }} />
                  ) : (
                    <div style={{ height: "100%", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 36 }}>🥐</div>
                  )}
                </div>
                <div style={{ padding: "8px 8px 6px" }}>
                  <p style={{
                    margin: 0, fontSize: 11, fontWeight: 700, color: "#1e293b",
                    textTransform: "capitalize", lineHeight: 1.25,
                    display: "-webkit-box", WebkitLineClamp: 2,
                    WebkitBoxOrient: "vertical", overflow: "hidden"
                  }}>{prod.nome}</p>
                  {prod.allergeni?.length > 0 && (
                    <p style={{ margin: "3px 0 0", fontSize: 9, color: "#d97706", fontWeight: 600 }}>
                      ⚠ {prod.allergeni.slice(0,2).join(", ")}
                    </p>
                  )}
                  {prod.prezzo_singolo > 0 && (
                    <p style={{ margin: "2px 0 0", fontSize: 10, color: "#059669", fontWeight: 700 }}>
                      €{prod.prezzo_singolo.toFixed(3)}/pz
                    </p>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {prodottoVendita && (
        <div style={{
          position: "absolute", inset: 0, background: "rgba(0,0,0,0.6)",
          display: "flex", alignItems: "flex-end", justifyContent: "center"
        }} onClick={e => { if (e.target === e.currentTarget) { setProdottoVendita(null); setPezziVendita(1); } }}>
          <div style={{
            background: "#fff", borderRadius: "20px 20px 0 0", padding: "24px 20px",
            width: "100%", maxWidth: 460
          }}>
            <div style={{ display: "flex", gap: 14, alignItems: "flex-start", marginBottom: 16 }}>
              {prodottoVendita.foto_url && (
                <img src={prodottoVendita.foto_url} alt={prodottoVendita.nome}
                  style={{ width: 72, height: 72, objectFit: "cover", borderRadius: 10, flexShrink: 0 }}
                  onError={e => { e.target.style.display = "none"; }} />
              )}
              <div>
                <p style={{ margin: 0, fontWeight: 800, fontSize: 16, textTransform: "capitalize", color: "#1e293b" }}>
                  {prodottoVendita.nome}
                </p>
                {prodottoVendita.allergeni?.length > 0 && (
                  <p style={{ margin: "4px 0 0", fontSize: 11, color: "#d97706", fontWeight: 600 }}>
                    ⚠ Allergeni: {prodottoVendita.allergeni.join(", ")}
                  </p>
                )}
                {prodottoVendita.grammi > 0 && (
                  <p style={{ margin: "2px 0 0", fontSize: 11, color: "#6b7280" }}>
                    {prodottoVendita.grammi}g/pz • {prodottoVendita.pz_confezione || "?"} pz/conf
                  </p>
                )}
                {prodottoVendita.prezzo_singolo > 0 && (
                  <p style={{ margin: "4px 0 0", fontSize: 13, color: "#059669", fontWeight: 700 }}>
                    €{prodottoVendita.prezzo_singolo.toFixed(3)}/pz
                    {prodottoVendita.prezzo_acquisto_confezione > 0 && (
                      <span style={{ color: "#9ca3af", fontWeight: 400, fontSize: 11, marginLeft: 6 }}>
                        (conf. €{prodottoVendita.prezzo_acquisto_confezione.toFixed(2)})
                      </span>
                    )}
                  </p>
                )}
              </div>
            </div>
            <div style={{ marginBottom: 16 }}>
              <label style={{ fontSize: 13, fontWeight: 600, color: "#374151", display: "block", marginBottom: 6 }}>
                Pezzi messi in vendita oggi:
              </label>
              <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                <button onClick={() => setPezziVendita(Math.max(1, pezziVendita - 1))}
                  style={{ width: 44, height: 44, borderRadius: 12, border: "2px solid #e5e7eb", background: "#f9fafb", fontSize: 22, cursor: "pointer" }}>−</button>
                <input type="number" min={1} value={pezziVendita}
                  onChange={e => setPezziVendita(Math.max(1, parseInt(e.target.value) || 1))}
                  style={{ flex: 1, textAlign: "center", fontSize: 28, fontWeight: 800, border: "2px solid #d1d5db", borderRadius: 12, padding: "6px 0", outline: "none" }} />
                <button onClick={() => setPezziVendita(pezziVendita + 1)}
                  style={{ width: 44, height: 44, borderRadius: 12, border: "2px solid #e5e7eb", background: "#f9fafb", fontSize: 22, cursor: "pointer" }}>+</button>
              </div>
              {prodottoVendita?.prezzo_singolo > 0 && (
                <p style={{ margin: "8px 0 0", fontSize: 12, color: "#6b7280", textAlign: "center" }}>
                  Costo acquisto totale: <strong style={{ color: "#059669" }}>
                    €{(pezziVendita * prodottoVendita.prezzo_singolo).toFixed(2)}
                  </strong>
                </p>
              )}
            </div>
            <div style={{ display: "flex", gap: 10 }}>
              <button onClick={() => { setProdottoVendita(null); setPezziVendita(1); }}
                style={{
                  flex: 1, padding: "14px", borderRadius: 12, border: "2px solid #e5e7eb",
                  background: "#f9fafb", fontSize: 14, fontWeight: 600, cursor: "pointer", color: "#6b7280"
                }}>Annulla</button>
              <button onClick={registraVendita} disabled={saving}
                style={{
                  flex: 2, padding: "14px", borderRadius: 12, border: "none",
                  background: saving ? "#9ca3af" : "linear-gradient(135deg, #92400e, #b45309)",
                  color: "#fff", fontSize: 14, fontWeight: 800, cursor: saving ? "default" : "pointer"
                }}>
                {saving ? "Registrando..." : `Registra ${pezziVendita} pz in vendita`}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default ModalAcquaviva;
