import { useState, useEffect, useCallback } from "react";
import axios from "axios";
import { FileText, Download, ExternalLink, RefreshCw, BookOpen, Loader, Plus, X, Trash2 } from "lucide-react";
import { API } from "../../utils/constants";

const SEZIONI_COLORI = {
  "Ricorrenze":          "bg-blue-50 border-blue-200",
  "Applicazioni Prodotto":"bg-green-50 border-green-200",
  "Ricette":             "bg-teal-50 border-teal-200",
  "Aggiornato":          "bg-purple-50 border-purple-200",
  "MEPA":                "bg-amber-50 border-amber-200",
};

// ── Viewer PDF: fetch blob → embed con URL locale (bypassa CSP/X-Frame-Options) ──
const PdfViewer = ({ ricett, onClose }) => {
  const [blobUrl, setBlobUrl] = useState(null);
  const [loadingPdf, setLoadingPdf] = useState(true);
  const [errore, setErrore] = useState(null);

  useEffect(() => {
    let url = null;
    const carica = async () => {
      setLoadingPdf(true);
      setErrore(null);
      try {
        const proxyUrl = `${process.env.REACT_APP_BACKEND_URL}/api/saima/ricettari/pdf-proxy?url=${encodeURIComponent(ricett.url_pdf)}`;
        const res = await axios.get(proxyUrl, { responseType: "blob" });
        url = URL.createObjectURL(res.data);
        setBlobUrl(url);
      } catch (e) {
        setErrore("Impossibile caricare il PDF: " + (e.message || "errore"));
      } finally {
        setLoadingPdf(false);
      }
    };
    carica();
    return () => { if (url) URL.revokeObjectURL(url); };
  }, [ricett.url_pdf]);

  const proxyUrl = `${process.env.REACT_APP_BACKEND_URL}/api/saima/ricettari/pdf-proxy?url=${encodeURIComponent(ricett.url_pdf)}`;

  return (
    <div className="bg-white border border-gray-200 rounded-2xl overflow-hidden shadow-lg">
      {/* Toolbar */}
      <div className="flex items-center justify-between p-3 border-b border-gray-100 bg-gray-50 flex-wrap gap-2">
        <span className="font-semibold text-sm text-gray-700 flex items-center gap-2">
          <FileText size={14} className="text-blue-600" />
          {ricett.nome}
          {ricett.sezione === "MEPA" && (
            <span className="text-[10px] bg-amber-100 text-amber-700 px-2 py-0.5 rounded-full font-bold">MEPA</span>
          )}
        </span>
        <div className="flex items-center gap-2">
          {blobUrl && (
            <a href={blobUrl} download={`${ricett.nome}.pdf`}
              className="text-xs px-3 py-1.5 bg-blue-600 text-white rounded-lg hover:bg-blue-700 flex items-center gap-1.5 font-medium">
              <Download size={13} /> Scarica PDF
            </a>
          )}
          <a href={proxyUrl} target="_blank" rel="noopener noreferrer"
            className="text-xs px-3 py-1.5 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 flex items-center gap-1.5 font-medium">
            <ExternalLink size={13} /> Apri
          </a>
          <button onClick={onClose} className="text-sm px-2 py-1 text-gray-400 hover:text-gray-600 rounded">✕ Chiudi</button>
        </div>
      </div>

      {/* Contenuto */}
      <div style={{ height: "78vh" }} className="w-full bg-gray-100 flex items-center justify-center">
        {loadingPdf && (
          <div className="flex flex-col items-center gap-3 text-gray-500">
            <Loader className="animate-spin" size={32} />
            <span className="text-sm">Caricamento PDF in corso...</span>
          </div>
        )}
        {errore && (
          <div className="text-center p-8">
            <p className="text-red-500 text-sm mb-3">{errore}</p>
            <a href={proxyUrl} target="_blank" rel="noopener noreferrer"
              className="px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-medium hover:bg-blue-700">
              Apri in nuova scheda
            </a>
          </div>
        )}
        {blobUrl && !loadingPdf && (
          <embed
            src={blobUrl}
            type="application/pdf"
            className="w-full h-full border-0"
            style={{ height: "78vh" }}
          />
        )}
      </div>
    </div>
  );
};

// ── Form aggiunta ricettario manuale ──────────────────────────────────────────
const FormAggiungiRicettario = ({ onAdded }) => {
  const [open, setOpen] = useState(false);
  const [form, setForm] = useState({ nome: "", url_pdf: "", sezione: "MEPA", fornitore: "" });
  const [loading, setLoading] = useState(false);

  const salva = async () => {
    if (!form.nome.trim() || !form.url_pdf.trim()) return;
    setLoading(true);
    try {
      await axios.post(`${API}/saima/ricettari/aggiungi`, form);
      setOpen(false);
      setForm({ nome: "", url_pdf: "", sezione: "MEPA", fornitore: "" });
      onAdded && onAdded();
    } catch { }
    finally { setLoading(false); }
  };

  return (
    <>
      <button onClick={() => setOpen(true)}
        className="text-sm px-3 py-1.5 bg-white/20 hover:bg-white/30 rounded-lg flex items-center gap-1.5 transition-colors">
        <Plus size={13} /> Aggiungi Ricettario
      </button>
      {open && (
        <div className="fixed inset-0 z-50 flex items-center justify-center">
          <div className="absolute inset-0 bg-black/50" onClick={() => setOpen(false)} />
          <div className="relative bg-white rounded-2xl shadow-2xl p-6 max-w-sm w-full mx-4">
            <div className="flex items-center justify-between mb-4">
              <h3 className="font-bold text-gray-800">Aggiungi Ricettario</h3>
              <button onClick={() => setOpen(false)} className="text-gray-400 hover:text-gray-600"><X size={18} /></button>
            </div>
            <div className="space-y-3">
              <div>
                <label className="text-xs text-gray-500 font-medium">Nome</label>
                <input value={form.nome} onChange={e => setForm({...form, nome: e.target.value})}
                  placeholder="es. Ricettario Pasticceria MEPA"
                  className="w-full mt-1 px-3 py-2 border border-gray-200 rounded-lg text-sm focus:ring-1 focus:ring-blue-400" />
              </div>
              <div>
                <label className="text-xs text-gray-500 font-medium">URL PDF</label>
                <input value={form.url_pdf} onChange={e => setForm({...form, url_pdf: e.target.value})}
                  placeholder="https://esempio.com/ricettario.pdf"
                  className="w-full mt-1 px-3 py-2 border border-gray-200 rounded-lg text-sm focus:ring-1 focus:ring-blue-400" />
              </div>
              <div className="grid grid-cols-2 gap-2">
                <div>
                  <label className="text-xs text-gray-500 font-medium">Sezione</label>
                  <select value={form.sezione} onChange={e => setForm({...form, sezione: e.target.value})}
                    className="w-full mt-1 px-3 py-2 border border-gray-200 rounded-lg text-sm bg-white">
                    <option value="MEPA">MEPA</option>
                    <option value="Ricorrenze">Ricorrenze</option>
                    <option value="Applicazioni Prodotto">Applicazioni</option>
                    <option value="Altro">Altro</option>
                  </select>
                </div>
                <div>
                  <label className="text-xs text-gray-500 font-medium">Fornitore</label>
                  <input value={form.fornitore} onChange={e => setForm({...form, fornitore: e.target.value})}
                    placeholder="es. MEPA"
                    className="w-full mt-1 px-3 py-2 border border-gray-200 rounded-lg text-sm focus:ring-1 focus:ring-blue-400" />
                </div>
              </div>
            </div>
            <div className="flex gap-2 mt-4">
              <button onClick={() => setOpen(false)}
                className="flex-1 py-2 border border-gray-200 rounded-xl text-sm text-gray-600 hover:bg-gray-50">Annulla</button>
              <button onClick={salva} disabled={loading || !form.nome.trim() || !form.url_pdf.trim()}
                className="flex-1 py-2 bg-blue-600 text-white rounded-xl text-sm font-semibold hover:bg-blue-700 disabled:opacity-50">
                {loading ? "Salvo..." : "Aggiungi"}
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};
export const SaimaRicettariView = () => {
  const [ricettari, setRicettari] = useState([]);
  const [loading, setLoading] = useState(true);
  const [pdfAperto, setPdfAperto] = useState(null);

  const carica = useCallback(async () => {
    setLoading(true);
    try {
      const res = await axios.get(`${API}/saima/ricettari`);
      setRicettari(res.data || []);
    } catch {
      setRicettari([]);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { carica(); }, [carica]);

  const handleAggiorna = async () => {
    try {
      await axios.post(`${API}/saima/ricettari/aggiorna`);
      setTimeout(carica, 3000);
    } catch { }
  };

  // Raggruppa per sezione, MEPA in fondo
  const gruppi = ricettari.reduce((acc, r) => {
    const sez = r.sezione || "Ricorrenze";
    if (!acc[sez]) acc[sez] = [];
    acc[sez].push(r);
    return acc;
  }, {});

  // Ordine sezioni: prima SAIMA, poi MEPA
  const ordineSezioni = ["Ricorrenze", "Applicazioni Prodotto", "Ricette", "Aggiornato"]
    .concat(Object.keys(gruppi).filter(s => !["Ricorrenze","Applicazioni Prodotto","Ricette","Aggiornato"].includes(s)));

  if (loading) return (
    <div className="flex items-center justify-center py-16 text-gray-400">
      <RefreshCw className="animate-spin mr-2" size={18} /> Caricamento ricettari...
    </div>
  );

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="bg-blue-600 text-white rounded-2xl p-4 flex items-center justify-between">
        <div>
          <h2 className="text-xl font-bold flex items-center gap-2">
            <BookOpen size={20} /> Ricettari SAIMA &amp; MEPA
          </h2>
          <p className="text-sm opacity-80 mt-0.5">
            {ricettari.length} ricettari disponibili — clicca "Visualizza" per aprire il PDF inline
          </p>
        </div>
        <div className="flex items-center gap-2">
          <FormAggiungiRicettario onAdded={carica} />
          <button onClick={handleAggiorna}
            className="text-sm px-3 py-1.5 bg-white/20 hover:bg-white/30 rounded-lg flex items-center gap-1.5 transition-colors">
            <RefreshCw size={13} /> Aggiorna SAIMA
          </button>
        </div>
      </div>

      {/* Viewer PDF inline */}
      {pdfAperto && (
        <PdfViewer ricett={pdfAperto} onClose={() => setPdfAperto(null)} />
      )}

      {/* Griglia ricettari per sezione */}
      {ordineSezioni.filter(s => gruppi[s]).map(sezione => (
        <div key={sezione}>
          <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wider mb-3 flex items-center gap-2">
            {sezione}
            {sezione === "MEPA" && (
              <span className="text-[10px] normal-case bg-amber-100 text-amber-700 px-2 py-0.5 rounded-full font-semibold">Mercato Elettronico</span>
            )}
            <span className="text-gray-300 font-normal">({gruppi[sezione].length})</span>
          </h3>
          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-3">
            {gruppi[sezione].map(ricett => (
              <div
                key={ricett.id}
                className={`relative group rounded-xl border-2 ${SEZIONI_COLORI[ricett.sezione] || "bg-gray-50 border-gray-200"} p-4 hover:shadow-md transition-all ${pdfAperto?.id === ricett.id ? "ring-2 ring-blue-500" : ""}`}
              >
                <div className="flex items-center justify-center mb-3 h-16">
                  <FileText size={44} className="text-blue-400 opacity-60 group-hover:opacity-90 transition-opacity" />
                </div>
                <p className="text-xs font-bold text-gray-700 text-center leading-tight mb-2 line-clamp-2">
                  {ricett.nome}
                </p>
                <div className="flex gap-1.5 justify-center mt-auto">
                  <button
                    onClick={() => setPdfAperto(pdfAperto?.id === ricett.id ? null : ricett)}
                    className="text-[10px] flex-1 py-1 bg-blue-600 text-white rounded-lg font-medium hover:bg-blue-700 flex items-center justify-center gap-0.5"
                    data-testid={`btn-visualizza-pdf-${ricett.id}`}
                  >
                    <FileText size={9} /> Visualizza
                  </button>
                  <a
                    href={`${process.env.REACT_APP_BACKEND_URL}/api/saima/ricettari/pdf-proxy?url=${encodeURIComponent(ricett.url_pdf)}`}
                    download={`${ricett.nome}.pdf`}
                    onClick={e => e.stopPropagation()}
                    className="text-[10px] px-2 py-1 bg-white border border-blue-300 text-blue-600 rounded-lg font-medium hover:bg-blue-50 flex items-center"
                    title="Scarica PDF"
                  >
                    <Download size={9} />
                  </a>
                  {ricett.aggiunto_manualmente && (
                    <button onClick={async e => {
                      e.stopPropagation();
                      await axios.delete(`${API}/saima/ricettari/${ricett.id}`);
                      carica();
                    }} className="text-[10px] px-1.5 py-1 bg-red-50 border border-red-200 text-red-500 rounded-lg hover:bg-red-100" title="Elimina">
                      <Trash2 size={9} />
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>
      ))}

      {ricettari.length === 0 && (
        <div className="text-center py-16 text-gray-400">
          <BookOpen size={48} className="mx-auto mb-4 opacity-30" />
          <p>Nessun ricettario disponibile. Clicca "Aggiorna" per scaricare i ricettari.</p>
        </div>
      )}
    </div>
  );
};

export default SaimaRicettariView;
