                  <tr className="border-t-2 border-gray-200 bg-orange-50 font-bold">
                    <td className="py-2 px-1 text-orange-700">Totale uscite</td>
                    <td className="py-2 px-1 text-center text-orange-700">{data.totale_pezzi_usciti}</td>
                  </tr>
