// ── Helper parse data (supporta dd/mm/yyyy e ISO) ────────────────────────────
function parseData(ds) {
  if (!ds) return null;
  try {
    if (ds.includes("/")) {
      const [dd, mm, yyyy] = ds.split("/");
      return new Date(parseInt(yyyy), parseInt(mm) - 1, parseInt(dd));
    }
    return parseISO(ds);
  } catch { return null; }
}

// ── Alert lotto scadenza ──────────────────────────────────────────────────────
function AlertScadenza({ lotto, onElimina }) {
  const sc = parseData(lotto.data_scadenza);
  const giorni = sc ? differenceInDays(sc, new Date()) : 999;
  const color = giorni < 0 ? "red" : giorni <= 1 ? "red" : giorni <= 3 ? "amber" : "yellow";
  const colors = {
    red:   { bg: "bg-red-50",   border: "border-red-300",   text: "text-red-700",   badge: "bg-red-600 text-white" },
    amber: { bg: "bg-amber-50", border: "border-amber-300", text: "text-amber-700", badge: "bg-amber-500 text-white" },
    yellow:{ bg: "bg-yellow-50",border: "border-yellow-300",text: "text-yellow-700",badge: "bg-yellow-400 text-gray-800" },
  };
  const c = colors[color];
  return (
    <div className={`flex items-center gap-3 p-3 rounded-xl border ${c.bg} ${c.border}`}>
      <AlertTriangle className={c.text} size={16} />
      <div className="flex-1 min-w-0">
        <p className={`font-semibold text-sm capitalize truncate ${c.text}`}>{lotto.prodotto}</p>
        <p className={`text-xs ${c.text} opacity-80`}>
          {lotto.frigo_numero ? `${lotto.frigo_numero} · ` : ""}{lotto.numero_lotto}
        </p>
      </div>
      <span className={`flex-shrink-0 text-xs font-bold px-2 py-1 rounded-full ${c.badge}`}>
        {giorni < 0 ? `Scad. ${Math.abs(giorni)}gg fa` : giorni === 0 ? "Oggi!" : `${giorni}gg`}
      </span>
      {onElimina && (
        <button
          onClick={() => onElimina(lotto.id, lotto.prodotto)}
          className="flex-shrink-0 p-1.5 rounded-lg bg-white/70 hover:bg-red-100 text-red-500 hover:text-red-700 transition-colors border border-red-200"
          title="Elimina lotto"
        >
          <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14H6L5 6"/><path d="M10 11v6M14 11v6"/><path d="M9 6V4h6v2"/></svg>
        </button>
      )}
    </div>
  );
}

// ── Componente principale ─────────────────────────────────────────────────────
const DashboardView = ({ stats, onRefresh, onNavigate }) => {
  const [lottiScadenza, setLottiScadenza]           = useState([]);
  const [produzioniOggi, setProduzioniOggi]         = useState([]);
  const [venditeOggi, setVenditeOggi]               = useState([]);
  const [loadingExtra, setLoadingExtra]              = useState(true);
  const [mostraVendite, setMostraVendite]            = useState(false);
  const [magazzinoSemi, setMagazzinoSemi]            = useState(null);
  const [mostraPopupSemi, setMostraPopupSemi]        = useState(false);
  const [giornoProduttivo, setGiornoProduttivo]      = useState(true);   // true = produttivo
  const [loadingToggle, setLoadingToggle]            = useState(false);

  const caricaDatiLive = useCallback(async () => {
    setLoadingExtra(true);
    try {
      const [lottiRes, prodRes, vendRes, semiRes, gnpRes] = await Promise.allSettled([
        axios.get(`${API}/lotti?limit=300`),
        axios.get(`${API}/produzioni/per-oggi`),
        axios.get(`${API}/vendita-banco/oggi`),
        axios.get(`${API}/acquaviva/magazzino-congelatore`),
        axios.get(`${API}/chiusure/giorno-non-produttivo/oggi`),
      ]);

      // Lotti in scadenza nei prossimi 7 giorni
      if (lottiRes.status === "fulfilled") {
        const oggi = new Date();
        oggi.setHours(0, 0, 0, 0);
        const tra7 = new Date(oggi);
        tra7.setDate(tra7.getDate() + 7);
        const scadenti = (lottiRes.value.data || [])
          .filter(l => {
            if (l.consumato) return false;
            try { const sc = parseData(l.data_scadenza); return sc && sc <= tra7; } catch { return false; }
          })
          .sort((a, b) => {
            const da = parseData(a.data_scadenza), db = parseData(b.data_scadenza);
            return (da || 0) - (db || 0);
          })
          .slice(0, 10);
        setLottiScadenza(scadenti);
      }

      if (prodRes.status === "fulfilled")  setProduzioniOggi(prodRes.value.data || []);
      if (vendRes.status === "fulfilled")  setVenditeOggi(vendRes.value.data || []);
      if (semiRes.status === "fulfilled")  setMagazzinoSemi(semiRes.value.data || null);
      if (gnpRes.status === "fulfilled")   setGiornoProduttivo(!gnpRes.value.data?.non_produttivo);
    } catch (e) {
      console.error("Errore dati live dashboard:", e);
    } finally {
      setLoadingExtra(false);
    }
  }, []);

  const toggleGiornoNonProduttivo = async () => {
    setLoadingToggle(true);
    try {
      const nuovoStato = !giornoProduttivo; // se era produttivo → diventa non produttivo (attivo=true)
      await axios.post(`${API}/chiusure/giorno-non-produttivo/oggi`, {
        attivo: nuovoStato,
        motivo: "Giorno di riposo"
      });
      setGiornoProduttivo(!nuovoStato);
      if (nuovoStato) {
        toast.success("Giorno marcato come non produttivo — alert P1 soppresso");
      } else {
        toast.info("Giorno ripristinato come produttivo");
      }
      onRefresh(); // aggiorna il Supervisore badge
    } catch (e) {
      toast.error("Errore aggiornamento stato giorno");
    }
    setLoadingToggle(false);
  };

  useEffect(() => { caricaDatiLive(); }, [caricaDatiLive]);

  const handleRefresh = () => { onRefresh(); caricaDatiLive(); };

  const eliminaLotto = async (lottoId, nomeProdotto) => {
    const toastId = toast(`Marcare "${nomeProdotto}" come consumato?`, {
      description: "Il lotto rimarrà nel registro storico come esaurito.",
      action: {
        label: "Conferma",
        onClick: async () => {
          try {
            await axios.patch(`${API}/lotti/${lottoId}/consuma`);
            setLottiScadenza(prev => prev.filter(l => l.id !== lottoId));
            toast.success("Lotto marcato come consumato");
            onRefresh();
          } catch (e) {
            toast.error("Errore: " + (e.response?.data?.detail || e.message));
          }
        }
      },
      cancel: { label: "Annulla", onClick: () => {} },
      duration: 8000,
    });
  };

  // Produzioni reali di laboratorio
  const pezziProdPast   = produzioniOggi.filter(p => p.reparto === "pasticceria").reduce((s, p) => s + (p.quantita || 0), 0);
  const pezziProdCucina = produzioniOggi.filter(p => p.reparto === "rosticceria").reduce((s, p) => s + (p.quantita || 0), 0);

  const aperte  = venditeOggi.filter(v => v.stato === "aperto");
  const chiuse  = venditeOggi.filter(v => v.stato === "chiuso");

  // Semilavorati Acquaviva al banco (pronti, non trasformati)
  const isSemilavorato = v => v.fonte === "colazione" || v.fonte === "acquaviva";

  // Totali generali (per tabella dettaglio e scadenze)
  const totVenduti   = chiuse.reduce((s, v) => s + (v.pezzi_venduti || 0), 0);
  const totInvenduti = chiuse.reduce((s, v) => s + (v.pezzi_invenduto || 0), 0);
  const pezziAperte  = aperte.reduce((s, v) => s + (v.pezzi_prodotti || 0), 0);
  const pezziAlBanco = venditeOggi.reduce((s, v) => s + (v.pezzi_prodotti || 0), 0);

  // Venduti per reparto
  const vendutiPast   = chiuse.filter(v => v.reparto === "pasticceria").reduce((s, v) => s + (v.pezzi_venduti || 0), 0);
  const vendutiCucina = chiuse.filter(v => v.reparto === "rosticceria").reduce((s, v) => s + (v.pezzi_venduti || 0), 0);

  // Invenduti per reparto
  const invPast   = chiuse.filter(v => v.reparto === "pasticceria").reduce((s, v) => s + (v.pezzi_invenduto || 0), 0);
  const invCucina = chiuse.filter(v => v.reparto === "rosticceria").reduce((s, v) => s + (v.pezzi_invenduto || 0), 0);

  // ── Dati per colonna semilavorati ──────────────────────────────────────────
  const pezziSemiAlBanco = venditeOggi.filter(isSemilavorato).reduce((s, v) => s + (v.pezzi_prodotti || 0), 0);
  const venduteSemi      = chiuse.filter(isSemilavorato).reduce((s, v) => s + (v.pezzi_venduti || 0), 0);
  const invSemi          = chiuse.filter(isSemilavorato).reduce((s, v) => s + (v.pezzi_invenduto || 0), 0);

  // Incasso potenziale per colonna (produzioni aperte * prezzo)
  const incassoPast  = aperte.filter(v => v.reparto === "pasticceria").reduce((s, v) => s + ((v.prezzo_vendita || 0) * (v.pezzi_prodotti || 0)), 0);
  const incassoCucina= aperte.filter(v => v.reparto === "rosticceria").reduce((s, v) => s + ((v.prezzo_vendita || 0) * (v.pezzi_prodotti || 0)), 0);
  const incassoSemi  = aperte.filter(isSemilavorato).reduce((s, v) => s + ((v.prezzo_vendita || 0) * (v.pezzi_prodotti || 0)), 0);

  // Costo effettivo (invenduti) per colonna
  const costoPast    = chiuse.filter(v => v.reparto === "pasticceria").reduce((s, v) => s + ((v.costo_produzione || 0) * (v.pezzi_invenduto || 0)), 0);
  const costoCucina  = chiuse.filter(v => v.reparto === "rosticceria").reduce((s, v) => s + ((v.costo_produzione || 0) * (v.pezzi_invenduto || 0)), 0);
  const costoSemi    = chiuse.filter(isSemilavorato).reduce((s, v) => s + ((v.costo_produzione || 0) * (v.pezzi_invenduto || 0)), 0);

  // Pezzi al banco per colonna (laboratorio)
  const pezziPastAlBanco   = venditeOggi.filter(v => v.reparto === "pasticceria" && !isSemilavorato(v)).reduce((s, v) => s + (v.pezzi_prodotti || 0), 0);
  const pezziCucinaAlBanco = venditeOggi.filter(v => v.reparto === "rosticceria" && !isSemilavorato(v)).reduce((s, v) => s + (v.pezzi_prodotti || 0), 0);

  // In frigo per colonna (prodotto in lab ma non ancora al banco)
  const pezziPastInCella   = Math.max(0, pezziProdPast - pezziPastAlBanco);
  const pezziCucinaInCella = Math.max(0, pezziProdCucina - pezziCucinaAlBanco);

  const lavorPast   = produzioniOggi.filter(p => p.reparto === "pasticceria").length;
  const lavorCucina = produzioniOggi.filter(p => p.reparto === "rosticceria").length;

  // ── Dati magazzino semilavorati ─────────────────────────────────────────────
  const semiEntrati   = magazzinoSemi?.totale_pezzi_entrati ?? 0;
  const semiUsciti    = magazzinoSemi?.totale_pezzi_usciti ?? 0;
  const semiCongelatore = magazzinoSemi?.saldo_congelatore ?? 0;

  return (
    <div className="space-y-6">
      {/* Popup magazzino semilavorati */}
      {mostraPopupSemi && (
        <PopupMagazzinoSemi data={magazzinoSemi} onClose={() => setMostraPopupSemi(false)} />
      )}

      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Dashboard</h1>
          <p className="text-gray-500 text-sm">
            {format(new Date(), "EEEE d MMMM yyyy", { locale: it })}
          </p>
        </div>
        <div className="flex items-center gap-3">
          {/* Toggle Giorno Non Produttivo */}
          <button
            data-testid="toggle-giorno-non-produttivo"
            onClick={toggleGiornoNonProduttivo}
            disabled={loadingToggle}
            title={giornoProduttivo ? "Marca come giorno di riposo (disattiva alert P1)" : "Ripristina come giorno produttivo"}
            className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-medium border transition-colors shadow-sm ${
              giornoProduttivo
                ? "bg-white border-gray-200 text-gray-600 hover:bg-gray-50"
                : "bg-amber-50 border-amber-300 text-amber-700 hover:bg-amber-100"
            }`}
          >
            {giornoProduttivo
              ? <><ToggleLeft size={18} className="text-gray-400" /> Giorno Produttivo</>
              : <><ToggleRight size={18} className="text-amber-500" /> Giorno di Riposo</>
            }
          </button>
          <button onClick={handleRefresh}
            className="flex items-center gap-2 px-4 py-2 bg-white border border-gray-200 rounded-xl text-sm font-medium text-gray-600 hover:bg-gray-50 transition-colors shadow-sm">
            <RefreshCw size={16} /> Aggiorna
          </button>
        </div>
      </div>

      {/* Accesso rapido Tablet — IN CIMA per accesso immediato */}
      <div>
        <h3 className="text-xs font-bold text-gray-400 uppercase tracking-wide mb-3">Accesso Rapido Tablet</h3>
        <div className="grid grid-cols-3 gap-3">
          {[
            { href: "#tablet/rosticceria", label: "Tablet Rosticceria", sub: "Registra lotti salati",       bg: "bg-blue-50   border-blue-200   hover:bg-blue-100   hover:border-blue-400",   txt: "text-blue-800",   stxt: "text-blue-600"   },
            { href: "#tablet/pasticceria", label: "Tablet Pasticceria", sub: "Registra + stampa etichetta", bg: "bg-amber-50  border-amber-200  hover:bg-amber-100  hover:border-amber-400",  txt: "text-amber-800",  stxt: "text-amber-600"  },
            { href: "#tablet/vendita",     label: "Tablet Vendita",     sub: "Registra invenduto serale",   bg: "bg-orange-50 border-orange-200 hover:bg-orange-100 hover:border-orange-400", txt: "text-orange-800", stxt: "text-orange-600" },
          ].map(tab => (
            <a key={tab.href} href={tab.href} target="_blank" rel="noopener noreferrer"
              className={`flex items-center gap-3 p-4 rounded-xl border-2 transition-all cursor-pointer no-underline group ${tab.bg}`}>
              <div className="min-w-0">
                <p className={`text-sm font-bold ${tab.txt} m-0 truncate`}>{tab.label}</p>
                <p className={`text-xs ${tab.stxt} m-0`}>{tab.sub}</p>
              </div>
            </a>
          ))}
        </div>
      </div>

      {/* Alert lotti in scadenza */}
      {lottiScadenza.length > 0 && (
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5">
          <div className="flex items-center gap-2 mb-4">
            <AlertTriangle className="text-amber-500" size={20} />
            <h3 className="font-bold text-gray-800">
              Lotti in Scadenza — prossimi 7 giorni
            </h3>
            <span className="ml-auto text-xs font-bold px-2.5 py-1 bg-amber-100 text-amber-700 rounded-full">
              {lottiScadenza.length}
            </span>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
            {lottiScadenza.map(l => <AlertScadenza key={l.id} lotto={l} onElimina={eliminaLotto} />)}
          </div>
        </div>
      )}

      {/* ── GRIGLIA 3 COLONNE ────────────────────────────────────────────── */}
      <div className="bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden">

        {/* Intestazione colonne */}
        <div className="grid grid-cols-3 border-b-2 border-gray-200 bg-gray-50">
          <div className="px-4 py-3 border-r border-gray-200">
            <p className="text-xs font-bold text-gray-400 uppercase tracking-widest">Prodotti in pasticceria</p>
          </div>
          <div className="px-4 py-3 border-r border-gray-200">
            <p className="text-xs font-bold text-gray-400 uppercase tracking-widest">Prodotti in cucina</p>
          </div>
          <div className="px-4 py-3">
            <p className="text-xs font-bold text-gray-400 uppercase tracking-widest">Prodotti semilavorati</p>
          </div>
        </div>

        {/* Riga: Prodotti prodotti oggi */}
        <div className="grid grid-cols-3 border-b border-gray-100">
          <GridCell
            value={pezziProdPast}
            label="Prodotti in pasticceria"
            sub={`${lavorPast} lavorazioni`}
            onClick={() => onNavigate("storico_produzioni")}
          />
          <GridCell
            value={pezziProdCucina}
            label="Prodotti in cucina"
            sub={`${lavorCucina} lavorazioni`}
            onClick={() => onNavigate("storico_produzioni")}
          />
          {/* Semilavorati: saldo congelatore = acquistati - usati */}
          <GridCell
            value={semiCongelatore}
            label="In congelatore ora"
            sub={`${semiEntrati} entrati − ${semiUsciti} usciti`}
            sub2={`${magazzinoSemi?.num_referenze ?? 0} referenze Vandemoortele`}
            onClick={() => setMostraPopupSemi(true)}
          />
        </div>

        {/* Riga: Al banco oggi */}
        <div className="grid grid-cols-3 border-b border-gray-100 bg-blue-50/30">
          <GridCell
            value={pezziPastAlBanco}
            label="Al banco oggi"
            sub={`${pezziPastAlBanco} lab`}
            sub2={`${aperte.filter(v => v.reparto === "pasticceria").length} lavorazioni aperte`}
            onClick={() => window.open("#tablet/vendita", "_blank")}
          />
          <GridCell
            value={pezziCucinaAlBanco}
            label="Al banco oggi"
            sub2={`${aperte.filter(v => v.reparto === "rosticceria").length} lavorazioni aperte`}
            onClick={() => window.open("#tablet/vendita", "_blank")}
          />
          <GridCell
            value={pezziSemiAlBanco}
            label="Al banco oggi"
            sub="pezzi dal congelatore"
            sub2={`${aperte.filter(isSemilavorato).length} lavorazioni aperte`}
            onClick={() => setMostraPopupSemi(true)}
          />
        </div>

        {/* Riga: In frigo/congelatori */}
        <div className="grid grid-cols-3 border-b border-gray-100">
          <GridCell
            value={pezziPastInCella}
            label="In frigo/congelatori"
            sub={pezziPastInCella > 0 ? "Non ancora al banco" : "Tutto al banco"}
          />
          <GridCell
            value={pezziCucinaInCella}
            label="In frigo/congelatori"
            sub={pezziCucinaInCella > 0 ? "Non ancora al banco" : "Tutto al banco"}
          />
          <GridCell
            value={0}
            label="Rientrati in congelatore"
            sub="Gli invenduti non rientrano"
            onClick={() => setMostraPopupSemi(true)}
          />
        </div>

        {/* Riga: Venduti / Invenduti */}
        <div className="grid grid-cols-3 border-b border-gray-100 bg-green-50/20">
          <GridCell
            value={vendutiPast}
            label="Venduti oggi"
            sub={invPast > 0 ? `${invPast} invenduti` : chiuse.filter(v=>v.reparto==="pasticceria").length > 0 ? "Nessuno spreco" : "In corso"}
            onClick={() => setMostraVendite(v => !v)}
          />
          <GridCell
            value={vendutiCucina}
            label="Venduti oggi"
            sub={invCucina > 0 ? `${invCucina} invenduti` : chiuse.filter(v=>v.reparto==="rosticceria").length > 0 ? "Nessuno spreco" : "In corso"}
            onClick={() => setMostraVendite(v => !v)}
          />
          <GridCell
            value={venduteSemi}
            label="Venduti oggi"
            sub={invSemi > 0 ? `${invSemi} invenduti` : "—"}
            onClick={() => setMostraVendite(v => !v)}
          />
        </div>

        {/* Riga: Incasso potenziale */}
        <div className="grid grid-cols-3 border-b border-gray-100 bg-purple-50/20">
          <GridCell
            value={incassoPast > 0 ? incassoPast.toFixed(2) : "—"}
            label="Incasso potenziale"
            sub="euro"
            euro={incassoPast > 0}
          />
          <GridCell
            value={incassoCucina > 0 ? incassoCucina.toFixed(2) : "—"}
            label="Incasso potenziale"
            sub="euro"
            euro={incassoCucina > 0}
          />
          <GridCell
            value={incassoSemi > 0 ? incassoSemi.toFixed(2) : "—"}
            label="Incasso potenziale"
            sub="euro"
            euro={incassoSemi > 0}
          />
        </div>

        {/* Riga: Costo effettivo sprechi */}
        <div className="grid grid-cols-3">
          <GridCell
            value={costoPast > 0 ? costoPast.toFixed(2) : "—"}
            label="Costo effettivo"
            sub="euro (invenduto)"
            euro={costoPast > 0}
            highlight
          />
          <GridCell
            value={costoCucina > 0 ? costoCucina.toFixed(2) : "—"}
            label="Costo effettivo"
            sub="euro (invenduto)"
            euro={costoCucina > 0}
            highlight
          />
          <GridCell
            value={costoSemi > 0 ? costoSemi.toFixed(2) : "—"}
            label="Costo effettivo"
            sub="euro (invenduto)"
            euro={costoSemi > 0}
            highlight
          />
        </div>
      </div>

      {/* Pannello dettaglio vendite oggi — aperto al click sulla card */}
      {mostraVendite && venditeOggi.length > 0 && (
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5">
          <div className="flex items-center justify-between mb-4">
            <h3 className="font-bold text-gray-800 flex items-center gap-2">
              <ShoppingCart size={18} className="text-orange-500" /> Dettaglio Banco Oggi
            </h3>
            <button onClick={() => setMostraVendite(false)}
              className="text-xs text-gray-400 hover:text-gray-600 font-semibold px-3 py-1 rounded-lg border border-gray-200 hover:bg-gray-50">
              Chiudi
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b border-gray-100">
                  <th className="text-left py-2 px-1 text-xs font-bold text-gray-400 uppercase">Prodotto</th>
                  <th className="text-center py-2 px-1 text-xs font-bold text-gray-400 uppercase">Al banco</th>
                  <th className="text-center py-2 px-1 text-xs font-bold text-gray-400 uppercase">Venduti</th>
                  <th className="text-center py-2 px-1 text-xs font-bold text-gray-400 uppercase">Invenduti</th>
                  <th className="text-center py-2 px-1 text-xs font-bold text-gray-400 uppercase">Stato</th>
                </tr>
              </thead>
              <tbody>
                {venditeOggi.filter(v => (v.pezzi_prodotti || 0) > 0).map(v => (
                  <tr key={v.id} className="border-b border-gray-50 hover:bg-gray-50">
                    <td className="py-2 px-1 font-medium text-gray-700 capitalize">{v.prodotto_nome}</td>
                    <td className="py-2 px-1 text-center text-gray-600">{v.pezzi_prodotti || 0}</td>
                    <td className="py-2 px-1 text-center font-bold text-green-600">{v.pezzi_venduti ?? "—"}</td>
                    <td className="py-2 px-1 text-center font-bold text-red-500">{v.pezzi_invenduto ?? "—"}</td>
                    <td className="py-2 px-1 text-center">
                      {v.stato === "chiuso"
                        ? <span className="text-xs bg-green-100 text-green-700 px-2 py-0.5 rounded-full font-bold">Chiuso</span>
                        : <span className="text-xs bg-amber-100 text-amber-700 px-2 py-0.5 rounded-full font-bold">Aperto</span>
                      }
                    </td>
                  </tr>
                ))}
              </tbody>
              <tfoot>
                <tr className="border-t-2 border-gray-200 bg-gray-50">
                  <td className="py-2 px-1 font-bold text-gray-700">Totale</td>
                  <td className="py-2 px-1 text-center font-bold text-gray-700">{pezziAlBanco}</td>
                  <td className="py-2 px-1 text-center font-bold text-green-600">{totVenduti}</td>
                  <td className="py-2 px-1 text-center font-bold text-red-500">{totInvenduti}</td>
                  <td></td>
                </tr>
              </tfoot>
            </table>
          </div>
        </div>
      )}

      {/* KPI Generali */}
      <div>
        <h3 className="text-xs font-bold text-gray-400 uppercase tracking-wide mb-3">Archivio</h3>
        <div className="grid grid-cols-2 lg:grid-cols-5 gap-3">
          {[
            { icon: Package,  bg: "bg-blue-50",   col: "text-blue-500",   val: stats.materie_prime,  label: "Materie Prime",  nav: "materie" },
            { icon: BookOpen, bg: "bg-green-50",  col: "text-green-500",  val: stats.ricette,        label: "Ricette",        nav: "ricette" },
            { icon: Layers,   bg: "bg-purple-50", col: "text-purple-500", val: stats.lotti_totali,   label: "Lotti Totali",   nav: "lotti"   },
            { icon: FileText, bg: "bg-indigo-50", col: "text-indigo-500", val: stats.fatture,        label: "Fatture",        nav: "fatture" },
            { icon: Search,   bg: "bg-rose-50",   col: "text-rose-500",   val: "Recall",             label: "Recall ASL",     nav: "lotti"   },
          ].map(k => (
            <div key={k.label} onClick={() => onNavigate(k.nav)}
              className="bg-white rounded-xl border border-gray-100 shadow-sm p-3 flex items-center gap-3 cursor-pointer hover:shadow-md hover:border-blue-200 transition-all">
              <div className={`p-2 ${k.bg} rounded-lg flex-shrink-0`}>
                <k.icon className={k.col} size={18} />
              </div>
              <div>
                <p className="text-2xl font-bold text-gray-900 leading-none">{k.val ?? "—"}</p>
                <p className="text-xs font-semibold text-gray-500 mt-0.5">{k.label}</p>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Scadenze + aperti */}
      <div className="grid grid-cols-2 gap-3">
        <div onClick={() => onNavigate("lotti")}
          className={`bg-white rounded-xl border shadow-sm p-3 flex items-center gap-3 cursor-pointer transition-all ${lottiScadenza.filter(l => { const sc = parseData(l.data_scadenza); return sc && differenceInDays(sc, new Date()) <= 1; }).length > 0 ? "border-red-200 hover:border-red-400" : "border-gray-100 hover:border-blue-200"}`}>
          <div className={`p-2 rounded-lg ${lottiScadenza.filter(l => { const sc = parseData(l.data_scadenza); return sc && differenceInDays(sc, new Date()) <= 1; }).length > 0 ? "bg-red-100" : "bg-emerald-100"}`}>
            {lottiScadenza.filter(l => { const sc = parseData(l.data_scadenza); return sc && differenceInDays(sc, new Date()) <= 1; }).length > 0
              ? <AlertTriangle className="text-red-600" size={18} />
              : <CheckCircle className="text-emerald-600" size={18} />}
          </div>
          <div>
            <p className="text-2xl font-bold text-gray-900 leading-none">
              {lottiScadenza.filter(l => { const sc = parseData(l.data_scadenza); return sc && differenceInDays(sc, new Date()) <= 1; }).length || "OK"}
            </p>
            <p className="text-xs font-semibold text-gray-500 mt-0.5">Scadono oggi/domani</p>
          </div>
        </div>
        <div onClick={() => window.open("#tablet/vendita", "_blank")}
          className={`bg-white rounded-xl border shadow-sm p-3 flex items-center gap-3 cursor-pointer hover:shadow-md transition-all ${aperte.length > 0 ? "border-yellow-200 hover:border-yellow-400" : "border-gray-100 hover:border-blue-200"}`}>
          <div className={`p-2 rounded-lg ${aperte.length > 0 ? "bg-yellow-100" : "bg-green-100"}`}>
            <Package className={aperte.length > 0 ? "text-yellow-600" : "text-green-600"} size={18} />
          </div>
          <div>
            <p className="text-2xl font-bold text-gray-900 leading-none">
              {aperte.length > 0 ? pezziAperte : pezziAlBanco}
            </p>
            <p className="text-xs font-semibold text-gray-500 mt-0.5">
              {aperte.length > 0 ? `${aperte.length} referenze aperte` : "Tutti registrati"}
            </p>
          </div>
        </div>
      </div>

      {/* Produzioni di oggi */}
      {produzioniOggi.length > 0 && (
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5">
          <div className="flex items-center justify-between mb-4">
            <h3 className="font-bold text-gray-800 flex items-center gap-2">
              <Clock size={18} className="text-blue-500" /> Produzioni di Oggi
            </h3>
            <button onClick={() => onNavigate("storico_produzioni")}
              className="text-xs text-blue-600 hover:text-blue-800 font-semibold">
              Vedi tutte
            </button>
          </div>
          <div className="space-y-2">
            {produzioniOggi.slice(0, 8).map(p => (
              <div key={p.id} className="flex items-center justify-between py-1.5 border-b border-gray-50 last:border-0">
                <span className="text-sm font-medium text-gray-700 capitalize">{p.ricetta_nome}</span>
                <div className="flex items-center gap-3">
                  {p.frigo_numero && (
                    <span className="text-xs bg-blue-50 text-blue-600 px-2 py-0.5 rounded">{p.frigo_numero}</span>
                  )}
                  <span className="text-sm font-bold text-blue-700">{p.pezzi} pz</span>
                  {p.costo_totale > 0 && (
                    <span className="text-xs text-gray-400">€{p.costo_totale.toFixed(2)}</span>
                  )}
                </div>
              </div>
            ))}
            {produzioniOggi.length > 8 && (
              <p className="text-xs text-gray-400 text-center pt-1">
                +{produzioniOggi.length - 8} altre produzioni
              </p>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default DashboardView;
